// ─── MATERIAL SYMBOLS GLOBAL ─────────────────────────────────────────────────
// Disponible para todos los componentes, incluidos los declarados fuera del
// módulo de POSTURAS. Evita referencias fuera de alcance al helper local `MS`.
function MS({ name, size = 20, active = false, color = "currentColor", style = {}, className = "", title = "" }) {
  const resolvedColor = color !== "currentColor"
    ? color
    : active
      ? "#a1c9ff"
      : "rgba(212,228,250,.78)";

  return (
    <span
      className={`material-symbols-outlined ${className}`.trim()}
      aria-hidden={title ? undefined : "true"}
      role={title ? "img" : undefined}
      title={title || undefined}
      style={{
        display: "inline-flex",
        alignItems: "center",
        justifyContent: "center",
        width: size,
        height: size,
        flex: "0 0 auto",
        overflow: "hidden",
        color: resolvedColor,
        fontFamily: "Material Symbols Outlined",
        fontSize: size,
        lineHeight: 1,
        fontWeight: 400,
        fontStyle: "normal",
        letterSpacing: "normal",
        textTransform: "none",
        whiteSpace: "nowrap",
        wordWrap: "normal",
        direction: "ltr",
        fontFeatureSettings: "liga",
        WebkitFontFeatureSettings: "liga",
        fontVariationSettings: `'FILL' ${active ? 1 : 0}, 'wght' 400, 'GRAD' 0, 'opsz' 24`,
        WebkitFontSmoothing: "antialiased",
        ...style,
      }}
    >
      {name}
    </span>
  );
}



