function FiscalZoneMap({ zona, rutas }) {
  const theme = React.useContext(ThemeContext);
  const L = useLeaflet();
  const mapRef = useRef(null);
  const leafRef = useRef(null);
  const layersRef = useRef(null);
  const tileRef = useRef(null);
  const labelRef = useRef(null);
  const routeRefs = useRef({});
  const refRefs = useRef({});
  const [tileMode, setTileMode] = useState("dark");

  const filtered = RUTAS_FISCALES.filter(r => r.zona === zona);
  const filteredRefs = RUTA_FISCAL_REFERENCIAS.filter(r => r.zona === zona);
  const TILE_OPTIONS = [
    { id: "dark", label: "Oscuro", icon: "moon", url: "https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png", subdomains: "abcd", labels: null },
    { id: "light", label: "Claro", icon: "sun", url: "https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png", subdomains: "abcd", labels: null },
    { id: "streets", label: "Calles", icon: "map", url: "https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png", subdomains: "abc", labels: null },
    { id: "satellite", label: "Satélite", icon: "satellite", url: "https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}", subdomains: "", labels: "https://services.arcgisonline.com/ArcGIS/rest/services/Reference/World_Boundaries_and_Places/MapServer/tile/{z}/{y}/{x}" },
  ];

  const getRutaColor = (routeId) => {
    const st = rutas?.[routeId] || { status: "libre" };
    return (RUTA_FISCAL_STATUS_OPTIONS.find(o => o.id === st.status) || RUTA_FISCAL_STATUS_OPTIONS[0]).color;
  };

  const focusRoute = (routeId) => {
    const map = leafRef.current;
    const layer = routeRefs.current[routeId];
    if (!map || !layer) return;
    map.fitBounds(layer.getBounds(), { padding: [38, 38], maxZoom: 17 });
    layer.openTooltip();
  };

  const focusReference = (refId) => {
    const map = leafRef.current;
    const marker = refRefs.current[refId];
    if (!map || !marker) return;
    map.setView(marker.getLatLng(), Math.max(map.getZoom(), 17), { animate: true });
    marker.openTooltip();
  };

  useEffect(() => {
    if (!L || !mapRef.current || leafRef.current) return;
    const firstTile = TILE_OPTIONS.find(t => t.id === tileMode) || TILE_OPTIONS[0];
    const map = L.map(mapRef.current, {
      center: zona === "Norte" ? [19.0852, -104.2985] : [19.0638, -104.2912],
      zoom: zona === "Norte" ? 15 : 14,
      zoomControl: true,
      attributionControl: false,
      scrollWheelZoom: true,
      dragging: true,
      touchZoom: true,
      doubleClickZoom: true,
    });
    tileRef.current = L.tileLayer(firstTile.url, { maxZoom: 20, subdomains: firstTile.subdomains || "abc" }).addTo(map);
    layersRef.current = L.layerGroup().addTo(map);
    leafRef.current = map;
    setTimeout(() => map.invalidateSize(), 150);
    return () => {
      if (leafRef.current) {
        leafRef.current.remove();
        leafRef.current = null;
        layersRef.current = null;
        routeRefs.current = {};
        refRefs.current = {};
      }
    };
  }, [L]);

  useEffect(() => {
    if (!L || !leafRef.current || !tileRef.current) return;
    const t = TILE_OPTIONS.find(t => t.id === tileMode) || TILE_OPTIONS[0];
    leafRef.current.removeLayer(tileRef.current);
    tileRef.current = L.tileLayer(t.url, { maxZoom: 20, subdomains: t.subdomains || "abc" }).addTo(leafRef.current);
    if (labelRef.current) { leafRef.current.removeLayer(labelRef.current); labelRef.current = null; }
    if (t.labels) labelRef.current = L.tileLayer(t.labels, { maxZoom: 20, subdomains: "abcd", pane: "overlayPane" }).addTo(leafRef.current);
  }, [tileMode, L]);

  useEffect(() => {
    const map = leafRef.current;
    if (!map || !L || !layersRef.current) return;
    layersRef.current.clearLayers();
    routeRefs.current = {};
    refRefs.current = {};
    const allCoords = [];
    filtered.forEach(route => {
      const st = rutas?.[route.id] || { status: "libre", lastUpdate: Date.now(), updatedBy: "Sistema" };
      const opt = RUTA_FISCAL_STATUS_OPTIONS.find(o => o.id === st.status) || RUTA_FISCAL_STATUS_OPTIONS[0];
      route.coords.forEach(c => allCoords.push(c));
      const routeColor = cmVividMapColor(opt.color, route.id);
      const layer = L.polygon(route.coords, cmMapPolygonStyle(routeColor, {
        key: route.id,
        weight: 4,
        fillOpacity: 0.52,
      }))
        .bindTooltip(`<b>${route.name}</b><br><span style="color:${opt.color}">${leafletIconMarkup(opt.icon, opt.color, 14)} ${opt.label}</span>`, {
          permanent: false,
          sticky: true,
          className: "cm-tooltip",
        })
        .addTo(layersRef.current);
      routeRefs.current[route.id] = layer;
    });
    filteredRefs.forEach(ref => {
      allCoords.push(ref.coords);
      const color = ref.tipo === "acceso" ? "#fbbf24" : "#38bdf8";
      const marker = L.marker(ref.coords, {
        icon: L.divIcon({
          className: "cm-ref-marker",
          html: `<div class="cm-ref-dot" style="border-color:${color};box-shadow:0 0 0 4px ${color}22,0 6px 18px rgba(0,0,0,.45)">${leafletIconMarkup(ref.icon, color, 18)}</div><div class="cm-ref-label" style="border-color:${color}66;color:${color}">${ref.short}</div>`,
          iconSize: [96, 42],
          iconAnchor: [18, 18],
        })
      })
        .bindTooltip(`<b>${ref.name}</b><br><span>${ref.tipo === "acceso" ? "Acceso de referencia" : "Terminal de referencia"}</span>`, {
          permanent: false,
          sticky: true,
          className: "cm-tooltip",
        })
        .addTo(layersRef.current);
      refRefs.current[ref.id] = marker;
    });

    if (allCoords.length) {
      map.fitBounds(L.latLngBounds(allCoords), { padding: [28, 28], maxZoom: zona === "Norte" ? 17 : 15 });
      setTimeout(() => map.invalidateSize(), 150);
    }
  }, [zona, rutas, L]);

  return (
    <div style={{ marginBottom:"14px" }}>
      <style>{`
        .cm-tooltip{background:rgba(4,12,24,0.95)!important;border:1px solid rgba(56,189,248,0.35)!important;border-radius:6px!important;color:rgba(255,255,255,0.9)!important;font-family:'DM Sans',sans-serif!important;font-size:12px!important;font-weight:700!important;padding:4px 9px!important;box-shadow:0 2px 12px rgba(0,0,0,0.5)!important;white-space:nowrap!important;}
        .cm-tooltip::before{display:none!important;}
        .leaflet-control-zoom a{background:rgba(4,12,24,0.9)!important;color:rgba(255,255,255,0.75)!important;border-color:rgba(255,255,255,0.1)!important;}
        .leaflet-control-zoom a:hover{background:rgba(56,189,248,0.2)!important;}
        .cm-ref-marker{background:transparent!important;border:none!important;}
        .cm-ref-dot{width:34px;height:34px;border:2px solid #38bdf8;border-radius:999px;background:rgba(4,12,24,.94);display:flex;align-items:center;justify-content:center;font-size:16px;}
        .cm-ref-label{position:absolute;left:38px;top:6px;white-space:nowrap;background:rgba(4,12,24,.88);border:1px solid rgba(56,189,248,.45);border-radius:7px;padding:3px 7px;font-family:'DM Sans',sans-serif;font-size:10px;font-weight:800;text-shadow:0 1px 2px rgba(0,0,0,.6);box-shadow:0 4px 12px rgba(0,0,0,.28);}
      `}</style>
      <div style={{ display:"flex", gap:"8px", flexWrap:"wrap", alignItems:"center", marginBottom:"10px" }}>
        <span style={{ fontFamily:getFont(theme,"secondary"), fontSize:"11px", color:"rgba(255,255,255,0.48)", fontWeight:"700" }}>Vista:</span>
        {TILE_OPTIONS.map(t => (
          <button key={t.id} onClick={() => setTileMode(t.id)} style={{ padding:"6px 10px", borderRadius:"9px", border:`1.5px solid ${tileMode===t.id ? "#38bdf8" : "rgba(255,255,255,0.16)"}`, background:tileMode===t.id ? "rgba(56,189,248,0.16)" : "rgba(255,255,255,0.04)", color:tileMode===t.id ? "#38bdf8" : "rgba(255,255,255,0.75)", fontFamily:getFont(theme,"secondary"), fontSize:"11px", fontWeight:"700", cursor:"pointer" }}>
            <AppIcon name={t.icon} size={14} active={tileMode===t.id} /> {t.label}
          </button>
        ))}
      </div>
      <div
        ref={mapRef}
        style={{
          width:"100%",
          minHeight: zona === "Norte" ? "420px" : "460px",
          height:"clamp(420px, 58vh, 660px)",
          borderRadius:"14px",
          overflow:"hidden",
          border:"1px solid rgba(56,189,248,0.28)",
          boxShadow:"0 12px 36px rgba(0,0,0,0.35)",
          background:"#061428",
        }}
      />
      {!L && <div style={{ textAlign:"center", color:"#94a3b8", fontFamily:getFont(theme,"secondary"), fontSize:"12px", marginTop:"8px" }}>Cargando mapa…</div>}
      <div style={{ fontFamily:getFont(theme,"secondary"), fontSize:"10px", color:"rgba(255,255,255,0.42)", marginTop:"8px" }}>
        Puedes mover, acercar y alejar el mapa. Los iconos del mapa muestran terminales y accesos de referencia; cambia entre Oscuro, Satélite, Claro o Calles.
      </div>
    </div>
  );
}

