const mkSegundoState = () => {
  const state = {};
  ACCESOS_SEGUNDO.forEach(acc => {
    acc.carriles.forEach(c => {
      if (c.tipo === "ingreso") {
        state[c.id] = { abierto: true, terminal: c.defaultTerminal, saturado: false, retornos: false, lastUpdate: Date.now(), updatedBy: "Sistema" };
      } else {
        state[c.id] = { abierto: true, saturado: false, lastUpdate: Date.now(), updatedBy: "Sistema" };
      }
    });
  });
  return state;
};

// ─── HELPERS ──────────────────────────────────────────────────────────────────
const timeAgo = (ts) => {
  const d = Date.now() - ts;
  if (d < 60000)   return "hace un momento";
  if (d < 3600000) return `hace ${Math.floor(d / 60000)}min`;
  return `hace ${Math.floor(d / 3600000)}h`;
};
const uid = () => "u_" + Math.random().toString(36).substr(2, 6);


// ─── ADMIN · REGISTROS, MENSAJES Y SANCIONES POR DISPOSITIVO ───────────────
const DEVICE_SANCTION_KEY = "cm_device_sanction_cache";
const getDeviceId = () => {
  try { return localStorage.getItem("puerto_trafico_uid") || "anon"; } catch { return "anon"; }
};
const auditLog = async ({ action, section, entityId = null, before = null, after = null, actor = null }) => {
  const deviceId = getDeviceId();
  try {
    await sb.from("admin_audit_logs").insert({
      action,
      section,
      entity_id: entityId,
      before_value: before,
      after_value: { ...(after || {}), device_id: deviceId, user_id: deviceId },
      actor: actor || `Usuario_${deviceId.slice(-4)}`,
      device_id: deviceId,
      user_agent: navigator.userAgent,
      created_at: new Date().toISOString()
    });
  } catch (e) { console.warn("auditLog pendiente: crea tabla admin_audit_logs", e?.message || e); }
};
const getLogSummary = (log) => {
  const a = log?.after_value || {};
  if (a.summary) return a.summary;
  if (log?.action?.includes("carril") || log?.section?.includes("carril") || log?.section === "segundo") {
    return `${a.user_id || log.device_id || log.actor || "Usuario"} modificó ${a.carril || log.entity_id || "carril"}${a.campo ? ` · ${a.campo}` : ""}${a.valor_label ? `: ${a.valor_label}` : a.value !== undefined ? `: ${String(a.value)}` : ""}`;
  }
  if (log?.action?.startsWith("votar") || log?.action?.includes("voto")) {
    return `${a.user_id || log.device_id || log.actor || "Usuario"} votó/modificó ${log.entity_id || "elemento"}${a.status ? `: ${a.status}` : ""}`;
  }
  if (log?.action === "crear_reporte") return `${a.user_id || log.device_id || log.actor || "Usuario"} creó reporte ${a.subcategory_label || a.subcategory || ""} en ${a.location || "ubicación sin nombre"}`;
  return "";
};
const isDeviceBlocked = async (action = "web") => {
  const deviceId = getDeviceId();
  let accountId = null;
  try { accountId = localStorage.getItem("cm_auth_user_id") || null; } catch {}
  try {
    const cached = JSON.parse(localStorage.getItem(DEVICE_SANCTION_KEY) || "null");
    if (cached && (cached.type === "ban" || (cached.until && new Date(cached.until).getTime() > Date.now()))) return cached;
  } catch {}
  try {
    let query = sb.from("admin_user_sanctions")
      .select("*").eq("active", true).order("created_at", { ascending:false }).limit(30);
    query = accountId
      ? query.or(`device_id.eq.${deviceId},user_id.eq.${accountId}`)
      : query.eq("device_id", deviceId);
    const { data, error } = await query;
    if (error) throw error;
    const hit = (data || []).find(s => {
      const acts = s.actions || ["web", "vote", "report"];
      const applies = acts.includes(action) || acts.includes("web");
      const still = s.type === "ban" || !s.until_at || new Date(s.until_at).getTime() > Date.now();
      return applies && still;
    });
    if (hit) {
      const normalized = { type: hit.type, reason: hit.reason || "Acción restringida por administración.", until: hit.until_at || null };
      try { localStorage.setItem(DEVICE_SANCTION_KEY, JSON.stringify(normalized)); } catch {}
      return normalized;
    }
  } catch {}
  return null;
};
const notifyIfBlocked = async (action, notify = alert) => {
  const blocked = await isDeviceBlocked(action);
  if (!blocked) return false;
  const until = blocked.until ? ` hasta ${new Date(blocked.until).toLocaleString("es-MX")}` : " indefinidamente";
  notify(`Tu dispositivo tiene acciones bloqueadas${until}. ${blocked.reason || ""}`, "#ef4444");
  return true;
};


const getWinnerFromVotes = (rows = [], defaultStatus = "libre") => {
  const conteo = {};
  (rows || []).forEach(v => { if (v?.status) conteo[v.status] = (conteo[v.status] || 0) + 1; });
  const ganadora = Object.entries(conteo).sort((a,b) => b[1] - a[1])[0];
  return { status: ganadora ? ganadora[0] : defaultStatus, count: ganadora ? ganadora[1] : 0, conteo };
};

const recalcStoredVoteEntity = async ({ table, entityColumn, entityId, tipo, defaultStatus = "libre" }) => {
  if (!entityId) return null;
  const { data } = await sb.from("votos").select("status").eq(entityColumn, entityId).eq("tipo", tipo);
  const winner = getWinnerFromVotes(data || [], defaultStatus);
  await sb.from(table).upsert({
    id: entityId,
    status: winner.status,
    pending_voters: winner.conteo,
    last_update: Date.now(),
    updated_by: winner.count ? `${winner.count} votos` : "Voto anulado por admin"
  });
  return winner;
};

const revokeIncidentVotesByDevice = async (deviceId, incidentId = null) => {
  const q = sb.from("incidents").select("id,votes,false_votes,resolve_votes");
  const { data } = incidentId ? await q.eq("id", incidentId) : await q;
  let changed = 0;
  for (const inc of data || []) {
    const votes = { ...(inc.votes || {}) };
    const falseVotes = { ...(inc.false_votes || {}) };
    const resolveVotes = { ...(inc.resolve_votes || {}) };
    const had = votes[deviceId] !== undefined || falseVotes[deviceId] !== undefined || resolveVotes[deviceId] !== undefined;
    if (!had) continue;
    delete votes[deviceId];
    delete falseVotes[deviceId];
    delete resolveVotes[deviceId];
    const confirmCount = Object.values(votes).filter(v => v === 1).length;
    const resolveCount = Object.values(resolveVotes).filter(v => v === 1).length;
    await sb.from("incidents").update({
      votes,
      false_votes: falseVotes,
      resolve_votes: resolveVotes,
      visible: confirmCount >= 3,
      resolved: resolveCount >= 3
    }).eq("id", inc.id);
    changed += 1;
  }
  return changed;
};

const restoreDirectVoteFromLog = async (log) => {
  if (!log?.entity_id || !log?.before_value) return false;
  const before = log.before_value || {};
  const action = log.action || "";
  const section = log.section || "";
  const entityId = log.entity_id;
  const ts = Date.now();
  const updatedBy = "Voto anulado por admin";

  const restoreCarrilesRow = async (rowId, defaultsFactory) => {
    const { data } = await sb.from("carriles").select("data").eq("id", rowId).maybeSingle();
    const base = data?.data || defaultsFactory();
    const restored = {
      ...base,
      [entityId]: {
        ...base?.[entityId],
        ...before,
        lastUpdate: ts,
        updatedBy
      }
    };
    await sb.from("carriles").upsert({ id: rowId, data: restored });
    return true;
  };

  if (action === "votar_acceso" || action === "actualizar_acceso") {
    await sb.from("accesos").upsert({ id: entityId, status: before.status || "libre", retornos: before.retornos || "none", last_update: ts, updated_by: updatedBy, pending_voters: {} });
    return true;
  }
  if (action === "votar_vialidad" || action === "actualizar_vialidad") {
    await sb.from("vialidades").upsert({ id: entityId, status: before.status || "libre", last_update: ts, updated_by: updatedBy, pending_voters: {} });
    return true;
  }
  if (action === "actualizar_ruta_fiscal" || action === "votar_ruta_fiscal") {
    await sb.from("rutas_fiscales").upsert({ id: entityId, status: before.status || "libre", last_update: ts, updated_by: updatedBy });
    return true;
  }
  if (section === "segundo" && (action === "modificar_carril_segundo" || action === "modificar_carril_salida")) {
    return await restoreCarrilesRow("segundo_acceso", mkSegundoIngreso);
  }
  if (section === "segundo" && action === "modificar_carril_confinada") {
    return await restoreCarrilesRow("confinada_acceso", mkConfinadaState);
  }
  if (section === "carriles" && action === "modificar_carril_expo_impo") {
    return await restoreCarrilesRow("expo_impo", mkCarrilesState);
  }
  return false;
};

const revokeDeviceVotes = async ({ deviceId, log = null, mode = "selected", actor = "Admin" }) => {
  const target = String(deviceId || "").trim();
  if (!target) throw new Error("Falta device_id.");
  const result = { votosTabla: 0, terminales: 0, patios: 0, incidentes: 0, directos: 0 };

  if (mode === "selected" && log) {
    const action = log.action || "";
    const section = log.section || "";
    const entityId = log.entity_id;
    if (section === "terminales" || action.includes("terminal")) {
      const { count } = await sb.from("votos").delete({ count:"exact" }).eq("user_id", target).eq("terminal_id", entityId).eq("tipo", "terminal");
      result.votosTabla += count || 0;
      await recalcStoredVoteEntity({ table:"terminals", entityColumn:"terminal_id", entityId, tipo:"terminal" });
      result.terminales += 1;
    } else if (section === "patios" || action.includes("patio")) {
      const { count } = await sb.from("votos").delete({ count:"exact" }).eq("user_id", target).eq("patio_id", entityId).eq("tipo", "patio");
      result.votosTabla += count || 0;
      await recalcStoredVoteEntity({ table:"patios", entityColumn:"patio_id", entityId, tipo:"patio" });
      result.patios += 1;
    } else if (section === "reporte_eventos" || action.includes("reporte") || action.includes("evento")) {
      result.incidentes += await revokeIncidentVotesByDevice(target, entityId);
    } else {
      result.directos += await restoreDirectVoteFromLog(log) ? 1 : 0;
    }
  } else {
    const { data: storedVotes } = await sb.from("votos").select("terminal_id,patio_id,tipo").eq("user_id", target);
    const terminalIds = Array.from(new Set((storedVotes || []).filter(v => v.tipo === "terminal" && v.terminal_id).map(v => v.terminal_id)));
    const patioIds = Array.from(new Set((storedVotes || []).filter(v => v.tipo === "patio" && v.patio_id).map(v => v.patio_id)));
    const { count } = await sb.from("votos").delete({ count:"exact" }).eq("user_id", target);
    result.votosTabla += count || 0;
    for (const id of terminalIds) { await recalcStoredVoteEntity({ table:"terminals", entityColumn:"terminal_id", entityId:id, tipo:"terminal" }); result.terminales += 1; }
    for (const id of patioIds) { await recalcStoredVoteEntity({ table:"patios", entityColumn:"patio_id", entityId:id, tipo:"patio" }); result.patios += 1; }
    result.incidentes += await revokeIncidentVotesByDevice(target, null);

    const { data: directLogs } = await sb.from("admin_audit_logs")
      .select("*").eq("device_id", target)
      .in("action", [
        "votar_acceso", "actualizar_acceso",
        "votar_vialidad", "actualizar_vialidad",
        "votar_ruta_fiscal", "actualizar_ruta_fiscal",
        "modificar_carril_segundo", "modificar_carril_salida", "modificar_carril_confinada",
        "modificar_carril_expo_impo"
      ])
      .order("created_at", { ascending:true }).limit(300);
    const touched = new Set();
    for (const dl of directLogs || []) {
      const field = dl?.after_value?.campo || "estado";
      const k = `${dl.section}:${dl.action}:${dl.entity_id}:${field}`;
      if (touched.has(k)) continue;
      if (await restoreDirectVoteFromLog(dl)) result.directos += 1;
      touched.add(k);
    }
  }

  await auditLog({
    action: mode === "selected" ? "anular_voto_usuario" : "anular_todos_votos_usuario",
    section: "admin_registros",
    entityId: target,
    after: { ...result, target_device_id: target, selected_log_id: log?.id || null, selected_action: log?.action || null, subsection: mode === "selected" ? "anulacion_voto" : "anulacion_total" },
    actor
  });
  return result;
};

// ✨ NUEVO: Helper para generar estilos de ContentBox basado en theme
const getContentBoxStyle = (theme) => {
  const ui = getAutoUIColors(theme || DEFAULT_THEME);
  if (!theme || !theme.contentBox || !theme.contentBox.enabled) {
    return {
      background: ui.panelBg,
      border: `1px solid ${ui.border}`,
      borderRadius: "12px",
      padding: "16px",
      color: ui.primary
    };
  }
  
  const box = theme.contentBox;
  const useAuto = theme.backgroundType === "color" && box.autoAdjustWithSolidBackground !== false;
  let background = useAuto ? ui.panelBg : (box.background || "rgba(255, 255, 255, 0.03)");
  
  if (!useAuto && box.gradientOverlay && box.gradientOverlay.enabled) {
    background = `${box.gradientOverlay.gradient}, ${box.background}`;
  }
  
  let boxShadow = "none";
  if (box.shadow && box.shadow.enabled) {
    boxShadow = `${box.shadow.offsetX || 0}px ${box.shadow.offsetY || 0}px ${box.shadow.blur || 0}px ${box.shadow.color || "rgba(0,0,0,0.3)"}`;
  } else if (useAuto) {
    boxShadow = ui.shadow;
  }
  
  return {
    background,
    backdropFilter: box.backdropBlur ? `blur(${box.backdropBlur}px)` : "none",
    WebkitBackdropFilter: box.backdropBlur ? `blur(${box.backdropBlur}px)` : "none",
    border: `${box.borderWidth || 1}px solid ${useAuto ? ui.border : (box.borderColor || "rgba(255, 255, 255, 0.1)")}`,
    borderRadius: `${box.borderRadius || 12}px`,
    padding: `${box.padding || 16}px`,
    minHeight: box.minHeight ? `${box.minHeight}px` : undefined,
    maxWidth: box.maxWidth ? `${box.maxWidth}px` : undefined,
    boxShadow,
    color: ui.primary
  };
};

// ✨ Helper para obtener fuentes dinámicas del theme
// Validado FIX: Validación robusta con fallbacks seguros
const getFont = (theme, type) => {
  if (!theme) return "'DM Sans', sans-serif"; // fallback si theme es undefined/null
  if (type === "title") return theme.primaryFont || "'Playfair Display', serif";
  return theme.secondaryFont || "'DM Sans', sans-serif";
};

// Validado FIX: Validación robusta con fallbacks seguros
const getFontSize = (theme, type) => {
  if (!theme) return "14px"; // fallback si theme es undefined/null
  if (type === "title") return `${theme.titleFontSize || 17}px`;
  return `${theme.baseFontSize || 14}px`;
};

// Validado Helpers de color de texto: conectan el panel Admin con la UI
const getTextColor = (theme, type = "primary", fallback = "#ffffff") => {
  return theme?.textColors?.[type] || DEFAULT_THEME.textColors?.[type] || fallback;
};
const withAlpha = (hex, alpha = 1) => {
  if (!hex || typeof hex !== "string") return `rgba(255,255,255,${alpha})`;
  const clean = hex.replace("#", "").trim();
  if (![3, 6].includes(clean.length)) return hex;
  const full = clean.length === 3 ? clean.split("").map(c => c + c).join("") : clean;
  const n = parseInt(full, 16);
  const r = (n >> 16) & 255, g = (n >> 8) & 255, b = n & 255;
  return `rgba(${r},${g},${b},${alpha})`;
};

const clamp255 = (n) => Math.max(0, Math.min(255, Math.round(n)));
const cmHexToRgb = (hex, fallback = { r: 10, g: 22, b: 40 }) => {
  if (!hex || typeof hex !== "string") return fallback;
  const clean = hex.replace("#", "").trim();
  if (![3, 6].includes(clean.length)) return fallback;
  const full = clean.length === 3 ? clean.split("").map(c => c + c).join("") : clean;
  const n = parseInt(full, 16);
  if (Number.isNaN(n)) return fallback;
  return { r: (n >> 16) & 255, g: (n >> 8) & 255, b: n & 255 };
};
const rgbToHex = ({ r, g, b }) => `#${[r,g,b].map(v => clamp255(v).toString(16).padStart(2,"0")).join("")}`;
const rgbToRgba = ({ r, g, b }, a = 1) => `rgba(${clamp255(r)},${clamp255(g)},${clamp255(b)},${a})`;
const mixRgb = (a, b, weight = 0.5) => ({
  r: a.r * (1 - weight) + b.r * weight,
  g: a.g * (1 - weight) + b.g * weight,
  b: a.b * (1 - weight) + b.b * weight,
});
const relLuminance = ({ r, g, b }) => {
  const f = (v) => {
    v /= 255;
    return v <= 0.03928 ? v / 12.92 : Math.pow((v + 0.055) / 1.055, 2.4);
  };
  return 0.2126 * f(r) + 0.7152 * f(g) + 0.0722 * f(b);
};

// Genera una paleta armónica a partir del fondo sólido. Se usa para tabs, header,
// ventanas e iconos sin que el admin tenga que configurar cada color manualmente.
const getAutoUIColors = (theme = DEFAULT_THEME) => {
  const fallbackAccent = theme?.textColors?.accent || DEFAULT_THEME.textColors.accent;
  if (theme?.backgroundType !== "color" || theme?.uiAutoAdjust === false) {
    return {
      isDark: true,
      primary: theme?.textColors?.primary || "#ffffff",
      secondary: theme?.textColors?.secondary || "#e2e8f0",
      muted: theme?.textColors?.muted || "#94a3b8",
      accent: fallbackAccent,
      headerBg: "rgba(255,255,255,0.08)",
      navBg: "rgba(255,255,255,0.07)",
      tabBg: "transparent",
      tabHoverBg: "rgba(255,255,255,0.05)",
      tabActiveBg: "rgba(255,255,255,0.15)",
      border: "rgba(255,255,255,0.12)",
      subtleBorder: "rgba(255,255,255,0.06)",
      panelBg: "rgba(255,255,255,0.06)",
      panelStrongBg: "rgba(255,255,255,0.10)",
      iconActive: "#f8fafc",
      iconMuted: "#94a3b8",
      iconMuted2: "#64748b",
      shadow: "0 18px 44px rgba(0,0,0,0.25)",
    };
  }

  const base = cmHexToRgb(theme.backgroundColor || DEFAULT_THEME.backgroundColor);
  const lum = relLuminance(base);
  const isDark = lum < 0.45;
  const white = { r:255, g:255, b:255 };
  const black = { r:0, g:0, b:0 };
  const sky = cmHexToRgb(fallbackAccent, { r:56, g:189, b:248 });
  const text = isDark ? white : { r:15, g:23, b:42 };
  const text2 = isDark ? mixRgb(base, white, 0.78) : mixRgb(base, black, 0.72);
  const muted = isDark ? mixRgb(base, white, 0.55) : mixRgb(base, black, 0.48);
  const accent = isDark ? mixRgb(base, sky, 0.72) : mixRgb(base, sky, 0.58);
  const panelTint = isDark ? mixRgb(base, white, 0.12) : mixRgb(base, black, 0.035);
  const panelStrong = isDark ? mixRgb(base, white, 0.20) : mixRgb(base, white, 0.96);
  const navTint = isDark ? panelTint : mixRgb(base, white, 0.92);
  const borderTint = isDark ? mixRgb(base, white, 0.34) : mixRgb(base, black, 0.34);
  const activeTint = isDark ? panelStrong : mixRgb(base, accent, 0.16);

  return {
    isDark,
    primary: rgbToHex(text),
    secondary: rgbToHex(text2),
    muted: rgbToHex(muted),
    accent: rgbToHex(accent),
    headerBg: rgbToRgba(navTint, isDark ? 0.86 : 0.96),
    navBg: rgbToRgba(navTint, isDark ? 0.72 : 0.96),
    tabBg: "transparent",
    tabHoverBg: rgbToRgba(activeTint, isDark ? 0.28 : 0.36),
    tabActiveBg: rgbToRgba(activeTint, isDark ? 0.42 : 0.62),
    border: rgbToRgba(borderTint, isDark ? 0.42 : 0.22),
    subtleBorder: rgbToRgba(borderTint, isDark ? 0.24 : 0.14),
    panelBg: rgbToRgba(panelTint, isDark ? 0.62 : 0.98),
    panelStrongBg: rgbToRgba(panelStrong, isDark ? 0.72 : 0.98),
    iconActive: rgbToHex(text),
    iconMuted: rgbToHex(muted),
    iconMuted2: rgbToHex(mixRgb(muted, accent, 0.35)),
    shadow: isDark ? "0 18px 44px rgba(0,0,0,0.28)" : "0 14px 34px rgba(15,23,42,0.10)",
  };
};

