// ─── ADMIN MODE ───────────────────────────────────────────────────────────────
function useAdminMode() {
  const theme = React.useContext(ThemeContext);
  const [isAdmin, setIsAdmin] = useState(() => {
    try { return sessionStorage.getItem(ADMIN_KEY) === "1"; }
    catch { return false; }
  });

  const [showModal, setShowModal] = useState(false);
  const [tapCount, setTapCount] = useState(0);
  const [pass, setPass] = useState("");
  const [err, setErr] = useState(false);
  const [showAdminPass, setShowAdminPass] = useState(false);
  const [failedAttempts, setFailedAttempts] = useState(0);
  const [lockoutUntil, setLockoutUntil] = useState(0);
  const [lockoutRemaining, setLockoutRemaining] = useState(0);
  const tapTimer = useRef(null);

  // Countdown timer for lockout display
  useEffect(() => {
    if (lockoutUntil <= 0) return;
    const interval = setInterval(() => {
      const remaining = Math.ceil((lockoutUntil - Date.now()) / 1000);
      if (remaining <= 0) {
        setLockoutRemaining(0);
        setLockoutUntil(0);
      } else {
        setLockoutRemaining(remaining);
      }
    }, 500);
    return () => clearInterval(interval);
  }, [lockoutUntil]);

  const handleLogoTap = () => {
    const next = tapCount + 1;
    setTapCount(next);
    clearTimeout(tapTimer.current);
    tapTimer.current = setTimeout(() => setTapCount(0), 3000);
  };

  useEffect(() => {
    if (tapCount >= 5) {
      setTapCount(0);
      setPass("");
      setErr(false);
      setShowAdminPass(false);
      setShowModal(true);
    }
  }, [tapCount]);

  const tryLogin = async () => {
    if (Date.now() < lockoutUntil) return;
    const ok = await verifyAdminPass(pass);
    if (ok) {
      try { sessionStorage.setItem(ADMIN_KEY, "1"); } catch {}
      setIsAdmin(true);
      setShowModal(false);
      setFailedAttempts(0);
      setPass("");
    } else {
      const newFails = failedAttempts + 1;
      setFailedAttempts(newFails);
      setErr(true);
      if (newFails >= 5) {
        const delays = [30000, 60000, 300000];
        const delayIdx = Math.min(Math.floor((newFails - 5) / 3), delays.length - 1);
        const lockMs = delays[delayIdx];
        setLockoutUntil(Date.now() + lockMs);
        setLockoutRemaining(Math.ceil(lockMs / 1000));
        setFailedAttempts(0);
      }
    }
  };

  const logout = () => {
    try { sessionStorage.removeItem(ADMIN_KEY); } catch {}
    setIsAdmin(false);
  };

  const isLocked = Date.now() < lockoutUntil;

  const EyeIcon = ({ crossed }) => crossed ? (
    <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <path d="M17.94 17.94A10.07 10.07 0 0 1 12 20c-7 0-11-8-11-8a18.45 18.45 0 0 1 5.06-5.94"/>
      <path d="M9.9 4.24A9.12 9.12 0 0 1 12 4c7 0 11 8 11 8a18.5 18.5 0 0 1-2.16 3.19"/>
      <line x1="1" y1="1" x2="23" y2="23"/>
    </svg>
  ) : (
    <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"/>
      <circle cx="12" cy="12" r="3"/>
    </svg>
  );

  const Modal = showModal ? (
    <div style={{ position:"fixed", inset:0, background:"rgba(0,0,0,0.75)", display:"flex", alignItems:"center", justifyContent:"center", zIndex:9999, padding:"20px" }}>
      <div style={{ background:"#0d1b2e", border:"1px solid rgba(56,189,248,0.3)", borderRadius:"16px", padding:"24px", width:"100%", maxWidth:"300px" }}>
        <div style={{ fontFamily:getFont(theme, "title"), fontSize:"18px", color:"#fff", marginBottom:"6px" }}>🔐 Modo Admin</div>
        <div style={{ fontFamily:getFont(theme, "secondary"), fontSize:"12px", color:"rgba(255,255,255,0.4)", marginBottom:"18px" }}>Ingresa la contraseña para activar el modo administrador.</div>
        {isLocked ? (
          <div style={{ textAlign:"center", padding:"16px", background:"rgba(239,68,68,0.1)", border:"1px solid rgba(239,68,68,0.3)", borderRadius:"10px", marginBottom:"12px" }}>
            <div style={{ fontSize:"28px", marginBottom:"6px" }}>🔒</div>
            <div style={{ fontFamily:getFont(theme, "secondary"), fontSize:"12px", color:"#ef4444", fontWeight:"700" }}>Demasiados intentos fallidos</div>
            <div style={{ fontFamily:getFont(theme, "secondary"), fontSize:"11px", color:"rgba(255,255,255,0.5)", marginTop:"4px" }}>
              Bloqueado por <span style={{ color:"#f97316", fontWeight:"700" }}>{lockoutRemaining}s</span>
            </div>
          </div>
        ) : (
          <>
            <div style={{ position:"relative", marginBottom:"8px" }}>
              <input
                type={showAdminPass ? "text" : "password"}
                value={pass}
                onChange={e => { setPass(e.target.value); setErr(false); }}
                onKeyDown={e => e.key === "Enter" && tryLogin()}
                placeholder="Contraseña"
                autoFocus
                style={{ width:"100%", padding:"11px 44px 11px 14px", background:"rgba(255,255,255,0.07)", border:`1px solid ${err ? "#ef4444" : "rgba(255,255,255,0.15)"}`, borderRadius:"10px", color:"#fff", fontFamily:getFont(theme, "secondary"), fontSize:"14px", boxSizing:"border-box", outline:"none" }}
              />
              <span
                onClick={() => setShowAdminPass(v => !v)}
                style={{ position:"absolute", right:"12px", top:"50%", transform:"translateY(-50%)", cursor:"pointer", color:"rgba(255,255,255,0.45)", display:"flex", alignItems:"center" }}
              >
                <EyeIcon crossed={showAdminPass} />
              </span>
            </div>
            {err && (
              <div style={{ color:"#ef4444", fontFamily:getFont(theme, "secondary"), fontSize:"12px", marginBottom:"8px" }}>
                Contraseña incorrecta{failedAttempts >= 3 ? ` (${failedAttempts}/5 intentos)` : ""}
              </div>
            )}
          </>
        )}
        <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:"8px" }}>
          <button onClick={() => { setShowModal(false); setPass(""); setErr(false); }} style={{ padding:"11px", background:"rgba(255,255,255,0.07)", border:"none", borderRadius:"10px", color:"rgba(255,255,255,0.6)", fontFamily:getFont(theme, "secondary"), fontSize:"13px", cursor:"pointer" }}>Cancelar</button>
          <button onClick={tryLogin} disabled={isLocked} style={{ padding:"11px", background: isLocked ? "#334155" : "#38bdf8", border:"none", borderRadius:"10px", color: isLocked ? "rgba(255,255,255,0.3)" : "#0a0f1e", fontFamily:getFont(theme, "secondary"), fontSize:"13px", fontWeight:"700", cursor: isLocked ? "not-allowed" : "pointer" }}>Entrar</button>
        </div>
      </div>
    </div>
  ) : null;

  const openModal = () => {
    setPass("");
    setErr(false);
    setShowAdminPass(false);
    setShowModal(true);
  };

  return { isAdmin, handleLogoTap, openModal, logout, Modal };
}

// ─── HELPERS: noticias, comunicados y archivos operativos ───────────────────
const NOTICIAS_TIPOS_VISIBLES = ["comunicado", "admin", "incidente", "accidente"];
const NOTICIAS_TIPOS_OPERATIVOS_OCULTOS = ["acceso", "terminal", "resuelto", "patio", "carril", "vialidad", "ruta_fiscal", "segundo", "estado_segundo", "voto_segundo", "confinada_estado"];
const NOTICIAS_ORIGENES_OPERATIVOS_OCULTOS = ["sistema", "auto_estado_carril", "voto_carril", "votos", "grafica", "gráfica", "segundo", "confinada"];

const isNoticiaVisibleEnFeed = (n) => {
  if (!n) return false;
  if (n.ocultar_en_feed === true || n.ocultar_en_feed === "true" || n.ocultar_en_feed === 1) return false;
  const tipo = String(n.tipo || "").toLowerCase();
  const origen = String(n.origen || n.source || n.event_source || "").toLowerCase();
  const titulo = String(n.titulo || "").toLowerCase();
  const detalle = String(n.detalle || "").toLowerCase();

  // La sección Noticias queda reservada para comunicados/noticias publicadas.
  // Los movimientos automáticos de votos, gráficas, accesos, vialidades, rutas,
  // terminales, patios y carriles se consultan desde administración, no en el feed público.
  if (NOTICIAS_TIPOS_OPERATIVOS_OCULTOS.includes(tipo)) return false;
  if (NOTICIAS_ORIGENES_OPERATIVOS_OCULTOS.some(k => origen.includes(k))) return false;
  if (/actualizad[oa]|vot[óo]|voto|gr[aá]fica|confirm[óo]|marc[óo] falso|resuelt[oa]|anul[óo]/i.test(`${titulo} ${detalle}`)) return false;
  if (tipo && !NOTICIAS_TIPOS_VISIBLES.includes(tipo) && !origen.includes("admin_noticias") && !origen.includes("comunicados")) return false;
  return true;
};

const parseJsonArray = (value) => {
  if (!value) return [];
  if (Array.isArray(value)) return value.filter(Boolean);
  if (typeof value === "string") {
    try { const parsed = JSON.parse(value); return Array.isArray(parsed) ? parsed.filter(Boolean) : []; } catch { return value ? [value] : []; }
  }
  return [];
};

const sanitizeStorageName = (name = "archivo") => String(name)
  .normalize("NFD").replace(/[\u0300-\u036f]/g, "")
  .replace(/[^a-zA-Z0-9._-]+/g, "-")
  .replace(/-+/g, "-")
  .replace(/^-|-$/g, "")
  .slice(0, 90) || "archivo";

const loadScriptOnce = (src, testFn) => new Promise((resolve, reject) => {
  try {
    const isReady = () => (typeof testFn === "function" ? !!testFn() : true);
    if (isReady()) return resolve(true);
    const existing = Array.from(document.scripts || []).find(s => (s.src || "") === src);
    if (existing) {
      // CARGA ASÍNCRONA ROBUSTA: si el script ya existe pero ya terminó de cargar,
      // no dejamos la promesa colgada esperando un evento "load" que no volverá a ocurrir.
      if (existing.dataset.loaded === "true" || existing.readyState === "complete") {
        return isReady()
          ? resolve(true)
          : reject(new Error(`El script cargó, pero la librería no quedó disponible: ${src}`));
      }
      existing.addEventListener("load", () => {
        existing.dataset.loaded = "true";
        isReady() ? resolve(true) : reject(new Error(`El script cargó, pero la librería no quedó disponible: ${src}`));
      }, { once: true });
      existing.addEventListener("error", reject, { once: true });
      return;
    }
    const s = document.createElement("script");
    s.src = src;
    s.async = true;
    s.onload = () => {
      s.dataset.loaded = "true";
      isReady() ? resolve(true) : reject(new Error(`El script cargó, pero la librería no quedó disponible: ${src}`));
    };
    s.onerror = reject;
    document.head.appendChild(s);
  } catch (e) { reject(e); }
});

const loadTesseractClient = async () => {
  await loadScriptOnce("https://cdn.jsdelivr.net/npm/tesseract.js@5/dist/tesseract.min.js", () => !!window.Tesseract);
  if (!window.Tesseract?.recognize) throw new Error("Tesseract.js no cargó correctamente");
  return window.Tesseract;
};

const loadPdfJsClient = async () => {
  await loadScriptOnce("https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.min.js", () => !!window.pdfjsLib);
  if (!window.pdfjsLib?.getDocument) throw new Error("PDF.js no cargó correctamente");
  window.pdfjsLib.GlobalWorkerOptions.workerSrc = "https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js";
  return window.pdfjsLib;
};

const imageUrlToCanvas = (src, maxSide = 1800) => new Promise((resolve, reject) => {
  const img = new Image();
  img.crossOrigin = "anonymous";
  img.onload = () => {
    const ratio = Math.min(1, maxSide / Math.max(img.naturalWidth || img.width, img.naturalHeight || img.height));
    const canvas = document.createElement("canvas");
    canvas.width = Math.max(1, Math.round((img.naturalWidth || img.width) * ratio));
    canvas.height = Math.max(1, Math.round((img.naturalHeight || img.height) * ratio));
    const ctx = canvas.getContext("2d");
    ctx.fillStyle = "#ffffff";
    ctx.fillRect(0, 0, canvas.width, canvas.height);
    ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
    resolve(canvas);
  };
  img.onerror = reject;
  img.src = src;
});

const ocrCanvasClient = async (canvas) => {
  const Tesseract = await loadTesseractClient();
  const result = await Tesseract.recognize(canvas, "spa+eng");
  return String(result?.data?.text || "").trim();
};

const stripFileNamesFromOcrText = (rawText = "", files = []) => {
  const names = Array.from(files || [])
    .map(f => String(f?.name || "").trim())
    .filter(Boolean);
  if (!names.length) return String(rawText || "").trim();

  const escapeRegExp = (s) => String(s).replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
  const candidates = [];
  names.forEach(name => {
    candidates.push(name);
    candidates.push(name.replace(/\.[a-z0-9]{1,8}$/i, ""));
  });

  const cleanLines = String(rawText || "")
    .replace(/^\s*\[[^\]]+\]\s*$/gm, "")
    .split(/\r?\n/)
    .filter(line => {
      const normalized = line.trim();
      if (!normalized) return true;
      return !candidates.some(candidate => {
        const c = String(candidate || "").trim();
        if (!c) return false;
        return normalized === c || normalized.replace(/\s+/g, " ") === c.replace(/\s+/g, " ");
      });
    })
    .join("\n");

  return cleanLines
    .replace(new RegExp(`^\\s*(?:${candidates.map(escapeRegExp).join("|")})\\s*$`, "gim"), "")
    .replace(/\n{3,}/g, "\n\n")
    .trim();
};

const processImageOcrClient = async (sourceUrl) => {
  const canvas = await imageUrlToCanvas(sourceUrl);
  const text = await ocrCanvasClient(canvas);
  return { ok: true, text, image_urls: [sourceUrl] };
};


const cropCanvasByZone = (sourceCanvas, zone = null) => {
  if (!sourceCanvas) throw new Error("No hay canvas para recortar");
  const z = zone || { x: 0, y: 0, w: 1, h: 1 };
  const sx = Math.max(0, Math.round((z.x || 0) * sourceCanvas.width));
  const sy = Math.max(0, Math.round((z.y || 0) * sourceCanvas.height));
  const sw = Math.max(1, Math.min(sourceCanvas.width - sx, Math.round((z.w || 1) * sourceCanvas.width)));
  const sh = Math.max(1, Math.min(sourceCanvas.height - sy, Math.round((z.h || 1) * sourceCanvas.height)));
  const out = document.createElement("canvas");
  out.width = sw;
  out.height = sh;
  const ctx = out.getContext("2d");
  ctx.fillStyle = "#ffffff";
  ctx.fillRect(0, 0, sw, sh);
  ctx.drawImage(sourceCanvas, sx, sy, sw, sh, 0, 0, sw, sh);
  return out;
};

const renderPdfFileToCanvases = async (fileOrUrl, maxPages = 8) => {
  const pdfjsLib = await loadPdfJsClient();
  const data = typeof fileOrUrl === "string"
    ? await (await fetch(fileOrUrl, { mode: "cors" })).arrayBuffer()
    : await fileOrUrl.arrayBuffer();
  const pdf = await pdfjsLib.getDocument({ data }).promise;
  const pages = [];
  const limit = Math.min(pdf.numPages || 0, maxPages);
  for (let pageNo = 1; pageNo <= limit; pageNo++) {
    const page = await pdf.getPage(pageNo);
    const viewport = page.getViewport({ scale: 2 });
    const canvas = document.createElement("canvas");
    canvas.width = Math.ceil(viewport.width);
    canvas.height = Math.ceil(viewport.height);
    const ctx = canvas.getContext("2d");
    ctx.fillStyle = "#ffffff";
    ctx.fillRect(0, 0, canvas.width, canvas.height);
    await page.render({ canvasContext: ctx, viewport }).promise;
    pages.push({ pageNo, canvas, previewUrl: canvas.toDataURL("image/jpeg", 0.86), width: canvas.width, height: canvas.height });
  }
  return pages;
};

const fileToImageCanvas = async (file) => {
  const url = URL.createObjectURL(file);
  try {
    const canvas = await imageUrlToCanvas(url, 2200);
    return { canvas, previewUrl: canvas.toDataURL("image/jpeg", 0.88), width: canvas.width, height: canvas.height };
  } finally {
    URL.revokeObjectURL(url);
  }
};

const downloadClientBlob = (blob, fileName) => {
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url;
  a.download = fileName;
  document.body.appendChild(a);
  a.click();
  a.remove();
  setTimeout(() => URL.revokeObjectURL(url), 1200);
};

const canvasToClientBlob = (canvas, type = "image/jpeg", quality = 0.92) => new Promise((resolve, reject) => {
  canvas.toBlob((blob) => blob ? resolve(blob) : reject(new Error("No se pudo crear el archivo convertido")), type, quality);
});

const loadJsZipClient = async () => {
  await loadScriptOnce("https://cdnjs.cloudflare.com/ajax/libs/jszip/3.10.1/jszip.min.js", () => !!window.JSZip);
  if (!window.JSZip) throw new Error("JSZip no cargó correctamente");
  return window.JSZip;
};

const loadJsPdfClient = async () => {
  await loadScriptOnce("https://cdnjs.cloudflare.com/ajax/libs/jspdf/2.5.1/jspdf.umd.min.js", () => !!window.jspdf?.jsPDF);
  if (!window.jspdf?.jsPDF) throw new Error("jsPDF no cargó correctamente");
  return window.jspdf.jsPDF;
};

const savePdfDocumentClient = (doc, fileName) => {
  if (!doc) throw new Error("Documento PDF no inicializado");
  try {
    // DESCARGA PDF ROBUSTA: usamos Blob + enlace temporal para evitar fallos de
    // doc.save() en navegadores móviles o cuando FileSaver no está disponible.
    const blob = doc.output("blob");
    if (!(blob instanceof Blob) || !blob.size) throw new Error("PDF vacío");
    downloadClientBlob(blob, fileName);
  } catch (blobError) {
    // Fallback conservador de jsPDF. Si también falla, el catch superior mostrará el error.
    doc.save(fileName);
  }
};

const pdfFilesToJpegDownloadClient = async (files = []) => {
  const pdfFiles = Array.from(files).filter(f => f.type === "application/pdf");
  if (!pdfFiles.length) throw new Error("Selecciona al menos un PDF para convertir a JPEG");
  const rendered = [];
  for (const file of pdfFiles) {
    const pages = await renderPdfFileToCanvases(file, 80);
    for (const page of pages) {
      const blob = await canvasToClientBlob(page.canvas, "image/jpeg", 0.94);
      const base = sanitizeStorageName(file.name.replace(/\.pdf$/i, "")) || "pdf";
      rendered.push({ blob, name: `${base}_hoja_${String(page.pageNo).padStart(2, "0")}.jpg` });
    }
  }
  if (rendered.length === 1) {
    downloadClientBlob(rendered[0].blob, rendered[0].name);
    return { count: 1, zipped: false };
  }
  const JSZip = await loadJsZipClient();
  const zip = new JSZip();
  rendered.forEach(item => zip.file(item.name, item.blob));
  const zipBlob = await zip.generateAsync({ type: "blob" });
  downloadClientBlob(zipBlob, `pdf_a_jpeg_${new Date().toISOString().slice(0,10)}.zip`);
  return { count: rendered.length, zipped: true };
};

const imageFilesToPdfDownloadClient = async (files = []) => {
  const imageFiles = Array.from(files).filter(f => f.type?.startsWith("image/"));
  if (!imageFiles.length) throw new Error("Selecciona al menos una imagen para convertir a PDF");
  const jsPDF = await loadJsPdfClient();
  let doc = null;
  for (let i = 0; i < imageFiles.length; i++) {
    const file = imageFiles[i];
    const { canvas } = await fileToImageCanvas(file);
    const orientation = canvas.width > canvas.height ? "landscape" : "portrait";
    if (!doc) doc = new jsPDF({ orientation, unit: "mm", format: "letter" });
    else doc.addPage("letter", orientation);
    const pageW = doc.internal.pageSize.getWidth();
    const pageH = doc.internal.pageSize.getHeight();
    const margin = 8;
    const usableW = pageW - margin * 2;
    const usableH = pageH - margin * 2;
    const imgRatio = canvas.height / canvas.width;
    let renderW = usableW;
    let renderH = renderW * imgRatio;
    if (renderH > usableH) {
      renderH = usableH;
      renderW = renderH / imgRatio;
    }
    const x = (pageW - renderW) / 2;
    const y = (pageH - renderH) / 2;
    doc.addImage(canvas.toDataURL("image/jpeg", 0.94), "JPEG", x, y, renderW, renderH, undefined, "FAST");
  }
  const blob = doc.output("blob");
  downloadClientBlob(blob, `imagenes_a_pdf_${new Date().toISOString().slice(0,10)}.pdf`);
  return { count: imageFiles.length };
};

const processPdfOcrClient = async (sourceUrl, bucketPath = "noticias/pdf") => {
  const pdfjsLib = await loadPdfJsClient();
  const res = await fetch(sourceUrl, { mode: "cors" });
  if (!res.ok) throw new Error(`No se pudo leer PDF: HTTP ${res.status}`);
  const data = await res.arrayBuffer();
  const pdf = await pdfjsLib.getDocument({ data }).promise;
  let text = "";
  const imageUrls = [];
  const pageLimit = Math.min(pdf.numPages || 0, 8);
  for (let pageNo = 1; pageNo <= pageLimit; pageNo++) {
    const page = await pdf.getPage(pageNo);
    const viewport = page.getViewport({ scale: 2 });
    const canvas = document.createElement("canvas");
    canvas.width = Math.ceil(viewport.width);
    canvas.height = Math.ceil(viewport.height);
    const ctx = canvas.getContext("2d");
    ctx.fillStyle = "#ffffff";
    ctx.fillRect(0, 0, canvas.width, canvas.height);
    await page.render({ canvasContext: ctx, viewport }).promise;

    const pageText = await ocrCanvasClient(canvas);
    if (pageText) text += (text ? "\n\n" : "") + pageText;

    // Genera una vista previa de páginas en imágenes y las sube al bucket noticias.
    // Si la subida falla, el OCR sigue funcionando y solo omite la miniatura.
    try {
      const blob = await new Promise(resolve => canvas.toBlob(resolve, "image/jpeg", 0.88));
      if (blob) {
        const path = `${bucketPath || "noticias/pdf"}/page_${Date.now()}_${pageNo}_${Math.random().toString(36).slice(2)}.jpg`;
        const { error } = await sb.storage.from("noticias").upload(path, blob, { contentType: "image/jpeg", upsert: false });
        if (!error) {
          const { data: { publicUrl } } = sb.storage.from("noticias").getPublicUrl(path);
          imageUrls.push(publicUrl);
        }
      }
    } catch {}
  }
  return { ok: true, text: text.trim(), image_urls: imageUrls };
};

const callMediaProcessor = async ({ action, sourceUrl, fileType, title, bucketPath }) => {
  // Primero intenta una Edge Function opcional llamada media-process, útil si después
  // decides hacer OCR en servidor. Si no existe, cae automáticamente al OCR en navegador.
  try {
    if (sb?.functions?.invoke) {
      const { data, error } = await sb.functions.invoke("media-process", {
        body: { action, source_url: sourceUrl, file_type: fileType, title, bucket_path: bucketPath, lang: "spa+eng" }
      });
      if (!error && data?.ok !== false && (data?.text || data?.image_urls)) return data;
    }
  } catch (e) {
    console.warn("Edge Function media-process no disponible; usando OCR en navegador.", e?.message || e);
  }

  try {
    const isPdfAction = action === "pdf_to_images_ocr" || String(fileType || "").includes("pdf") || /\.pdf(\?|$)/i.test(String(sourceUrl || ""));
    return isPdfAction
      ? await processPdfOcrClient(sourceUrl, bucketPath)
      : await processImageOcrClient(sourceUrl);
  } catch (e) {
    console.warn("OCR en navegador no disponible.", e?.message || e);
    return { ok: false, text: "", image_urls: [] };
  }
};

const procesarMediaComunicado = async (comunicado) => {
  const isPdf = (comunicado?.archivo_tipo || "").includes("pdf") || String(comunicado?.archivo_url || "").toLowerCase().endsWith(".pdf");
  const isImage = (comunicado?.archivo_tipo || "").startsWith("image/") || /\.(png|jpe?g|webp)$/i.test(String(comunicado?.archivo_url || ""));
  if (!comunicado?.archivo_url || (!isPdf && !isImage)) return { textoExtraido: "", imagenes: [] };
  const result = await callMediaProcessor({
    action: isPdf ? "pdf_to_images_ocr" : "image_ocr",
    sourceUrl: comunicado.archivo_url,
    fileType: comunicado.archivo_tipo,
    title: comunicado.titulo,
    bucketPath: `comunicados/${comunicado.id || Date.now()}`
  });
  const imagenes = parseJsonArray(result?.image_urls);
  return {
    textoExtraido: String(result?.text || "").trim(),
    imagenes: imagenes.length ? imagenes : (isImage ? [comunicado.archivo_url] : []),
  };
};

const insertNoticiaConFallback = async (payload) => {
  const intentos = [
    payload,
    {
      tipo: payload.tipo || "comunicado",
      titulo: payload.titulo || "Comunicado oficial",
      detalle: payload.detalle || "Comunicado oficial publicado por administración.",
      icono: payload.icono || "document",
      color: payload.color || "#2563eb",
      origen: payload.origen || "comunicados",
      archivo_url: payload.archivo_url || null,
      archivo_tipo: payload.archivo_tipo || null,
      media_urls: payload.media_urls || [],
      pdf_urls: payload.pdf_urls || [],
      ocultar_en_feed: false,
    },
    {
      tipo: payload.tipo || "comunicado",
      titulo: payload.titulo || "Comunicado oficial",
      detalle: [payload.detalle, payload.archivo_url ? `Archivo: ${payload.archivo_url}` : ""].filter(Boolean).join("\n\n"),
      icono: payload.icono || "document",
      color: payload.color || "#2563eb",
      origen: payload.origen || "comunicados",
      ocultar_en_feed: false,
    },
    {
      tipo: payload.tipo || "comunicado",
      titulo: payload.titulo || "Comunicado oficial",
      detalle: [payload.detalle, payload.archivo_url ? `Archivo: ${payload.archivo_url}` : ""].filter(Boolean).join("\n\n"),
      icono: payload.icono || "document",
      color: payload.color || "#2563eb",
    },
  ];

  let ultimoError = null;
  for (const intento of intentos) {
    const limpio = Object.fromEntries(Object.entries(intento).filter(([, v]) => v !== undefined));
    const { data, error } = await sb.from("noticias").insert(limpio).select("*").single();
    if (!error) return data;
    ultimoError = error;
    console.warn("Intento de publicar en Noticias falló:", error?.message || error);
  }
  throw ultimoError || new Error("No se pudo insertar la noticia");
};

const syncComunicadoToNoticia = async (comunicado, { processMedia = false } = {}) => {
  if (!comunicado) return null;
  const aprobado = comunicado.aprobado === true || comunicado.aprobado === "true" || comunicado.aprobado === 1 || comunicado.aprobado === "1";
  if (!aprobado) return null;

  // Evita duplicados cuando la tabla ya tiene comunicado_id. Si esa columna no existe, simplemente continúa.
  try {
    const { data: existing, error: findErr } = await sb
      .from("noticias")
      .select("id, comunicado_id")
      .eq("comunicado_id", comunicado.id)
      .maybeSingle();
    if (!findErr && existing?.id) return existing;
  } catch {}

  let media = { textoExtraido: comunicado.texto_extraido || "", imagenes: [] };
  if (processMedia) {
    try {
      media = await procesarMediaComunicado(comunicado);
    } catch (e) {
      console.warn("No se procesó media del comunicado; se publicará con el archivo original:", e?.message || e);
    }
  }

  const isImage = String(comunicado.archivo_tipo || "").startsWith("image/") || /\.(png|jpe?g|webp)$/i.test(String(comunicado.archivo_url || ""));
  const isPdfFile = String(comunicado.archivo_tipo || "").includes("pdf") || /\.pdf(\?|$)/i.test(String(comunicado.archivo_url || ""));
  const imagenes = media.imagenes?.length ? media.imagenes : (isImage && comunicado.archivo_url ? [comunicado.archivo_url] : []);
  const pdfs = isPdfFile && comunicado.archivo_url ? [comunicado.archivo_url] : [];
  const detalleBase = [comunicado.detalle, media.textoExtraido].filter(Boolean).join("\n\n").trim();

  return await insertNoticiaConFallback({
    tipo: "comunicado",
    titulo: comunicado.titulo || "Comunicado oficial",
    detalle: detalleBase || "Comunicado oficial publicado por administración.",
    icono: "document",
    color: "#2563eb",
    origen: "comunicados",
    comunicado_id: comunicado.id,
    archivo_url: comunicado.archivo_url || null,
    archivo_tipo: comunicado.archivo_tipo || null,
    media_urls: imagenes,
    pdf_urls: pdfs,
    texto_extraido: media.textoExtraido || null,
    ocultar_en_feed: false,
    created_at: comunicado.created_at || new Date().toISOString(),
  });
};

const publicarNoticia = async ({ tipo, titulo, detalle, icono, color, origen, ocultar_en_feed, ...extra }) => {
  const tipoNorm = String(tipo || "").toLowerCase();
  const autoOculta = NOTICIAS_TIPOS_AUTO_OCULTOS.includes(tipoNorm);
  const payload = {
    tipo, titulo, detalle, icono, color,
    origen: origen || (autoOculta ? "auto_estado_carril" : "sistema"),
    ocultar_en_feed: ocultar_en_feed ?? autoOculta,
    ...extra,
  };
  const { error } = await sb.from("noticias").insert(payload);
  if (error) {
    // Compatibilidad con tabla antigua sin columnas origen/ocultar_en_feed.
    await sb.from("noticias").insert({ tipo, titulo, detalle, icono, color });
  }
};

