// ─── RESPONSIVE HOOK ─────────────────────────────────────────────────────────
function useWindowWidth() {
  const [w, setW] = useState(() => window.innerWidth);
  useEffect(() => {
    const fn = () => setW(window.innerWidth);
    window.addEventListener("resize", fn);
    return () => window.removeEventListener("resize", fn);
  }, []);
  return w;
}


function AdSenseUnit({
  sectionKey = "global",
  slot,
  variant = "horizontal",
  format = "auto",
  layoutKey = null,
  responsive = true,
}) {
  const adRef = useRef(null);
  const wrapRef = useRef(null);
  const pushedRef = useRef(false);
  const [adStatus, setAdStatus] = useState("loading");

  useEffect(() => {
    pushedRef.current = false;
    setAdStatus("loading");
    const el = adRef.current;
    if (!el) return;

    const readStatus = () => {
      const status = el.getAttribute("data-ad-status");
      if (status === "filled" || status === "unfilled") setAdStatus(status);
    };

    const obs = new MutationObserver(readStatus);
    obs.observe(el, { attributes: true, attributeFilter: ["data-ad-status", "style"] });

    const pushTimer = setTimeout(() => {
      try {
        if (!adRef.current || pushedRef.current) return;
        if (!window.adsbygoogle) window.adsbygoogle = [];
        window.adsbygoogle.push({});
        pushedRef.current = true;
      } catch (err) {
        console.warn("AdSense no pudo inicializarse aún:", err?.message || err);
      }
    }, 600);

    // Si Google no llena el bloque después de unos segundos, no dejamos el hueco transparente.
    const hideTimer = setTimeout(() => {
      const status = el.getAttribute("data-ad-status");
      const hasIframe = !!el.querySelector("iframe");
      const h = el.offsetHeight || 0;
      if (status === "unfilled" || (!hasIframe && h < 12)) setAdStatus("unfilled");
    }, 6500);

    return () => {
      clearTimeout(pushTimer);
      clearTimeout(hideTimer);
      obs.disconnect();
    };
  }, [sectionKey, slot, variant]);

  const isFilled = adStatus === "filled";
  const isHidden = adStatus === "unfilled";
  const isLoading = adStatus === "loading";

  return (
    <div
      ref={wrapRef}
      className={`cm-adsense-wrap cm-adsense-${variant} ${isFilled ? "cm-ad-filled" : ""} ${isHidden ? "cm-ad-hidden" : ""} ${isLoading ? "cm-ad-loading" : ""}`}
      style={{
        width: "100%",
        maxWidth: "980px",
        margin: isHidden || isLoading ? 0 : "10px auto 12px",
        padding: isHidden || isLoading ? 0 : "0 10px",
        position: "relative",
        zIndex: 2,
        overflow: "hidden",
        height: isHidden || isLoading ? 0 : "auto",
        minHeight: 0,
        opacity: isHidden || isLoading ? 0 : 1,
        pointerEvents: isHidden || isLoading ? "none" : "auto",
        transition: "opacity .25s ease",
      }}
      aria-hidden={isHidden || isLoading ? "true" : undefined}
    >
      <ins
        key={`${variant}-${sectionKey}-${slot}`}
        ref={adRef}
        className="adsbygoogle"
        style={{ display: "block", width: "100%" }}
        data-ad-client="ca-pub-6574016310382297"
        data-ad-slot={slot}
        data-ad-format={format}
        data-full-width-responsive={responsive ? "true" : undefined}
        data-ad-layout-key={layoutKey || undefined}
      />
    </div>
  );
}

