const VOTOS_DEFAULT = {
  1: { fluido: 0, moderado: 0, detenido: 0, cierre: 0, retorno_fila: 0, retorno_terminal: 0, retorno_aduana: 0, sinuso: 0 },
  2: { fluido: 0, moderado: 0, detenido: 0, cierre: 0, retorno_fila: 0, retorno_terminal: 0, retorno_aduana: 0, sinuso: 0 },
  3: { fluido: 0, moderado: 0, detenido: 0, cierre: 0, retorno_fila: 0, retorno_terminal: 0, retorno_aduana: 0, sinuso: 0 },
};

const USER_VOTES_DEFAULT = { 1: {}, 2: {}, 3: {} };

const contarVotosFases = (userVotes = USER_VOTES_DEFAULT) => {
  const counts = JSON.parse(JSON.stringify(VOTOS_DEFAULT));
  [1, 2, 3].forEach((fase) => {
    Object.values(userVotes?.[fase] || {}).forEach((tipo) => {
      if (counts[fase]?.[tipo] !== undefined) counts[fase][tipo] += 1;
    });
  });
  return counts;
};

const normalizarVotosFases = (raw) => {
  // Formato nuevo: { _userVotes: { fase: { userId: status } } }
  if (raw?._userVotes) {
    const userVotes = { ...USER_VOTES_DEFAULT, ...raw._userVotes };
    return { userVotes, counts: contarVotosFases(userVotes) };
  }
  // Formato anterior: solo conteos. Se respeta para no romper datos existentes,
  // pero los votos nuevos ya se guardan por usuario.
  return {
    userVotes: { ...USER_VOTES_DEFAULT },
    counts: { ...VOTOS_DEFAULT, ...(raw || {}) },
  };
};


const SEGUNDO_REPORTE_CARRILES = [
  { id: "c1", label: "Carril 1", tipo: "Ingreso", zona: "2° Acceso", defaultTerminal: "general" },
  { id: "c2", label: "Carril 2", tipo: "Ingreso", zona: "2° Acceso", defaultTerminal: "general" },
  { id: "c3", label: "Carril 3", tipo: "Ingreso", zona: "2° Acceso", defaultTerminal: "general" },
  { id: "c4", label: "Carril 4", tipo: "Salida",  zona: "2° Acceso", defaultTerminal: "general" },
];

const describeTrafficValue = (value, prefix) => {
  if (!value || value === "libre") return "";
  const opt = SEGUNDO_TRAFICO_OPTS.find(o => o.id === value);
  return `${prefix}: ${opt?.label || value}`;
};

const buildSegundoCarrilReportRows = (segundoState = {}, terminalNameFn = (id) => id || "General") =>
  SEGUNDO_REPORTE_CARRILES.map(c => {
    const st = segundoState?.[c.id] || {};
    const laneOpt = getCarrilEstadoOpt(st);
    const terminal = terminalNameFn(st.terminal || c.defaultTerminal || "general");
    const detail = [
      `Terminal: ${terminal}`,
      `Zona: ${c.zona}`,
      `Tipo: ${c.tipo}`,
      st.retornos ? "Retornos activos" : "",
      describeTrafficValue(st.expo, "Expo"),
      describeTrafficValue(st.impo, "Impo"),
    ].filter(Boolean).join(" · ");
    return { name: `2° Acceso · ${c.label}`, status: laneOpt.label, detail, color: laneOpt.color };
  });

const buildConfinadaCarrilReportRows = (confinadaState = {}, terminalNameFn = (id) => id || "General") =>
  CONFINADA_CARRILES.map(c => {
    const st = confinadaState?.[c.id] || {};
    const laneOpt = getCarrilEstadoOpt(st);
    const terminal = terminalNameFn(st.terminal || c.defaultTerminal || "general");
    const detail = [
      `Terminal: ${terminal}`,
      "Zona: Confinada",
      st.transferencia ? "Transferencia" : "",
      st.retornos ? "Retornos activos" : "",
      describeTrafficValue(st.expo, "Expo"),
      describeTrafficValue(st.impo, "Impo"),
    ].filter(Boolean).join(" · ");
    return { name: `Confinada · ${c.label}`, status: laneOpt.label, detail, color: laneOpt.color };
  });

const buildSegundoFasesReportRows = (rawFases = null) => {
  const { counts } = normalizarVotosFases(rawFases || {});
  const calcStatus = (votes) => {
    const safe = votes || {};
    const total = Object.values(safe).reduce((s, n) => s + (Number(n) || 0), 0);
    if (total === 0) return "fluido";
    const prioridad = ["cierre", "sinuso", "retorno_aduana", "retorno_terminal", "retorno_fila", "detenido", "moderado", "fluido"];
    for (const key of prioridad) if ((safe[key] || 0) > 0) return key === "sinuso" ? "cierre" : key;
    return "fluido";
  };
  return Object.entries(TRAFICO_FASES).map(([id, fase]) => {
    const statusId = calcStatus(counts?.[id]);
    const opt = TRAFICO_STATUS[statusId] || TRAFICO_STATUS.fluido;
    return { name: `Segundo acceso por fases · ${fase.nombre}`, status: opt.label, detail: fase.descripcion, color: opt.color };
  });
};

const paqueteVotosFases = (userVotes) => ({
  _version: 2,
  _userVotes: userVotes,
  counts: contarVotosFases(userVotes),
  updatedAt: Date.now(),
});

function useLeaflet() {
  const [L, setL] = useState(null);
  useEffect(() => {
    if (window.L) { setL(window.L); return; }
    const link = document.createElement("link");
    link.rel = "stylesheet";
    link.href = "https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/leaflet.min.css";
    document.head.appendChild(link);
    const script = document.createElement("script");
    script.src = "https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/leaflet.min.js";
    script.onload = () => setL(window.L);
    document.head.appendChild(script);
  }, []);
  return L;
}

// ─── Sub-componente: Mapa de Tráfico para 2do Acceso ─────────────────────────
function TrafficMapSegundo({ theme, myId }) {
  const L = useLeaflet();
  const mapRef    = useRef(null);
  const mapInstanceRef = useRef(null);
  const linesRef  = useRef({});
  const shadowsRef = useRef({});
  const tileLayerRef = useRef(null);

  const [votos, setVotos]           = useState(VOTOS_DEFAULT);
  const [userVotes, setUserVotes]   = useState(USER_VOTES_DEFAULT);
  const [statusMapa, setStatusMapa] = useState({ 1: "fluido", 2: "fluido", 3: "fluido" });
  const [lastUpdate, setLastUpdate] = useState(null);
  const [activeVote, setActiveVote] = useState({ fase: null, tipo: null });
  const [mapStyle, setMapStyle]     = useState("streets");

  const TABLA  = "carriles";
  const ROW_ID = "trafico_mapa_votos";

  // ── Calcular status dominante ──────────────────────────────────────────────
  const calcStatus = (votes) => {
    const safe = votes || {};
    const total = Object.values(safe).reduce((s, n) => s + (Number(n) || 0), 0);
    if (total === 0) return "fluido";

    // Para reportes operativos, los estados críticos tienen prioridad visual.
    const prioridad = ["cierre", "sinuso", "retorno_aduana", "retorno_terminal", "retorno_fila", "detenido", "moderado", "fluido"];
    for (const key of prioridad) {
      if ((safe[key] || 0) > 0) return key === "sinuso" ? "cierre" : key;
    }
    return "fluido";
  };

  const recalcAllStatus = (v) => ({
    1: calcStatus(v[1]),
    2: calcStatus(v[2]),
    3: calcStatus(v[3]),
  });

  // ── Cargar votos desde Supabase + suscripción en tiempo real ──────────────
  useEffect(() => {
    sb.from(TABLA).select("*").eq("id", ROW_ID).single().then(({ data }) => {
      if (data?.data) {
        const { userVotes: uv, counts } = normalizarVotosFases(data.data);
        setUserVotes(uv);
        setVotos(counts);
        setStatusMapa(recalcAllStatus(counts));
      }
    });
    const chan = sb.channel("trafico-mapa-rt")
      .on("postgres_changes", { event: "*", schema: "public", table: TABLA }, ({ new: r }) => {
        if (r?.id === ROW_ID && r?.data) {
          const { userVotes: uv, counts } = normalizarVotosFases(r.data);
          setUserVotes(uv);
          setVotos(counts);
          setStatusMapa(recalcAllStatus(counts));
        }
      }).subscribe();
    return () => sb.removeChannel(chan);
  }, []);

  // ── Inicializar mapa Leaflet ───────────────────────────────────────────────
  useEffect(() => {
    if (!L || !mapRef.current || mapInstanceRef.current) return;
    const map = L.map(mapRef.current, { center: [19.0905, -104.2890], zoom: 15, zoomControl: true });
    const style = TRAFICO_MAP_STYLES[mapStyle];
    tileLayerRef.current = L.tileLayer(style.url, { attribution: style.attribution, subdomains: style.subdomains || "abc", maxZoom: 20 }).addTo(map);
    L.polygon(toLLC(TRAFICO_POLIGONO), cmMapPolygonStyle("#facc15", { key: "trafico_poligono", weight: 3, opacity: 0.9, fillOpacity: 0.24 }))
      .addTo(map).bindTooltip("Vialidad — contorno general", { sticky: true });
    Object.entries(TRAFICO_FASES).forEach(([id, fase]) => {
      const shadow = L.polyline(toLLC(fase.coords), { color: "#000", weight: 14, opacity: 0.2, lineCap: "round", lineJoin: "round" }).addTo(map);
      const line   = L.polyline(toLLC(fase.coords), { color: TRAFICO_STATUS.fluido.color, weight: 9, opacity: 0.95, lineCap: "round", lineJoin: "round" }).addTo(map);
      line.bindTooltip(`<b>${fase.nombre}</b><br>${fase.descripcion}`, { sticky: true });
      shadowsRef.current[id] = shadow;
      linesRef.current[id]   = line;
    });
    L.circleMarker([19.08615, -104.29568], { radius: 8, fillColor: "#6366f1", color: "#fff", weight: 3, fillOpacity: 1 }).addTo(map).bindTooltip("Explanada Zona Norte", { direction: "right" });
    L.circleMarker([19.08743, -104.28564], { radius: 8, fillColor: "#8b5cf6", color: "#fff", weight: 3, fillOpacity: 1 }).addTo(map).bindTooltip("Correos de México",    { direction: "top"   });
    L.circleMarker([19.09373, -104.28356], { radius: 8, fillColor: "#ec4899", color: "#fff", weight: 3, fillOpacity: 1 }).addTo(map).bindTooltip("Algodones",             { direction: "top"   });
    L.circleMarker([19.09845, -104.28316], { radius: 8, fillColor: "#14b8a6", color: "#fff", weight: 3, fillOpacity: 1 }).addTo(map).bindTooltip("Libramiento",           { direction: "left"  });
    mapInstanceRef.current = map;
  }, [L]);

  // ── Cambiar estilo de mapa ─────────────────────────────────────────────────
  const changeMapStyle = (newStyle) => {
    if (!mapInstanceRef.current || !tileLayerRef.current) return;
    mapInstanceRef.current.removeLayer(tileLayerRef.current);
    const style = TRAFICO_MAP_STYLES[newStyle];
    tileLayerRef.current = L.tileLayer(style.url, { attribution: style.attribution, subdomains: style.subdomains || "abc", maxZoom: 20 }).addTo(mapInstanceRef.current);
    setMapStyle(newStyle);
  };

  // ── Actualizar colores en el mapa cuando cambia el status ─────────────────
  useEffect(() => {
    Object.entries(statusMapa).forEach(([id, st]) => {
      const line = linesRef.current[id];
      if (line) line.setStyle({ color: TRAFICO_STATUS[st].color });
    });
  }, [statusMapa]);

  // ── Votar y guardar en Supabase ────────────────────────────────────────────
  const votar = async (fase, tipo) => {
    const faseKey = String(fase);

    // Modo tipo "Segundo Acceso": un toque cambia el estado operativo de la fase.
    // No pide confirmación ni acumula consenso; el último estado reportado queda activo.
    const rl = rateLimiter.check(`trafico_fase_${myId}_${fase}`, 2500);
    if (!rl.allowed) return;

    setActiveVote({ fase, tipo });
    setTimeout(() => setActiveVote({ fase: null, tipo: null }), 600);

    const nextUserVotes = {
      ...userVotes,
      [faseKey]: { [myId || "ultimo"]: tipo },
    };
    const nextCounts = contarVotosFases(nextUserVotes);

    setUserVotes(nextUserVotes);
    setVotos(nextCounts);
    setStatusMapa(recalcAllStatus(nextCounts));

    const now = new Date();
    setLastUpdate(`${now.getHours().toString().padStart(2,"0")}:${now.getMinutes().toString().padStart(2,"0")}:${now.getSeconds().toString().padStart(2,"0")}`);

    const paquete = paqueteVotosFases(nextUserVotes);
    writeStatusCache(`carriles:${ROW_ID}`, paquete);
    await sb.from(TABLA).upsert({ id: ROW_ID, data: paquete });
  };

  const totalVotos = (fase) => Object.values(votos[fase] || {}).reduce((a, b) => a + b, 0);

  // ── Render ─────────────────────────────────────────────────────────────────
  return (
    <div>
      {/* Header del mapa */}
      <div style={{ background: "rgba(255,255,255,0.05)", border: "1px solid rgba(255,255,255,0.12)", borderRadius: "12px", padding: "12px 16px", marginBottom: "12px", display: "flex", justifyContent: "space-between", alignItems: "center", flexWrap: "wrap", gap: 8 }}>
        <div>
          <div style={{ fontSize: "10px", color: "#38bdf8", fontFamily: getFont(theme,"secondary"), letterSpacing: "2px", marginBottom: "2px", fontWeight: "700" }}>MAPA — VIALIDAD EN TIEMPO REAL</div>
          <div style={{ color: "rgba(255,255,255,0.7)", fontSize: "12px", fontFamily: getFont(theme,"secondary") }}>Reportado por usuarios · Manzanillo, Colima</div>
        </div>
        {lastUpdate && (
          <span style={{ fontSize: "11px", color: "#e2e8f0", background: "rgba(56,189,248,0.12)", padding: "5px 12px", borderRadius: "20px", border: "1px solid rgba(56,189,248,0.3)", fontFamily: getFont(theme,"secondary") }}>
            🕐 {lastUpdate}
          </span>
        )}
      </div>

      {/* Selector de estilo de mapa */}
      <div style={{ display: "flex", gap: 6, flexWrap: "wrap", marginBottom: "10px", alignItems: "center" }}>
        <span style={{ fontSize: "11px", color: "rgba(255,255,255,0.45)", fontFamily: getFont(theme,"secondary") }}>Estilo:</span>
        {Object.entries(TRAFICO_MAP_STYLES).map(([key, style]) => (
          <button key={key} onClick={() => changeMapStyle(key)} style={{ fontSize: "11px", padding: "5px 10px", borderRadius: "8px", border: `1.5px solid ${mapStyle === key ? "#38bdf8" : "rgba(255,255,255,0.18)"}`, background: mapStyle === key ? "rgba(56,189,248,0.18)" : "rgba(255,255,255,0.04)", color: mapStyle === key ? "#38bdf8" : "#e2e8f0", cursor: "pointer", fontWeight: mapStyle === key ? 700 : 500, fontFamily: getFont(theme,"secondary"), transition: "all 0.2s" }}>
            {style.name}
          </button>
        ))}
      </div>

      {/* Mapa Leaflet */}
      <div ref={mapRef} style={{ width: "100%", height: 420, borderRadius: "14px", overflow: "hidden", border: "1px solid rgba(255,255,255,0.15)", boxShadow: "0 8px 32px rgba(0,0,0,0.4)", marginBottom: "14px", background: "#1a2942" }} />
      {!L && <div style={{ textAlign: "center", color: "#94a3b8", fontSize: "13px", marginBottom: "12px", padding: "12px", background: "rgba(255,255,255,0.04)", borderRadius: "10px", border: "1px solid rgba(255,255,255,0.1)", fontFamily: getFont(theme,"secondary") }}>Cargando mapa…</div>}

      {/* Cards de votación */}
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(280px, 1fr))", gap: 12, marginBottom: 14 }}>
        {[1, 2, 3].map((id) => {
          const st    = statusMapa[id];
          const t     = TRAFICO_STATUS[st];
          const v     = votos[id];
          const total = totalVotos(id);
          const fase  = TRAFICO_FASES[id];
          return (
            <div key={id} style={{ background: "rgba(255,255,255,0.05)", backdropFilter: "blur(12px)", borderRadius: "14px", border: `2px solid ${t.color}`, padding: "14px", display: "flex", flexDirection: "column", gap: 9, transition: "all 0.4s", boxShadow: `0 4px 16px ${t.color}40` }}>
              {/* Encabezado */}
              <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between" }}>
                <span style={{ fontSize: "14px", fontWeight: 700, color: "#ffffff", fontFamily: getFont(theme,"secondary") }}>{fase.nombre}</span>
                <span style={{ fontSize: "10px", fontWeight: 700, background: t.bg, color: t.text, padding: "3px 9px", borderRadius: "20px", border: `1px solid ${t.color}40` }}>{t.emoji} {t.label}</span>
              </div>
              <p style={{ margin: 0, fontSize: "11px", color: "#94a3b8", lineHeight: 1.5, fontFamily: getFont(theme,"secondary") }}>{fase.descripcion}</p>

              {/* Barra de estado dominante: ya no pinta varios colores al mismo tiempo */}
              {total > 0 && (
                <div style={{ height: 6, borderRadius: 6, overflow: "hidden", background: "rgba(255,255,255,0.1)" }}>
                  <div style={{ width: "100%", height: "100%", background: t.color, transition: "background 0.4s", boxShadow: `0 0 12px ${t.color}70` }} />
                </div>
              )}

              {/* Botones de voto */}
              <div style={{ display: "flex", flexDirection: "column", gap: 5, marginTop: 2 }}>
                {["fluido","moderado","detenido","cierre","retorno_fila","retorno_terminal","retorno_aduana"].map((tipo) => {
                  const tr = TRAFICO_STATUS[tipo];
                  const isActive = activeVote.fase === id && activeVote.tipo === tipo;
                  const miVoto = userVotes?.[String(id)]?.[myId] || userVotes?.[id]?.[myId];
                  const isMine = miVoto === tipo;
                  return (
                    <button
                      key={tipo}
                      onClick={() => votar(id, tipo)}
                      style={{ fontSize: "11px", padding: "9px 10px", borderRadius: "9px", border: `2px solid ${tr.color}`, background: isActive || isMine ? tr.color : "rgba(255,255,255,0.04)", color: isActive || isMine ? "#fff" : "#e2e8f0", cursor: "pointer", fontWeight: 600, transition: "all 0.2s", transform: isActive ? "scale(0.97)" : "scale(1)", display: "flex", alignItems: "center", gap: 7, fontFamily: getFont(theme,"secondary") }}
                      onMouseEnter={(e) => { if (!isActive && !isMine) e.currentTarget.style.background = `${tr.color}20`; }}
                      onMouseLeave={(e) => { if (!isActive && !isMine) e.currentTarget.style.background = "rgba(255,255,255,0.04)"; }}
                    >
                      <AppIcon name={tr.icon} size={16} active={true} />
                      <span>{tr.label}{st === tipo ? " · activo" : ""}</span>
                    </button>
                  );
                })}
              </div>

              {/* Total votos */}
              <div style={{ fontSize: "10px", color: "#94a3b8", borderTop: "1px solid rgba(255,255,255,0.1)", paddingTop: 7, textAlign: "center", fontFamily: getFont(theme,"secondary") }}>
                Estado por fase · el último reporte actualiza el mapa en tiempo real
              </div>
            </div>
          );
        })}
      </div>

      {/* Leyenda */}
      <div style={{ display: "flex", gap: 14, alignItems: "center", flexWrap: "wrap", fontSize: "11px", color: "#94a3b8", background: "rgba(255,255,255,0.04)", backdropFilter: "blur(12px)", borderRadius: "10px", padding: "12px 16px", border: "1px solid rgba(255,255,255,0.1)" }}>
        <span style={{ fontWeight: 700, color: "#ffffff", fontFamily: getFont(theme,"secondary") }}>Leyenda:</span>
        {Object.entries(TRAFICO_STATUS).filter(([key]) => key !== "sinuso").map(([key, t]) => (
          <span key={key} style={{ display: "flex", alignItems: "center", gap: 5 }}>
            <span style={{ width: 24, height: 5, borderRadius: 4, background: t.color, display: "inline-block", boxShadow: `0 0 8px ${t.color}60` }} />
            <span style={{ color: "#e2e8f0", fontFamily: getFont(theme,"secondary") }}>{t.label}</span>
          </span>
        ))}
        <span style={{ display: "flex", alignItems: "center", gap: 5 }}>
          <span style={{ width: 24, height: 5, borderRadius: 4, background: "#fbbf24", display: "inline-block", boxShadow: "0 0 8px #fbbf2460" }} />
          <span style={{ color: "#e2e8f0", fontFamily: getFont(theme,"secondary") }}>Vialidad (contorno)</span>
        </span>
      </div>
    </div>
  );
}

// ─── UI: Toggle tipo iOS (segmented switch de 2 opciones) ─────────────────────
// Reemplaza pares de botones mutuamente excluyentes (ej. LIBRE/SATURADO) por
// un solo control deslizante con animación, más rápido de leer y de tocar.
function SegmentedToggle({ value, onChange, leftLabel, rightLabel, leftColor = "#22c55e", rightColor = "#ef4444", pending = false, theme }) {
  const activeColor = value ? rightColor : leftColor;
  return (
    <div
      onClick={() => onChange(!value)}
      role="button"
      aria-pressed={value}
      style={{
        position: "relative",
        display: "grid",
        gridTemplateColumns: "1fr 1fr",
        width: "100%",
        height: "38px",
        background: "#0a1628",
        border: `1px solid ${activeColor}55`,
        borderRadius: "10px",
        padding: "3px",
        cursor: "pointer",
        userSelect: "none",
        opacity: pending ? 0.65 : 1,
        transition: "opacity 0.15s, border-color 0.25s",
        boxSizing: "border-box"
      }}
    >
      {/* Thumb deslizante */}
      <div style={{
        position: "absolute",
        top: "3px",
        bottom: "3px",
        left: value ? "calc(50% + 1.5px)" : "3px",
        width: "calc(50% - 4.5px)",
        background: activeColor + "26",
        border: `1px solid ${activeColor}`,
        borderRadius: "7px",
        transition: "left 0.22s cubic-bezier(.4,0,.2,1), background 0.22s, border-color 0.22s",
        boxShadow: pending ? "none" : `0 0 10px ${activeColor}33`
      }} />
      <div style={{ position:"relative", zIndex:1, display:"flex", alignItems:"center", justifyContent:"center", fontFamily:getFont(theme, "secondary"), fontSize:"11px", fontWeight: !value ? "700" : "400", color: !value ? leftColor : "#64748b", transition:"color 0.22s" }}>
        {leftLabel}
      </div>
      <div style={{ position:"relative", zIndex:1, display:"flex", alignItems:"center", justifyContent:"center", fontFamily:getFont(theme, "secondary"), fontSize:"11px", fontWeight: value ? "700" : "400", color: value ? rightColor : "#64748b", transition:"color 0.22s" }}>
        {rightLabel}
      </div>
    </div>
  );
}

// ─── UI: Dropdown de selección rápida (reemplaza <select> ambiguos) ───────────
// Muestra claramente que es un control de selección (chevron + panel flotante
// con opciones), evitando que el usuario dude si el campo es texto libre.
function QuickSelectDropdown({ value, options, onChange, placeholder = "— Sin especificar —", allowClear = false, pending = false, theme }) {
  const [open, setOpen] = useState(false);
  const [menuPos, setMenuPos] = useState(null);
  const ref = React.useRef(null);
  const current = options.find(o => o.id === value) || null;

  const updateMenuPos = useCallback(() => {
    if (!ref.current) return;
    const r = ref.current.getBoundingClientRect();
    const margin = 8;
    const maxH = Math.min(260, Math.max(140, window.innerHeight - r.bottom - margin));
    setMenuPos({ top: r.bottom + 4, left: r.left, width: r.width, maxHeight: maxH });
  }, []);

  useEffect(() => {
    if (!open) return;
    updateMenuPos();
    const onDocPointer = (e) => {
      if (ref.current && ref.current.contains(e.target)) return;
      if (e.target?.closest?.('[data-cm-quickselect-menu="1"]')) return;
      setOpen(false);
    };
    const onMove = () => updateMenuPos();
    document.addEventListener("mousedown", onDocPointer);
    window.addEventListener("scroll", onMove, true);
    window.addEventListener("resize", onMove);
    return () => {
      document.removeEventListener("mousedown", onDocPointer);
      window.removeEventListener("scroll", onMove, true);
      window.removeEventListener("resize", onMove);
    };
  }, [open, updateMenuPos]);

  const color = current?.color || "#64748b";
  const menu = open && menuPos ? createPortal(
    <div data-cm-quickselect-menu="1" style={{
      position:"fixed", top:menuPos.top, left:menuPos.left, width:menuPos.width,
      zIndex:2147483000, background:"#0f233a", border:"1px solid #1e3a5f", borderRadius:"8px",
      boxShadow:"0 18px 42px rgba(0,0,0,0.62)", overflowY:"auto", maxHeight:menuPos.maxHeight,
      WebkitOverflowScrolling:"touch"
    }}>
      {allowClear && (
        <div
          onClick={() => { onChange(null); setOpen(false); }}
          style={{ padding:"9px 10px", fontFamily:getFont(theme,"secondary"), fontSize:"11px", color:"#64748b", cursor:"pointer", borderBottom:"1px solid rgba(255,255,255,0.06)" }}
          onMouseEnter={e => e.currentTarget.style.background = "rgba(255,255,255,0.05)"}
          onMouseLeave={e => e.currentTarget.style.background = "transparent"}
        >
          {placeholder}
        </div>
      )}
      {options.map(o => (
        <div
          key={o.id}
          onClick={() => { onChange(o.id); setOpen(false); }}
          style={{ padding:"9px 10px", display:"flex", alignItems:"center", justifyContent:"space-between", cursor:"pointer", background: o.id === value ? o.color + "18" : "transparent" }}
          onMouseEnter={e => e.currentTarget.style.background = o.color + "22"}
          onMouseLeave={e => e.currentTarget.style.background = o.id === value ? o.color + "18" : "transparent"}
        >
          <IconText icon={o.icon} label={o.label} size={14} style={{ color: o.color, fontFamily:getFont(theme,"secondary"), fontSize:"11px", fontWeight: o.id === value ? "700" : "500" }} />
          {o.id === value && <span style={{ color:o.color, fontSize:"12px" }}>✓</span>}
        </div>
      ))}
    </div>,
    document.body
  ) : null;

  return (
    <div ref={ref} style={{ position:"relative", zIndex: open ? 99999 : 1, opacity: pending ? 0.65 : 1, transition:"opacity 0.15s" }}>
      <button
        type="button"
        onClick={() => setOpen(v => !v)}
        style={{
          width:"100%", padding:"9px 10px", background:"#0a1628",
          border:`1px solid ${current ? color : "#1e3a5f"}`, borderRadius:"8px",
          color: current ? color : "#64748b", fontFamily:getFont(theme, "secondary"),
          fontSize:"11px", cursor:"pointer", fontWeight: current ? "700" : "400",
          display:"flex", alignItems:"center", justifyContent:"space-between", gap:"6px",
          transition:"border-color 0.2s, color 0.2s"
        }}
      >
        <span style={{ display:"flex", alignItems:"center", gap:"6px", overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>
          {current ? <IconText icon={current.icon} label={current.label} size={14} /> : placeholder}
        </span>
        <svg width="11" height="11" viewBox="0 0 24 24" style={{ flexShrink:0, transform: open ? "rotate(180deg)" : "rotate(0deg)", transition:"transform 0.18s" }}>
          <path d="M6 9l6 6 6-6" stroke={current ? color : "#64748b"} strokeWidth="2.4" fill="none" strokeLinecap="round" strokeLinejoin="round"/>
        </svg>
      </button>
      {menu}
    </div>
  );
}

// ─── UI: Selector de Rueda compacto ──────────────────────────────────────────
// Reduce espacio en listas largas: muestra un botón compacto y abre un wheel picker
// con scroll-snap, selección central y confirmación explícita.
function WheelPickerSelect({ value, options, onChange, placeholder = "— Sin especificar —", allowClear = false, pending = false, theme, title = "Seleccionar opción" }) {
  const [open, setOpen] = useState(false);
  const listRef = React.useRef(null);
  const scrollTimerRef = React.useRef(null);
  const lastInteractionRef = React.useRef("wheel");
  const current = options.find(o => o.id === value) || null;
  const [draft, setDraft] = useState(value ?? null);

  const syncDraftFromWheelCenter = useCallback(() => {
    const list = listRef.current;
    if (!list) return;
    const centerY = list.getBoundingClientRect().top + list.clientHeight / 2;
    const items = Array.from(list.querySelectorAll('[data-wheel-id]'));
    let closest = null;
    let closestDist = Infinity;
    items.forEach(el => {
      const rect = el.getBoundingClientRect();
      const itemCenter = rect.top + rect.height / 2;
      const dist = Math.abs(itemCenter - centerY);
      if (dist < closestDist) {
        closestDist = dist;
        closest = el;
      }
    });
    if (!closest) return;
    const nextId = closest.getAttribute('data-wheel-id');
    setDraft(nextId === '__clear' ? null : nextId);
  }, []);

  const handleWheelScroll = useCallback(() => {
    lastInteractionRef.current = "wheel";
    if (scrollTimerRef.current) clearTimeout(scrollTimerRef.current);
    scrollTimerRef.current = setTimeout(syncDraftFromWheelCenter, 90);
  }, [syncDraftFromWheelCenter]);

  const getDraftFromWheelCenter = useCallback(() => {
    const list = listRef.current;
    if (!list) return draft;
    const centerY = list.getBoundingClientRect().top + list.clientHeight / 2;
    const items = Array.from(list.querySelectorAll('[data-wheel-id]'));
    let closest = null;
    let closestDist = Infinity;
    items.forEach(el => {
      const rect = el.getBoundingClientRect();
      const itemCenter = rect.top + rect.height / 2;
      const dist = Math.abs(itemCenter - centerY);
      if (dist < closestDist) {
        closestDist = dist;
        closest = el;
      }
    });
    if (!closest) return draft;
    const nextId = closest.getAttribute('data-wheel-id');
    return nextId === '__clear' ? null : nextId;
  }, [draft]);

  const applyWheelSelection = useCallback(() => {
    const next = lastInteractionRef.current === "tap" ? draft : getDraftFromWheelCenter();
    setDraft(next);
    onChange(next);
    setOpen(false);
  }, [draft, getDraftFromWheelCenter, onChange]);

  const chooseDraftByTap = useCallback((next, el = null) => {
    lastInteractionRef.current = "tap";
    setDraft(next);
    el?.scrollIntoView?.({ block:"center", behavior:"smooth" });
  }, []);

  useEffect(() => {
    if (!open) return;
    setDraft(value ?? null);
    lastInteractionRef.current = "wheel";
    const onKey = (e) => { if (e.key === "Escape") setOpen(false); };
    document.addEventListener("keydown", onKey);
    return () => {
      document.removeEventListener("keydown", onKey);
      if (scrollTimerRef.current) clearTimeout(scrollTimerRef.current);
    };
  }, [open, value]);

  useEffect(() => {
    if (!open || !listRef.current) return;
    const idx = Math.max(0, options.findIndex(o => o.id === (draft ?? value)));
    setTimeout(() => {
      const item = listRef.current?.querySelector(`[data-wheel-id="${CSS.escape(String(options[idx]?.id || ""))}"]`);
      item?.scrollIntoView?.({ block:"center", behavior:"smooth" });
      setTimeout(syncDraftFromWheelCenter, 220);
    }, 40);
  }, [open, syncDraftFromWheelCenter]);

  const color = current?.color || "#64748b";
  const display = current ? current.label : placeholder;

  const modal = open ? createPortal(
    <div onClick={() => setOpen(false)} style={{ position:"fixed", inset:0, zIndex:2147483000, background:"rgba(2,6,23,.68)", backdropFilter:"blur(8px)", display:"flex", alignItems:"flex-end", justifyContent:"center", padding:"16px" }}>
      <div onClick={e => e.stopPropagation()} style={{ width:"100%", maxWidth:"460px", background:"linear-gradient(180deg,#10233b,#081424)", border:"1px solid rgba(56,189,248,.28)", borderRadius:"18px", boxShadow:"0 24px 70px rgba(0,0,0,.65)", overflow:"hidden" }}>
        <div style={{ padding:"14px 16px", display:"flex", alignItems:"center", justifyContent:"space-between", borderBottom:"1px solid rgba(255,255,255,.08)" }}>
          <div>
            <div style={{ color:"#e2e8f0", fontFamily:getFont(theme,"secondary"), fontWeight:900, fontSize:"13px" }}>{title}</div>
            <div style={{ color:"rgba(255,255,255,.38)", fontFamily:getFont(theme,"secondary"), fontSize:"10px", marginTop:"2px" }}>Desliza la rueda o toca una opción y confirma</div>
          </div>
          <button onClick={() => setOpen(false)} style={{ width:"32px", height:"32px", borderRadius:"999px", border:"1px solid rgba(255,255,255,.12)", background:"rgba(255,255,255,.06)", color:"#94a3b8", cursor:"pointer" }}>✕</button>
        </div>

        <div style={{ position:"relative", padding:"10px 14px" }}>
          <div style={{ position:"absolute", left:"14px", right:"14px", top:"50%", height:"44px", transform:"translateY(-50%)", border:"1px solid rgba(56,189,248,.42)", background:"rgba(56,189,248,.08)", borderRadius:"12px", pointerEvents:"none", boxShadow:"0 0 0 999px rgba(2,6,23,.18)" }} />
          <div
            ref={listRef}
            onScroll={handleWheelScroll}
            onPointerUp={syncDraftFromWheelCenter}
            onTouchEnd={syncDraftFromWheelCenter}
            style={{ height:"190px", overflowY:"auto", scrollSnapType:"y mandatory", WebkitOverflowScrolling:"touch", padding:"74px 0", scrollbarWidth:"thin" }}
          >
            {allowClear && (
              <button
                type="button"
                data-wheel-id="__clear"
                onClick={(e) => chooseDraftByTap(null, e.currentTarget)}
                style={{ scrollSnapAlign:"center", width:"100%", height:"48px", margin:"4px 0", borderRadius:"12px", border:"none", background: draft == null ? "rgba(100,116,139,.20)" : "transparent", color:draft == null ? "#94a3b8" : "#64748b", fontFamily:getFont(theme,"secondary"), fontSize:"13px", fontWeight:draft == null ? 800 : 500, cursor:"pointer" }}
              >{placeholder}</button>
            )}
            {options.map(o => {
              const active = o.id === draft;
              return (
                <button
                  type="button"
                  key={o.id}
                  data-wheel-id={o.id}
                  onClick={(e) => chooseDraftByTap(o.id, e.currentTarget)}
                  style={{ scrollSnapAlign:"center", width:"100%", minHeight:"48px", margin:"4px 0", padding:"9px 14px", borderRadius:"12px", border:"none", background: active ? o.color + "22" : "transparent", color: active ? o.color : "rgba(226,232,240,.68)", fontFamily:getFont(theme,"secondary"), fontSize: active ? "14px" : "13px", fontWeight: active ? 900 : 650, cursor:"pointer", display:"flex", alignItems:"center", justifyContent:"space-between", gap:"10px", transition:"all .14s" }}
                >
                  <span>{o.label}</span>
                  {active && <span style={{ color:o.color, fontWeight:900 }}>✓</span>}
                </button>
              );
            })}
          </div>
        </div>

        <div style={{ padding:"12px 14px 14px", display:"grid", gridTemplateColumns:"1fr 1fr", gap:"8px", borderTop:"1px solid rgba(255,255,255,.08)" }}>
          <button type="button" onClick={() => setOpen(false)} style={{ padding:"11px", borderRadius:"10px", border:"1px solid rgba(255,255,255,.12)", background:"rgba(255,255,255,.05)", color:"#94a3b8", fontFamily:getFont(theme,"secondary"), fontWeight:800, cursor:"pointer" }}>Cancelar</button>
          <button type="button" onClick={applyWheelSelection} style={{ padding:"11px", borderRadius:"10px", border:"1px solid rgba(34,197,94,.45)", background:"rgba(34,197,94,.16)", color:"#22c55e", fontFamily:getFont(theme,"secondary"), fontWeight:900, cursor:"pointer" }}>Aplicar</button>
        </div>
      </div>
    </div>,
    document.body
  ) : null;

  return (
    <div style={{ opacity: pending ? .65 : 1 }}>
      <button
        type="button"
        onClick={() => setOpen(true)}
        style={{ width:"100%", minHeight:"44px", padding:"11px 14px", background:"linear-gradient(180deg, rgba(10,22,40,.98), rgba(8,18,34,.98))", border:`1px solid ${current ? color : "#1e3a5f"}`, borderRadius:"10px", color: current ? color : "#64748b", fontFamily:getFont(theme,"secondary"), fontSize:"13px", cursor:"pointer", fontWeight: current ? 900 : 650, display:"flex", alignItems:"center", justifyContent:"space-between", gap:"10px", boxShadow: current ? `inset 0 0 0 1px ${color}22` : "none" }}
      >
        <span style={{ minWidth:0, flex:1, overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap", display:"flex", alignItems:"center", justifyContent:"center", gap:"7px" }}>{current ? <IconText icon={current.icon} label={display} size={16} /> : display}</span>
        <span style={{ color: current ? color : "#64748b", fontSize:"16px", lineHeight:1 }}>☰</span>
      </button>
      {modal}
    </div>
  );
}

// ─── UI: Buscador de terminal (filtro en vivo sobre los botones existentes) ───
function TerminalSearchBox({ value, onChange, theme }) {
  return (
    <div style={{ position:"relative", marginBottom:"10px" }}>
      <svg width="13" height="13" viewBox="0 0 24 24" style={{ position:"absolute", left:"10px", top:"50%", transform:"translateY(-50%)", pointerEvents:"none" }}>
        <circle cx="10.5" cy="10.5" r="6.5" stroke="#64748b" strokeWidth="2" fill="none"/>
        <path d="M15.5 15.5L20 20" stroke="#64748b" strokeWidth="2" strokeLinecap="round"/>
      </svg>
      <input
        type="text"
        value={value}
        onChange={e => onChange(e.target.value)}
        placeholder="Buscar terminal (ej. CONTECON)…"
        style={{
          width:"100%", padding:"8px 10px 8px 30px", background:"#0a1628",
          border:"1px solid #1e3a5f", borderRadius:"8px", color:"#e2e8f0",
          fontFamily:getFont(theme, "secondary"), fontSize:"11px", outline:"none", boxSizing:"border-box"
        }}
      />
      {value && (
        <button
          onClick={() => onChange("")}
          style={{ position:"absolute", right:"8px", top:"50%", transform:"translateY(-50%)", background:"transparent", border:"none", color:"#64748b", fontSize:"14px", cursor:"pointer", lineHeight:1, padding:"2px 4px" }}
        >
          ✕
        </button>
      )}
    </div>
  );
}

function SegundoAccesoTab({ myId }) {
  const theme = React.useContext(ThemeContext);
  const [subTab, setSubTab] = useState("segundo");
  const [segundoLegendOpen, setSegundoLegendOpen] = useState(false);
  const [selectedSecondLane, setSelectedSecondLane] = useState("c4");
  const [confinadaLegendOpen, setConfinadaLegendOpen] = useState(false);
  const [selectedConfinadaLane, setSelectedConfinadaLane] = useState("cf_c1");
  const [terminalSearch, setTerminalSearch] = useState({}); // { [carrilId]: string } — filtro en vivo del buscador de terminal
  const [pendingKeys, setPendingKeys] = useState({}); // { "carrilId:field": true } — feedback optimista mientras confirma el servidor

  // ── Estado 2DO ACCESO ──
  const [carriles, setCarriles] = useState(mkSegundoIngreso);
  // ── Estado CONFINADA ──
  const [confinada, setConfinada] = useState(mkConfinadaState);

  const [toast, setToast] = useState(null);
  const notify = (msg, color = "#38bdf8") => { setToast({ msg, color }); setTimeout(() => setToast(null), 2800); };

  const TABLA = "carriles";
  const ROW_ID = "segundo_acceso";
  const ROW_ID_CF = "confinada_acceso";

  const saveToSupa = async (newState) => { persistCarrilesRow(ROW_ID, newState); const { error } = await sb.from(TABLA).upsert({ id: ROW_ID, data: newState }); return error; };
  const saveConfinada = async (newState) => { persistCarrilesRow(ROW_ID_CF, newState); const { error } = await sb.from(TABLA).upsert({ id: ROW_ID_CF, data: newState }); return error; };

  // ── Helper: marca/desmarca una clave como "pendiente de confirmación" (feedback optimista) ──
  const setPending = (key, on) => setPendingKeys(prev => {
    if (on) return { ...prev, [key]: true };
    const { [key]: _omit, ...rest } = prev;
    return rest;
  });

  useEffect(() => {
    sb.from(TABLA).select("*").eq("id", ROW_ID).single().then(({ data, error }) => {
      setCarriles(mergeCarrilesRowByLatest(ROW_ID, mkSegundoIngreso(), error ? {} : (data?.data || {})));
    });
    sb.from(TABLA).select("*").eq("id", ROW_ID_CF).single().then(({ data, error }) => {
      setConfinada(mergeCarrilesRowByLatest(ROW_ID_CF, mkConfinadaState(), error ? {} : (data?.data || {})));
    });
    const chan = sb.channel("segundo-rt")
      .on("postgres_changes", { event: "*", schema: "public", table: TABLA }, ({ new: r }) => {
        if (r?.id === ROW_ID && r?.data) setCarriles(prev => mergeCarrilesRowByLatest(ROW_ID, prev || mkSegundoIngreso(), r.data));
        if (r?.id === ROW_ID_CF && r?.data) setConfinada(prev => mergeCarrilesRowByLatest(ROW_ID_CF, prev || mkConfinadaState(), r.data));
      }).subscribe();
    return () => sb.removeChannel(chan);
  }, []);

  // ── Handlers 2DO ACCESO ──
  const updateIngreso = async (id, field, value) => {
    if (!carriles) return;
    const prev = carriles;
    const key = `${id}:${field}`;
    const next = { ...carriles, [id]: { ...carriles[id], [field]: value, lastUpdate: Date.now(), updatedBy: "Tú" } };
    setCarriles(next); // ✓ feedback instantáneo, sin esperar al servidor
    setPending(key, true);
    const error = await saveToSupa(next);
    setPending(key, false);
    if (error) {
      setCarriles(prev); // ↩ revertir si el guardado falló
      notify("✗ No se pudo guardar, se revirtió el cambio", "#ef4444");
      return;
    }
    const carrilDefForAudit = SEGUNDO_CARRILES_INGRESO.find(c => c.id === id);
    const valorLabelAudit = field === "retornos" ? (value ? "Con retornos" : "Sin retornos") : field === "saturado" ? (value ? "Saturado" : "Libre") : String(value);
    await auditLog({ action:"modificar_carril_segundo", section:"segundo", entityId:id, before:carriles[id], after:{ carril:carrilDefForAudit?.label || id, campo:field, value, valor_label:valorLabelAudit, summary:`${getDeviceId()} votó ${valorLabelAudit} en ${carrilDefForAudit?.label || id}` }, actor:`Usuario_${myId.slice(-4)}` });
    notify("✓ Carril actualizado", "#22c55e");
    const carrilDef = SEGUNDO_CARRILES_INGRESO.find(c => c.id === id);
    const fieldLabel = field === "saturado" ? (value ? "Saturado" : "Libre") : (value ? "Con Retornos" : "Sin Retornos");
    await publicarNoticia({ tipo: "segundo", icono: "road", color: "#34d399", titulo: `2do Acceso ${carrilDef?.label || id} — ${fieldLabel}`, detalle: "Estado de carril actualizado" });
  };
  const updateSalida = async (field, value) => {
    const prev = carriles;
    const key = `c4:${field}`;
    const next = { ...carriles, c4: { ...carriles.c4, [field]: value, lastUpdate: Date.now(), updatedBy: "Tú" } };
    setCarriles(next); // ✓ feedback instantáneo, sin esperar al servidor
    setPending(key, true);
    const error = await saveToSupa(next);
    setPending(key, false);
    if (error) {
      setCarriles(prev); // ↩ revertir si el guardado falló
      notify("✗ No se pudo guardar, se revirtió el cambio", "#ef4444");
      return;
    }
    await auditLog({ action:"modificar_carril_salida", section:"segundo", entityId:"c4", before:prev.c4, after:{ carril:"Carril 4", campo:field, value, valor_label:String(value), summary:`${getDeviceId()} modificó Carril 4 · ${field}: ${String(value)}` }, actor:`Usuario_${myId.slice(-4)}` });
    notify("✓ Carril de salida actualizado", "#22c55e");
    const fieldLabel =
      field === "saturado" ? (value ? "Saturado" : "Libre") :
      field === "retornos" ? (value ? "Con retornos" : "Sin retornos") :
      field === "expo" ? `Exportación: ${SEGUNDO_TRAFICO_OPTS.find(o => o.id === value)?.label || value}` :
      field === "impo" ? `Importación: ${SEGUNDO_TRAFICO_OPTS.find(o => o.id === value)?.label || value}` :
      field === "expo_contenedor" ? `Contenedor: ${SEGUNDO_CONTENEDOR_OPTS.find(o => o.id === value)?.label || "sin selección"}` :
      "Actualizado";
    await publicarNoticia({ tipo: "segundo", icono: "road", color: "#22c55e", titulo: `2do Acceso Carril 4 — ${fieldLabel}`, detalle: "Estado de carril de salida actualizado" });
  };
  const updateIngresoEstado = async (id, estadoId) => {
    if (!carriles) return;
    const prev = carriles;
    const def = SEGUNDO_CARRILES_INGRESO.find(c => c.id === id);
    const opt = CARRIL_ESTADO_OPTS.find(o => o.id === estadoId) || CARRIL_ESTADO_OPTS[0];
    const current = carriles[id] || {};
    const nextTerminal = opt.id === "sin_uso" ? "sin_uso" : (current.terminal === "sin_uso" ? (def?.defaultTerminal || "ssa") : current.terminal);
    const next = {
      ...carriles,
      [id]: { ...current, terminal: nextTerminal, estado_carril: opt.id, saturado: carrilEstadoIsSaturado(opt.id), lastUpdate: Date.now(), updatedBy: "Tú" }
    };
    setCarriles(next);
    setPending(`${id}:estado_carril`, true);
    const error = await saveToSupa(next);
    setPending(`${id}:estado_carril`, false);
    if (error) { setCarriles(prev); notify("✗ No se pudo guardar, se revirtió el cambio", "#ef4444"); return; }
    await auditLog({ action:"modificar_estado_carril_segundo", section:"segundo", entityId:id, before:prev[id], after:{ carril:def?.label || id, campo:"estado_carril", value:opt.id, valor_label:opt.label, summary:`${getDeviceId()} marcó ${def?.label || id} como ${opt.label}` }, actor:`Usuario_${myId.slice(-4)}` });
    notify("✓ Estado del carril actualizado", opt.color);
    await publicarNoticia({ tipo: "segundo", icono: "road", color: opt.color, titulo: `2do Acceso ${def?.label || id} — ${opt.label}`, detalle: "Estado de carril actualizado" });
  };

  const updateSalidaEstado = async (estadoId) => {
    if (!carriles?.c4) return;
    const prev = carriles;
    const opt = CARRIL_ESTADO_OPTS.find(o => o.id === estadoId) || CARRIL_ESTADO_OPTS[0];
    const next = { ...carriles, c4: { ...carriles.c4, estado_carril: opt.id, saturado: carrilEstadoIsSaturado(opt.id), lastUpdate: Date.now(), updatedBy: "Tú" } };
    setCarriles(next);
    setPending("c4:estado_carril", true);
    const error = await saveToSupa(next);
    setPending("c4:estado_carril", false);
    if (error) { setCarriles(prev); notify("✗ No se pudo guardar, se revirtió el cambio", "#ef4444"); return; }
    await auditLog({ action:"modificar_estado_carril_salida", section:"segundo", entityId:"c4", before:prev.c4, after:{ carril:"Carril 4", campo:"estado_carril", value:opt.id, valor_label:opt.label, summary:`${getDeviceId()} marcó Carril 4 como ${opt.label}` }, actor:`Usuario_${myId.slice(-4)}` });
    notify("✓ Estado del carril de salida actualizado", opt.color);
    await publicarNoticia({ tipo: "segundo", icono: "road", color: opt.color, titulo: `2do Acceso Carril 4 — ${opt.label}`, detalle: "Estado de carril de salida actualizado" });
  };

  const resetAll = async () => {
    const next = mkSegundoIngreso();
    setCarriles(next);
    await saveToSupa(next);
    notify("✓ Todos los carriles restablecidos", "#22c55e");
  };
  const resetOne = async (id) => {
    const def = SEGUNDO_CARRILES_INGRESO.find(c => c.id === id);
    const next = { ...carriles, [id]: { terminal: def?.defaultTerminal || "ssa", estado_carril: "libre", saturado: false, retornos: false, expo: "libre", expo_contenedor: null, impo: "libre", lastUpdate: Date.now(), updatedBy: "Reset" } };
    setCarriles(next);
    await saveToSupa(next);
    notify("✓ Carril restablecido", "#22c55e");
  };

  // ── Handlers CONFINADA ──
  const updateConfinada = async (id, field, value) => {
    if (!confinada) return;
    const key = `${id}:${field}`;
    const next = { ...confinada, [id]: { ...confinada[id], [field]: value, lastUpdate: Date.now(), updatedBy: "Tú" } };
    setConfinada(next);
    setPending(key, true);
    await saveConfinada(next);
    setPending(key, false);
    const carrilDefForAudit = CONFINADA_CARRILES.find(c => c.id === id);
    const valorLabelAudit = field === "retornos" ? (value ? "Con retornos" : "Sin retornos") : field === "saturado" ? (value ? "Saturado" : "Libre") : field === "transferencia" ? (value ? "Segundo Acceso" : "Normal") : String(value);
    await auditLog({ action:"modificar_carril_confinada", section:"segundo", entityId:id, before:confinada[id], after:{ carril:carrilDefForAudit?.label || id, campo:field, value, valor_label:valorLabelAudit, summary:`${getDeviceId()} votó ${valorLabelAudit} en ${carrilDefForAudit?.label || id}` }, actor:`Usuario_${myId.slice(-4)}` });
    notify("✓ Carril Confinada actualizado", "#a78bfa");
    const carrilDef = CONFINADA_CARRILES.find(c => c.id === id);
    const fieldLabel = field === "saturado" ? (value ? "Saturado" : "Libre") : field === "transferencia" ? (value ? "Segundo Acceso" : "Normal") : (value ? "Con Retornos" : "Sin Retornos");
    await publicarNoticia({ tipo: "segundo", icono: "🔒", color: "#a78bfa", titulo: `Confinada ${carrilDef?.label || id} — ${fieldLabel}`, detalle: "Estado de carril actualizado" });
  };
  const updateConfinadaEstado = async (id, estadoId) => {
    if (!confinada) return;
    const prev = confinada;
    const def = CONFINADA_CARRILES.find(c => c.id === id);
    const opt = CARRIL_ESTADO_OPTS.find(o => o.id === estadoId) || CARRIL_ESTADO_OPTS[0];
    const current = confinada[id] || {};
    const nextTerminal = estadoId === "sin_uso" ? "sin_uso" : (current.terminal === "sin_uso" ? (def?.defaultTerminal || "general") : current.terminal);
    const next = {
      ...confinada,
      [id]: { ...current, terminal: nextTerminal, estado_carril: opt.id, saturado: carrilEstadoIsSaturado(opt.id), lastUpdate: Date.now(), updatedBy: "Tú" }
    };
    setConfinada(next);
    setPending(`${id}:estado_carril`, true);
    await saveConfinada(next);
    setPending(`${id}:estado_carril`, false);
    await auditLog({ action:"modificar_estado_carril_confinada", section:"segundo", entityId:id, before:prev[id], after:{ carril:def?.label || id, campo:"estado_carril", value:opt.id, valor_label:opt.label, summary:`${getDeviceId()} marcó ${def?.label || id} como ${opt.label}` }, actor:`Usuario_${myId.slice(-4)}` });
    notify("✓ Estado del carril Confinada actualizado", opt.color);
    await publicarNoticia({ tipo: "segundo", icono: "🔒", color: opt.color, titulo: `Confinada ${def?.label || id} — ${opt.label}`, detalle: "Estado de carril actualizado" });
  };

  const resetAllConfinada = async () => {
    const next = mkConfinadaState();
    setConfinada(next);
    await saveConfinada(next);
    notify("✓ Confinada restablecida", "#a78bfa");
  };
  const resetOneConfinada = async (id) => {
    const def = CONFINADA_CARRILES.find(c => c.id === id);
    const next = { ...confinada, [id]: { terminal: def?.defaultTerminal || "timsa", estado_carril: "libre", saturado: false, retornos: false, transferencia: false, expo: "libre", expo_contenedor: null, impo: "libre", lastUpdate: Date.now(), updatedBy: "Reset" } };
    setConfinada(next);
    await saveConfinada(next);
    notify("✓ Carril restablecido", "#a78bfa");
  };

  const getTermName = (id) => id === "sin_uso" ? "SIN USO" : TODAS_TERMINALES.find(t => t.id === id)?.name || id?.toUpperCase() || "—";
  const getTermZona = (id) => id === "sin_uso" ? "Sin uso" : TODAS_TERMINALES.find(t => t.id === id)?.zona || "";
  const termsNorte  = TODAS_TERMINALES.filter(t => t.zona === "Norte");
  const termsSur    = TODAS_TERMINALES.filter(t => t.zona === "Sur");
  const terminalOptionsSegundo = [
    { id:"general", label:"GENERAL · todas las terminales", color:getTerminalBrandColor("general"), icon:"bolt" },
    ...termsNorte.map(t => ({ id:t.id, label:`Norte · ${t.name}`, color:getTerminalBrandColor(t.id), icon:"port-terminal" })),
    ...termsSur.map(t => ({ id:t.id, label:`Sur · ${t.name}`, color:getTerminalBrandColor(t.id), icon:"port-terminal" })),
  ];
  const terminalOptionsConfinada = [
    { id:"general", label:"GENERAL · todas las terminales", color:getTerminalBrandColor("general"), icon:"bolt" },
    ...termsSur.map(t => ({ id:t.id, label:`Sur · ${t.name}`, color:getTerminalBrandColor(t.id), icon:"port-terminal" })),
    { id:"sin_uso", label:"SIN USO · carril fuera de operación", color:"#71717a", icon:"ban" },
  ];

  const laneCardShell = (accent) => ({
    background:"linear-gradient(180deg, rgba(255,255,255,0.08), rgba(8,15,30,0.96))",
    backdropFilter:"blur(14px)", WebkitBackdropFilter:"blur(14px)",
    border:`1px solid ${accent}52`, borderRadius:"18px", padding:"14px", marginBottom:"16px",
    boxShadow:`0 18px 40px ${accent}14, inset 0 1px 0 rgba(255,255,255,0.07)`
  });
  const laneMiniLabelStyle = { fontSize:"9px", color:"rgba(255,255,255,0.46)", fontFamily:getFont(theme, "secondary"), letterSpacing:"1.2px", textTransform:"uppercase" };
  const laneHeroTitleStyle = { color:"#f8fafc", fontFamily:getFont(theme, "title"), fontWeight:"800", fontSize:"17px", letterSpacing:"-.01em" };
  const laneFieldTitleStyle = { fontSize:"10px", color:"rgba(255,255,255,0.54)", fontFamily:getFont(theme, "secondary"), letterSpacing:"1.1px", textTransform:"uppercase" };
  const laneBlockStyle = (accent, soft = true) => ({
    background: soft ? `linear-gradient(180deg, ${accent}10, rgba(7,17,31,0.92))` : "rgba(7,17,31,0.92)",
    border:`1px solid ${accent}3f`, borderRadius:"14px", padding:"12px", boxShadow:`0 8px 22px ${accent}16`
  });
  const laneHeaderNode = (iconName, title, subtitle, accent, iconSize = 26) => (
    <div style={{ display:"flex", alignItems:"center", gap:"10px", marginBottom:"10px" }}>
      <div style={{ width:"44px", height:"44px", borderRadius:"12px", display:"grid", placeItems:"center", background:`linear-gradient(180deg, ${accent}24, rgba(255,255,255,0.03))`, border:`1px solid ${accent}44`, boxShadow:`inset 0 1px 0 rgba(255,255,255,0.08), 0 10px 24px ${accent}22` }}>
        <AppIcon name={iconName} size={iconSize} active />
      </div>
      <div style={{ minWidth:0 }}>
        <div style={laneFieldTitleStyle}>{title}</div>
        <div style={{ color:"#f8fafc", fontFamily:getFont(theme, "secondary"), fontWeight:"800", fontSize:"13px", lineHeight:1.15 }}>{subtitle}</div>
      </div>
    </div>
  );

  const renderSegundoIngresoCard = (carril) => {
    const st = carriles[carril.id];
    const laneOpt = getCarrilEstadoOpt(st);
    const isSinUso = laneOpt.id === "sin_uso" || st.terminal === "sin_uso";
    const termObj = TODAS_TERMINALES.find(t => t.id === st.terminal);
    const zonaColor = isSinUso ? "#6b7280" : termObj?.zona === "Todas" ? "#fbbf24" : termObj?.zona === "Norte" ? "#38bdf8" : "#a78bfa";
    const expoOpt = SEGUNDO_TRAFICO_OPTS.find(o => o.id === (st.expo || "libre"));
    const expoContOpt = SEGUNDO_CONTENEDOR_OPTS.find(o => o.id === st.expo_contenedor);
    const impoOpt = SEGUNDO_TRAFICO_OPTS.find(o => o.id === (st.impo || "libre"));
    const isChanged = getCarrilEstadoId(st) !== "libre" || st.retornos || st.terminal !== carril.defaultTerminal || (st.expo && st.expo !== "libre") || (st.impo && st.impo !== "libre") || !!st.expo_contenedor;
    return (
      <div key={carril.id} style={laneCardShell(laneOpt.id !== "libre" ? laneOpt.color : zonaColor)}>
        <div style={{ display:"flex", alignItems:"flex-start", justifyContent:"space-between", gap:"12px", flexWrap:"wrap", marginBottom:"12px" }}>
          <div>
            <div style={{ display:"flex", alignItems:"center", gap:"8px", flexWrap:"wrap" }}>
              <div style={{ background:`${zonaColor}18`, border:`1px solid ${zonaColor}44`, borderRadius:"999px", padding:"4px 10px", color:zonaColor, fontFamily:getFont(theme, "secondary"), fontSize:"12px", fontWeight:"800", letterSpacing:".05em", textTransform:"uppercase" }}>{carril.label}</div>
              <Badge color="#22c55e" small>INGRESO</Badge>
            </div>
            <div style={{ color:"rgba(255,255,255,0.42)", fontSize:"10px", fontFamily:getFont(theme, "secondary"), marginTop:"5px" }}>{timeAgo(st.lastUpdate)} · {st.updatedBy}</div>
          </div>
          <div style={{ display:"flex", alignItems:"center", gap:"6px", flexWrap:"wrap", justifyContent:"flex-end" }}>
            <Badge color={laneOpt.color} small>{laneOpt.label.toUpperCase()}</Badge>
            {st.retornos && <Badge color="#f97316" small>CON RETORNOS</Badge>}
            {isChanged && <button onClick={() => resetOne(carril.id)} style={{ padding:"5px 10px", background:"rgba(20,184,166,0.12)", border:"1px solid rgba(20,184,166,0.32)", borderRadius:"999px", color:"#2dd4bf", fontFamily:getFont(theme, "secondary"), fontSize:"10px", fontWeight:"800", cursor:"pointer" }}>NORMAL</button>}
          </div>
        </div>

        <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fit,minmax(230px,1fr))", gap:"12px" }}>
          <div style={laneBlockStyle(zonaColor)}>
            {laneHeaderNode("terminal-crane", "Terminal", isSinUso ? "Sin uso / sin operación" : (termObj?.name || "Terminal no asignada"), zonaColor, 30)}
            <div style={{ ...laneMiniLabelStyle, marginBottom:"4px" }}>Asignación actual</div>
            <div style={{ ...laneHeroTitleStyle, color:zonaColor, fontSize:"16px", marginBottom:"2px" }}>{isSinUso ? "SIN USO" : getTermName(st.terminal)}</div>
            <div style={{ color:"rgba(255,255,255,0.46)", fontSize:"11px", marginBottom:"10px" }}>{isSinUso ? "Carril fuera de operación" : (getTermZona(st.terminal) === "Todas" ? "Disponible para todas las terminales" : `Zona ${getTermZona(st.terminal)}`)}</div>
            <WheelPickerSelect
              value={st.terminal || carril.defaultTerminal}
              options={terminalOptionsSegundo}
              onChange={(v) => updateIngreso(carril.id,"terminal",v)}
              pending={!!pendingKeys[`${carril.id}:terminal`]}
              theme={theme}
              title={`${carril.label} · Terminal / uso`}
            />
          </div>

          <div style={laneBlockStyle(laneOpt.color)}>
            {laneHeaderNode("lane-status-monitor", "Estado del carril", laneOpt.label, laneOpt.color, 30)}
            <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", gap:"10px", marginBottom:"10px" }}>
              <div>
                <div style={{ ...laneMiniLabelStyle, marginBottom:"3px" }}>Estado vigente</div>
                <div style={{ ...laneHeroTitleStyle, color:laneOpt.color }}>{laneOpt.label}</div>
              </div>
              <Badge color={laneOpt.color} small>{laneOpt.id === "sin_especificar" ? "N/A" : laneOpt.label.toUpperCase()}</Badge>
            </div>
            <WheelPickerSelect
              value={getCarrilEstadoId(st)}
              options={CARRIL_ESTADO_OPTS}
              onChange={(v) => updateIngresoEstado(carril.id, v || "libre")}
              pending={!!pendingKeys[`${carril.id}:estado_carril`]}
              theme={theme}
              title={`${carril.label} · Estado del carril`}
            />
          </div>

          <div style={laneBlockStyle("#f97316") }>
            {laneHeaderNode("truck-export", "Exportación", expoOpt?.label || "Libre", "#f97316", 28)}
            <div style={{ ...laneMiniLabelStyle, marginBottom:"8px" }}>Tráfico de exportación</div>
            <WheelPickerSelect
              value={st.expo || "libre"}
              options={SEGUNDO_TRAFICO_OPTS}
              onChange={(v) => updateIngreso(carril.id,"expo",v)}
              pending={!!pendingKeys[`${carril.id}:expo`]}
              theme={theme}
              title={`${carril.label} · Exportación`}
            />
          </div>

          <div style={laneBlockStyle("#38bdf8") }>
            {laneHeaderNode("truck-import", "Importación", impoOpt?.label || "Libre", "#38bdf8", 28)}
            <div style={{ ...laneMiniLabelStyle, marginBottom:"8px" }}>Tráfico de importación</div>
            <WheelPickerSelect
              value={st.impo || "libre"}
              options={SEGUNDO_TRAFICO_OPTS}
              onChange={(v) => updateIngreso(carril.id,"impo",v)}
              pending={!!pendingKeys[`${carril.id}:impo`]}
              theme={theme}
              title={`${carril.label} · Importación`}
            />
          </div>

          <div style={laneBlockStyle("#f97316") }>
            {laneHeaderNode("container-expo-open", "Contenedor Expo", expoContOpt?.label || "Sin especificar", "#f97316", 28)}
            <div style={{ ...laneMiniLabelStyle, marginBottom:"8px" }}>Condición del contenedor</div>
            <WheelPickerSelect
              value={st.expo_contenedor}
              options={SEGUNDO_CONTENEDOR_OPTS}
              onChange={(v) => updateIngreso(carril.id,"expo_contenedor", v)}
              placeholder="— Sin especificar —"
              allowClear
              pending={!!pendingKeys[`${carril.id}:expo_contenedor`]}
              theme={theme}
              title={`${carril.label} · Contenedor expo`}
            />
          </div>

          <div style={{ ...laneBlockStyle(st.retornos ? "#f97316" : "#22c55e"), gridColumn:"1 / -1" }}>
            <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", gap:"12px", flexWrap:"wrap", marginBottom:"10px" }}>
              {laneHeaderNode("return-route", "Modalidad de retornos", st.retornos ? "Con retornos" : "Sin retornos", st.retornos ? "#f97316" : "#22c55e", 26)}
              <div style={{ minWidth:"260px", flex:"1 1 260px" }}>
                <SegmentedToggle
                  value={!!st.retornos}
                  onChange={(v) => updateIngreso(carril.id,"retornos",v)}
                  leftLabel="SIN RETORNOS" rightLabel="CON RETORNOS"
                  leftColor="#22c55e" rightColor="#f97316"
                  pending={!!pendingKeys[`${carril.id}:retornos`]}
                  theme={theme}
                />
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  };

  const renderSegundoSalidaCard = () => {
    const st = carriles.c4;
    const laneOpt = getCarrilEstadoOpt(st);
    const expoOpt = SEGUNDO_TRAFICO_OPTS.find(o => o.id === (st.expo || "libre"));
    const expoContOpt = SEGUNDO_CONTENEDOR_OPTS.find(o => o.id === st.expo_contenedor);
    const impoOpt = SEGUNDO_TRAFICO_OPTS.find(o => o.id === (st.impo || "libre"));
    return (
      <div style={laneCardShell(laneOpt.id !== "libre" ? laneOpt.color : "#f97316")}>
        <div style={{ display:"flex", alignItems:"flex-start", justifyContent:"space-between", gap:"12px", flexWrap:"wrap", marginBottom:"12px" }}>
          <div>
            <div style={{ display:"flex", alignItems:"center", gap:"8px", flexWrap:"wrap" }}>
              <div style={{ background:"#f9731618", border:"1px solid #f9731644", borderRadius:"999px", padding:"4px 10px", color:"#f97316", fontFamily:getFont(theme, "secondary"), fontSize:"12px", fontWeight:"800", letterSpacing:".05em", textTransform:"uppercase" }}>Carril 4</div>
              <Badge color="#f97316" small>SALIDA</Badge>
            </div>
            <div style={{ color:"rgba(255,255,255,0.42)", fontSize:"10px", fontFamily:getFont(theme, "secondary"), marginTop:"5px" }}>{timeAgo(st.lastUpdate)} · {st.updatedBy}</div>
          </div>
          <Badge color={laneOpt.color} small>{laneOpt.label.toUpperCase()}</Badge>
        </div>

        <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fit,minmax(230px,1fr))", gap:"12px" }}>
          <div style={laneBlockStyle("#f97316") }>
            {laneHeaderNode("terminal-crane", "Salida general", "Flujo de salida del puerto", "#f97316", 30)}
            <div style={{ ...laneMiniLabelStyle, marginBottom:"4px" }}>Destino del carril</div>
            <div style={{ ...laneHeroTitleStyle, color:"#f97316", fontSize:"16px", marginBottom:"2px" }}>Salida General del Puerto</div>
            <div style={{ color:"rgba(255,255,255,0.46)", fontSize:"11px" }}>Todos los vehículos egresan hacia ciudad.</div>
          </div>

          <div style={laneBlockStyle(laneOpt.color)}>
            {laneHeaderNode("lane-status-monitor", "Estado del carril", laneOpt.label, laneOpt.color, 30)}
            <div style={{ ...laneMiniLabelStyle, marginBottom:"8px" }}>Estado vigente</div>
            <WheelPickerSelect
              value={getCarrilEstadoId(st)}
              options={CARRIL_ESTADO_OPTS}
              onChange={(v) => updateSalidaEstado(v || "libre")}
              pending={!!pendingKeys["c4:estado_carril"]}
              theme={theme}
              title="Carril 4 · Estado del carril"
            />
          </div>

          <div style={laneBlockStyle("#f97316") }>
            {laneHeaderNode("truck-export", "Exportación", expoOpt?.label || "Libre", "#f97316", 28)}
            <div style={{ ...laneMiniLabelStyle, marginBottom:"8px" }}>Tráfico de exportación</div>
            <WheelPickerSelect
              value={st.expo || "libre"}
              options={SEGUNDO_TRAFICO_OPTS}
              onChange={(v) => updateSalida("expo",v)}
              pending={!!pendingKeys["c4:expo"]}
              theme={theme}
            />
          </div>

          <div style={laneBlockStyle("#38bdf8") }>
            {laneHeaderNode("truck-import", "Importación", impoOpt?.label || "Libre", "#38bdf8", 28)}
            <div style={{ ...laneMiniLabelStyle, marginBottom:"8px" }}>Tráfico de importación</div>
            <WheelPickerSelect
              value={st.impo || "libre"}
              options={SEGUNDO_TRAFICO_OPTS}
              onChange={(v) => updateSalida("impo",v)}
              pending={!!pendingKeys["c4:impo"]}
              theme={theme}
            />
          </div>

          <div style={laneBlockStyle("#f97316") }>
            {laneHeaderNode("container-expo-open", "Contenedor Expo", expoContOpt?.label || "Sin especificar", "#f97316", 28)}
            <div style={{ ...laneMiniLabelStyle, marginBottom:"8px" }}>Condición del contenedor</div>
            <WheelPickerSelect
              value={st.expo_contenedor}
              options={SEGUNDO_CONTENEDOR_OPTS}
              onChange={(v) => updateSalida("expo_contenedor", v)}
              placeholder="— Sin especificar —"
              allowClear
              pending={!!pendingKeys["c4:expo_contenedor"]}
              theme={theme}
            />
          </div>

          <div style={{ ...laneBlockStyle(st.retornos ? "#f97316" : "#22c55e"), gridColumn:"1 / -1" }}>
            <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", gap:"12px", flexWrap:"wrap", marginBottom:"10px" }}>
              {laneHeaderNode("return-route", "Modalidad de retornos", st.retornos ? "Con retornos" : "Sin retornos", st.retornos ? "#f97316" : "#22c55e", 26)}
              <div style={{ minWidth:"260px", flex:"1 1 260px" }}>
                <SegmentedToggle
                  value={!!st.retornos}
                  onChange={(v) => updateSalida("retornos",v)}
                  leftLabel="SIN RETORNOS" rightLabel="CON RETORNOS"
                  leftColor="#22c55e" rightColor="#f97316"
                  pending={!!pendingKeys["c4:retornos"]}
                  theme={theme}
                />
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  };

  const renderConfinadaCard = (carril) => {
    const st = confinada[carril.id];
    const laneOpt = getCarrilEstadoOpt(st);
    const isSinUso = laneOpt.id === "sin_uso" || st.terminal === "sin_uso";
    const termObj = TODAS_TERMINALES.find(t => t.id === st.terminal);
    const termColor = isSinUso ? "#71717a" : st.terminal === "general" ? "#fbbf24" : "#a78bfa";
    const accent = isSinUso ? "#71717a" : st.transferencia ? "#fbbf24" : laneOpt.id !== "libre" ? laneOpt.color : getTerminalBrandColor(st.terminal || "general");
    const expoOpt = SEGUNDO_TRAFICO_OPTS.find(o => o.id === (st.expo || "libre"));
    const expoContOpt = SEGUNDO_CONTENEDOR_OPTS.find(o => o.id === st.expo_contenedor);
    const impoOpt = SEGUNDO_TRAFICO_OPTS.find(o => o.id === (st.impo || "libre"));
    const isChanged = getCarrilEstadoId(st) !== "libre" || st.retornos || st.transferencia || st.terminal !== carril.defaultTerminal || st.terminal === "general" || (st.expo && st.expo !== "libre") || (st.impo && st.impo !== "libre") || !!st.expo_contenedor;
    return (
      <div key={carril.id} style={laneCardShell(accent)}>
        <div style={{ display:"flex", alignItems:"flex-start", justifyContent:"space-between", gap:"12px", flexWrap:"wrap", marginBottom:"12px" }}>
          <div>
            <div style={{ display:"flex", alignItems:"center", gap:"8px", flexWrap:"wrap" }}>
              <div style={{ background:"#a78bfa18", border:"1px solid #a78bfa44", borderRadius:"999px", padding:"4px 10px", color:"#c4b5fd", fontFamily:getFont(theme, "secondary"), fontSize:"12px", fontWeight:"800", letterSpacing:".05em", textTransform:"uppercase" }}>{carril.label}</div>
              {isSinUso ? <Badge color="#6b7280" small>SIN USO</Badge> : <Badge color="#22c55e" small>INGRESO</Badge>}
              {st.transferencia && !isSinUso && <Badge color="#fbbf24" small>2° ACCESO</Badge>}
            </div>
            <div style={{ color:"rgba(255,255,255,0.42)", fontSize:"10px", fontFamily:getFont(theme, "secondary"), marginTop:"5px" }}>{timeAgo(st.lastUpdate)} · {st.updatedBy}</div>
          </div>
          <div style={{ display:"flex", alignItems:"center", gap:"6px", flexWrap:"wrap", justifyContent:"flex-end" }}>
            <Badge color={laneOpt.color} small>{laneOpt.label.toUpperCase()}</Badge>
            {st.retornos && <Badge color="#f97316" small>CON RETORNOS</Badge>}
            {expoOpt && expoOpt.id !== "libre" && <Badge color={expoOpt.color} small>EXPO {expoOpt.label}</Badge>}
            {expoContOpt && <Badge color={expoContOpt.color} small>{expoContOpt.label}</Badge>}
            {impoOpt && impoOpt.id !== "libre" && <Badge color={impoOpt.color} small>IMPO {impoOpt.label}</Badge>}
            {isChanged && <button onClick={() => resetOneConfinada(carril.id)} style={{ padding:"5px 10px", background:"rgba(167,139,250,0.12)", border:"1px solid rgba(167,139,250,0.34)", borderRadius:"999px", color:"#c4b5fd", fontFamily:getFont(theme, "secondary"), fontSize:"10px", fontWeight:"800", cursor:"pointer" }}>NORMAL</button>}
          </div>
        </div>

        <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fit,minmax(230px,1fr))", gap:"12px" }}>
          <div style={laneBlockStyle(termColor)}>
            {laneHeaderNode("terminal-crane", "Terminal", isSinUso ? "Sin uso / sin operación" : st.terminal === "general" ? "General" : (termObj?.name || "Terminal no asignada"), termColor, 30)}
            <div style={{ ...laneMiniLabelStyle, marginBottom:"4px" }}>Asignación actual</div>
            <div style={{ ...laneHeroTitleStyle, color:termColor, fontSize:"16px", marginBottom:"2px" }}>{isSinUso ? "SIN USO" : st.terminal === "general" ? "GENERAL" : (termObj?.name || getTermName(st.terminal))}</div>
            <div style={{ color:"rgba(255,255,255,0.46)", fontSize:"11px", marginBottom:"10px" }}>{isSinUso ? "Carril no disponible" : st.terminal === "general" ? "Todas las terminales" : `Zona ${termObj?.zona || getTermZona(st.terminal)}`}</div>
            <WheelPickerSelect
              value={st.terminal || carril.defaultTerminal}
              options={terminalOptionsConfinada}
              onChange={(v) => updateConfinada(carril.id,"terminal",v)}
              pending={!!pendingKeys[`${carril.id}:terminal`]}
              theme={theme}
              title={`Confinada ${carril.label} · Terminal / uso`}
            />
          </div>

          <div style={laneBlockStyle(laneOpt.color)}>
            {laneHeaderNode("lane-status-monitor", "Estado del carril", laneOpt.label, laneOpt.color, 30)}
            <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", gap:"10px", marginBottom:"10px" }}>
              <div>
                <div style={{ ...laneMiniLabelStyle, marginBottom:"3px" }}>Estado vigente</div>
                <div style={{ ...laneHeroTitleStyle, color:laneOpt.color }}>{laneOpt.label}</div>
              </div>
              <Badge color={laneOpt.color} small>{laneOpt.id === "sin_especificar" ? "N/A" : laneOpt.label.toUpperCase()}</Badge>
            </div>
            <WheelPickerSelect
              value={getCarrilEstadoId(st)}
              options={CARRIL_ESTADO_OPTS}
              onChange={(v) => updateConfinadaEstado(carril.id, v || "libre")}
              pending={!!pendingKeys[`${carril.id}:estado_carril`]}
              theme={theme}
              title={`Confinada ${carril.label} · Estado del carril`}
            />
          </div>

          <div style={laneBlockStyle("#f97316") }>
            {laneHeaderNode("truck-export", "Exportación", expoOpt?.label || "Libre", "#f97316", 28)}
            <div style={{ ...laneMiniLabelStyle, marginBottom:"8px" }}>Tráfico de exportación</div>
            <WheelPickerSelect
              value={st.expo || "libre"}
              options={SEGUNDO_TRAFICO_OPTS}
              onChange={(v) => updateConfinada(carril.id,"expo",v)}
              pending={!!pendingKeys[`${carril.id}:expo`]}
              theme={theme}
              title={`Confinada ${carril.label} · Exportación`}
            />
          </div>

          <div style={laneBlockStyle("#38bdf8") }>
            {laneHeaderNode("truck-import", "Importación", impoOpt?.label || "Libre", "#38bdf8", 28)}
            <div style={{ ...laneMiniLabelStyle, marginBottom:"8px" }}>Tráfico de importación</div>
            <WheelPickerSelect
              value={st.impo || "libre"}
              options={SEGUNDO_TRAFICO_OPTS}
              onChange={(v) => updateConfinada(carril.id,"impo",v)}
              pending={!!pendingKeys[`${carril.id}:impo`]}
              theme={theme}
              title={`Confinada ${carril.label} · Importación`}
            />
          </div>

          <div style={laneBlockStyle("#f97316") }>
            {laneHeaderNode("container-expo-open", "Contenedor Expo", expoContOpt?.label || "Sin especificar", "#f97316", 28)}
            <div style={{ ...laneMiniLabelStyle, marginBottom:"8px" }}>Condición del contenedor</div>
            <WheelPickerSelect
              value={st.expo_contenedor}
              options={SEGUNDO_CONTENEDOR_OPTS}
              onChange={(v) => updateConfinada(carril.id,"expo_contenedor", v)}
              placeholder="— Sin especificar —"
              allowClear
              pending={!!pendingKeys[`${carril.id}:expo_contenedor`]}
              theme={theme}
              title={`Confinada ${carril.label} · Contenedor expo`}
            />
          </div>

          <div style={{ ...laneBlockStyle(st.retornos ? "#f97316" : "#22c55e"), gridColumn:"1 / -1" }}>
            <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", gap:"12px", flexWrap:"wrap", marginBottom:"10px" }}>
              {laneHeaderNode("return-route", "Modalidad de retornos", st.retornos ? "Con retornos" : "Sin retornos", st.retornos ? "#f97316" : "#22c55e", 26)}
              <div style={{ minWidth:"260px", flex:"1 1 260px" }}>
                <SegmentedToggle
                  value={!!st.retornos}
                  onChange={(v) => updateConfinada(carril.id,"retornos",v)}
                  leftLabel="SIN RETORNOS" rightLabel="CON RETORNOS"
                  leftColor="#22c55e" rightColor="#f97316"
                  pending={!!pendingKeys[`${carril.id}:retornos`]}
                  theme={theme}
                />
              </div>
            </div>
          </div>

          <div style={{ ...laneBlockStyle(st.transferencia ? "#fbbf24" : "#a78bfa"), gridColumn:"1 / -1" }}>
            <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", gap:"12px", flexWrap:"wrap", marginBottom:"10px" }}>
              {laneHeaderNode("turnover", "Segundo Acceso", st.transferencia ? "Transferencia activa" : "Operación normal", st.transferencia ? "#fbbf24" : "#a78bfa", 26)}
              <div style={{ minWidth:"260px", flex:"1 1 260px" }}>
                <SegmentedToggle
                  value={!!st.transferencia}
                  onChange={(v) => updateConfinada(carril.id,"transferencia",v)}
                  leftLabel="NORMAL" rightLabel="TRANSFERENCIA"
                  leftColor="#22c55e" rightColor="#fbbf24"
                  pending={!!pendingKeys[`${carril.id}:transferencia`]}
                  theme={theme}
                />
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  };

  return (
    <div style={{ padding:"16px", paddingBottom:"80px", minHeight:"100vh" }}>

      {/* ── Header principal ── */}
      <div style={{ background:"rgba(255,255,255,0.08)", backdropFilter:"blur(12px)", WebkitBackdropFilter:"blur(12px)", border:"1px solid rgba(255,255,255,0.15)", borderRadius:"12px", padding:"12px", marginBottom:"14px" }}>
        <div style={{ fontSize:"10px", color:"#38bdf8", fontFamily:getFont(theme, "secondary"), letterSpacing:"2px", marginBottom:"4px" }}>CONFINADOS — PUERTO MANZANILLO</div>
        <div style={{ color:"rgba(255,255,255,0.7)", fontSize:"12px" }}>2do Acceso y zona confinada · Ingreso con terminal asignada.</div>
      </div>

      {/* ── Sub-tab selector ── */}
      <div style={{ display:"flex", gap:"8px", marginBottom:"16px" }}>
        {[
          { id:"segundo",   label:"2DO ACCESO",   icon:"route-road",  color:"#34d399" },
          { id:"confinada", label:"CONFINADA",    icon:"lock", color:"#a78bfa" },
        ].map(tab => (
          <button
            key={tab.id}
            onClick={() => setSubTab(tab.id)}
            style={{
              flex:1, padding:"12px 8px",
              background: subTab===tab.id ? tab.color+"22" : "rgba(255,255,255,0.04)",
              border: `2px solid ${subTab===tab.id ? tab.color : "rgba(255,255,255,0.12)"}`,
              borderRadius:"10px",
              color: subTab===tab.id ? tab.color : "rgba(255,255,255,0.45)",
              fontFamily:getFont(theme, "secondary"), fontSize:"12px", fontWeight:"800",
              cursor:"pointer", letterSpacing:"1px",
              transition:"all 0.2s",
              display:"flex", alignItems:"center", justifyContent:"center", gap:"6px",
            }}
          >
            <AppIcon name={tab.icon} size={18} active={subTab===tab.id} />{tab.label}
          </button>
        ))}
      </div>

      {/* ════════════════════════════════════════════════════
          SUB-TAB: 2DO ACCESO
      ════════════════════════════════════════════════════ */}
      {subTab === "segundo" && <>
        {/* ── Diagrama visual de carriles · rediseño industrial 3D ── */}
        <div className="cm-2do-diagram-shell">
          <style>{`
            .cm-2do-diagram-shell{position:relative;margin-bottom:18px;border-radius:18px;border:1px solid rgba(148,163,184,.18);background:radial-gradient(circle at 50% 0%,rgba(56,189,248,.10),transparent 42%),linear-gradient(180deg,rgba(15,23,42,.82),rgba(2,8,23,.94));box-shadow:0 24px 56px rgba(0,0,0,.36),inset 0 1px 0 rgba(255,255,255,.08);overflow:hidden;padding:14px;}
            .cm-2do-diagram-shell::before{content:"";position:absolute;inset:0;background:linear-gradient(90deg,rgba(255,255,255,.035),transparent 42%),repeating-linear-gradient(0deg,rgba(255,255,255,.028) 0 1px,transparent 1px 8px);pointer-events:none;opacity:.7;}
            .cm-2do-header{position:relative;z-index:1;display:flex;align-items:flex-start;justify-content:space-between;gap:12px;flex-wrap:wrap;margin-bottom:14px;}
            .cm-2do-kicker{color:#67e8f9;font-family:'DM Sans',sans-serif;font-size:10px;font-weight:900;letter-spacing:.18em;text-transform:uppercase;}
            .cm-2do-title{margin-top:4px;color:#f8fafc;font-family:'DM Sans',sans-serif;font-size:clamp(18px,2.6vw,28px);font-weight:900;letter-spacing:-.04em;}
            .cm-2do-sub{margin-top:3px;color:rgba(226,232,240,.58);font-size:11px;font-family:'DM Sans',sans-serif;}
            .cm-2do-perspective{position:relative;z-index:1;perspective:1180px;padding:0 0 10px;overflow:visible;}
            .cm-2do-road{display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:18px;min-height:390px;transform:translateY(-26px) rotateX(31deg) skewX(-2deg);transform-style:preserve-3d;transform-origin:center bottom;padding:6px 10px 0;align-items:stretch;}
            .cm-2do-lane{position:relative;min-height:390px;border-radius:16px;border:3px solid rgba(148,163,184,.18);background:linear-gradient(180deg,#1a2233 0%,#0b1220 100%);box-shadow:0 20px 36px rgba(0,0,0,.40),inset 0 1px 0 rgba(255,255,255,.08),inset 0 -18px 32px rgba(0,0,0,.26);overflow:hidden;cursor:pointer;display:flex;flex-direction:column;align-items:center;justify-content:space-between;padding:28px 12px 22px;transition:transform .28s ease,border-color .22s ease,box-shadow .22s ease;}
            .cm-2do-lane::before{content:"";position:absolute;inset:0;background:linear-gradient(180deg,transparent,rgba(0,0,0,.42));pointer-events:none;}
            .cm-2do-lane::after{content:"";position:absolute;inset:0;opacity:.22;background-image:linear-gradient(90deg,transparent 44%,#facc15 44%,#facc15 56%,transparent 56%);background-size:100% 44px;pointer-events:none;}
            .cm-2do-lane:hover,.cm-2do-lane.is-selected{transform:translateZ(30px) scale(1.035);border-color:var(--lane-color);box-shadow:0 28px 48px rgba(0,0,0,.50),0 0 28px color-mix(in srgb,var(--lane-color) 45%,transparent),inset 0 0 0 2px color-mix(in srgb,var(--lane-color) 58%,transparent);z-index:4;}
            .cm-2do-lane-chip{position:relative;z-index:1;display:inline-flex;align-items:center;justify-content:center;min-width:78px;padding:7px 14px;border-radius:999px;background:rgba(255,255,255,.10);border:1px solid rgba(255,255,255,.10);color:#fff;font-family:'DM Sans',sans-serif;font-size:18px;font-weight:900;letter-spacing:-.02em;box-shadow:inset 0 1px 0 rgba(255,255,255,.10);}
            .cm-2do-arrow{position:relative;z-index:1;width:66px;height:66px;border-radius:999px;border:4px solid var(--lane-color);display:grid;place-items:center;box-shadow:0 0 24px color-mix(in srgb,var(--lane-color) 55%,transparent),inset 0 0 14px color-mix(in srgb,var(--lane-color) 18%,transparent);animation:cm2doPulse 1.55s ease-in-out infinite;}
            .cm-2do-arrow span{font-size:40px;line-height:1;color:var(--lane-color);font-weight:900;}
            @keyframes cm2doPulse{0%,100%{opacity:1;transform:scale(1)}50%{opacity:.68;transform:scale(.94)}}
            .cm-2do-dir{position:relative;z-index:1;color:#f8fafc;font-family:'DM Sans',sans-serif;font-size:12px;font-weight:900;letter-spacing:.16em;text-transform:uppercase;text-align:center;}
            .cm-2do-status{position:relative;z-index:1;display:flex;flex-direction:column;align-items:center;gap:8px;}
            .cm-2do-status-pill{padding:6px 13px;border-radius:7px;background:var(--lane-color);color:#fff;font-family:'DM Sans',sans-serif;font-size:11px;font-weight:900;letter-spacing:.12em;text-transform:uppercase;box-shadow:0 10px 22px color-mix(in srgb,var(--lane-color) 30%,transparent);}
            .cm-2do-trucks{display:flex;justify-content:center;align-items:center;gap:6px;min-height:28px;filter:drop-shadow(0 6px 10px rgba(0,0,0,.35));}.cm-2do-truck-icon{display:grid;place-items:center;width:24px;height:24px;opacity:.92;}
            
            .cm-2do-bottom-row{position:relative;z-index:2;display:grid;grid-template-columns:1fr auto;align-items:center;gap:14px;margin-top:-8px;padding:0 26px 2px 18px;}
            .cm-2do-left-controls{display:flex;align-items:center;gap:10px;min-width:0;position:relative;}
            .cm-2do-direction-row{position:relative;z-index:1;display:flex;align-items:center;gap:8px;min-width:0;}
            .cm-2do-direction-row span{font-family:'DM Sans',sans-serif;font-size:10px;font-weight:900;letter-spacing:.14em;text-transform:uppercase;line-height:1.1;} .cm-2do-direction-row.is-right{justify-self:end;padding-right:10px;}
            .cm-2do-legend-area{position:relative;z-index:2;display:flex;align-items:center;justify-content:center;}
            .cm-2do-legend-btn{width:38px;height:38px;border-radius:999px;border:1px solid rgba(148,163,184,.22);background:rgba(15,23,42,.76);backdrop-filter:blur(14px);color:#e2e8f0;display:grid;place-items:center;cursor:pointer;box-shadow:0 12px 26px rgba(0,0,0,.34),inset 0 1px 0 rgba(255,255,255,.08);transition:transform .16s ease,background .16s ease;}
            .cm-2do-legend-btn:hover{transform:translateY(-2px);background:rgba(30,41,59,.86);}
            .cm-2do-legend-panel{position:absolute;left:0;bottom:calc(100% + 10px);top:auto;transform:none;width:min(calc(100vw - 44px),760px);max-width:calc(100vw - 44px);padding:14px 16px;border-radius:18px;border:1px solid rgba(148,163,184,.18);background:rgba(15,23,42,.94);backdrop-filter:blur(18px);box-shadow:0 22px 44px rgba(0,0,0,.40);transform-origin:bottom left;display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:10px 16px;box-sizing:border-box;overflow:visible;z-index:30;}
            .cm-2do-legend-title{grid-column:1 / -1;color:#fff;font-size:12px;font-weight:900;letter-spacing:.12em;text-transform:uppercase;margin-bottom:2px;border-bottom:1px solid rgba(255,255,255,.08);padding-bottom:8px;}
            .cm-2do-legend-row{display:flex;align-items:flex-start;gap:10px;margin:0;min-width:0;overflow:hidden;}
            .cm-2do-legend-color{width:13px;height:13px;border-radius:4px;box-shadow:0 0 12px currentColor;}
            .cm-2do-legend-row strong{display:block;color:#f8fafc;font-size:11px;text-transform:uppercase;letter-spacing:.08em;line-height:1.2;word-break:break-word;}
            .cm-2do-legend-row span{display:block;color:rgba(226,232,240,.48);font-size:10px;margin-top:2px;line-height:1.25;word-break:break-word;}
            @media (max-width:760px){
              .cm-2do-diagram-shell{padding:12px;border-radius:16px;margin-left:-2px;margin-right:-2px;}
              .cm-2do-header{margin-bottom:8px;}
              .cm-2do-perspective{perspective:none;overflow-x:auto;overflow-y:hidden;padding:2px 0 8px;-webkit-overflow-scrolling:touch;}
              .cm-2do-road{width:max-content;min-width:100%;grid-template-columns:repeat(4,144px);gap:10px;min-height:286px;transform:none;padding:2px 4px 6px;}
              .cm-2do-lane{min-height:282px;border-width:2px;border-radius:14px;padding:18px 9px 16px;}
              .cm-2do-lane:hover,.cm-2do-lane.is-selected{transform:translateY(-2px) scale(1.01);}
              .cm-2do-lane-chip{min-width:62px;padding:6px 10px;font-size:14px;}
              .cm-2do-arrow{width:50px;height:50px;border-width:3px;}
              .cm-2do-arrow span{font-size:31px;}
              .cm-2do-dir{font-size:10px;letter-spacing:.10em;}
              .cm-2do-status-pill{font-size:9px;padding:5px 9px;letter-spacing:.08em;}
              .cm-2do-trucks{min-height:22px;}.cm-2do-truck-icon{width:20px;height:20px;}
              .cm-2do-terminal strong{font-size:9px;}
              .cm-2do-terminal span{font-size:8px;}
              .cm-2do-bottom-row{grid-template-columns:1fr auto;align-items:center;gap:10px;margin-top:0;padding:2px 6px 0 4px;}
              .cm-2do-left-controls{gap:8px;}
              .cm-2do-direction-row{gap:6px;}
              .cm-2do-direction-row span{font-size:8px;letter-spacing:.08em;}
              .cm-2do-legend-btn{width:36px;height:36px;}
              .cm-2do-legend-panel{left:0;top:auto;bottom:calc(100% + 8px);transform:none;margin-left:0;width:min(calc(100vw - 24px),340px);max-width:calc(100vw - 24px);grid-template-columns:1fr;gap:9px;padding:12px 13px;box-sizing:border-box;}
            }
          `}</style>
          <div className="cm-2do-header">
            <div>
              <div className="cm-2do-kicker">DIAGRAMA · VISTA DE CARRILES</div>
              <div className="cm-2do-title">Puente 2DO Acceso</div>
              <div className="cm-2do-sub">Vista 3D operativa basada en el diseño industrial propuesto, manteniendo la lógica actual de carriles.</div>
            </div>
            <div style={{ display:"flex", alignItems:"center", gap:"8px", padding:"8px 10px", borderRadius:"999px", border:"1px solid rgba(52,211,153,.30)", background:"rgba(52,211,153,.10)", color:"#34d399", fontSize:"10px", fontWeight:900, letterSpacing:".12em" }}>
              <AppIcon name="status-live" size={14} active /> EN VIVO
            </div>
          </div>

          <div className="cm-2do-perspective">
            <div className="cm-2do-road">
              {(() => {
                const statusBrief = {
                  libre: "Flujo óptimo",
                  lento: "Avance lento",
                  moderado: "Densidad media",
                  saturado: "Alta ocupación",
                  bloqueo: "Bloqueo operativo",
                  cerrado: "Cierre temporal",
                  sin_uso: "Sin operación",
                };
                const truckCount = (id) => ({ libre:1, lento:2, moderado:2, saturado:3, bloqueo:3, cerrado:0, sin_uso:0 }[id] ?? 1);
                const c4Opt = getCarrilEstadoOpt(carriles?.c4);
                const lanes = [
                  {
                    id: "c4",
                    label: "C4",
                    direction: "SALIDA",
                    arrow: "↓",
                    color: c4Opt.color,
                    status: c4Opt.label,
                    brief: statusBrief[c4Opt.id] || c4Opt.label,
                    terminal: "Salida general",
                    terminalMeta: "Hacia ciudad",
                    terminalColor: "#f97316",
                    trucks: truckCount(c4Opt.id),
                    retornos: carriles?.c4?.retornos,
                  },
                  ...[...SEGUNDO_CARRILES_INGRESO].reverse().map((c) => {
                    const st = carriles?.[c.id] || {};
                    const opt = getCarrilEstadoOpt(st);
                    const zona = getTermZona(st?.terminal);
                    const terminalColor = zona === "Sin uso" ? "#6b7280" : zona === "Todas" ? "#fbbf24" : zona === "Norte" ? "#38bdf8" : "#a78bfa";
                    return {
                      id: c.id,
                      label: c.label.replace("Carril ", "C"),
                      direction: getTermName(st?.terminal),
                      arrow: "↑",
                      color: opt.id === "libre" ? "#14b8a6" : opt.color,
                      status: opt.label,
                      brief: statusBrief[opt.id] || opt.label,
                      terminal: getTermName(st?.terminal),
                      terminalMeta: zona === "Todas" ? "Todas las terminales" : zona ? `Zona ${zona}` : "Ingreso puerto",
                      terminalColor,
                      trucks: truckCount(opt.id),
                      retornos: st?.retornos,
                    };
                  })
                ];
                return lanes.map((lane) => (
                  <button
                    key={lane.id}
                    type="button"
                    className={`cm-2do-lane ${selectedSecondLane === lane.id ? "is-selected" : ""}`}
                    onClick={() => setSelectedSecondLane(lane.id)}
                    style={{ "--lane-color": lane.color, "--terminal-color": lane.terminalColor }}
                    title={`${lane.label} · ${lane.status}`}
                  >
                    <div className="cm-2do-lane-chip">{lane.label}</div>
                    <div className="cm-2do-arrow"><span>{lane.arrow}</span></div>
                    <div className="cm-2do-dir">{lane.direction}</div>
                    <div className="cm-2do-status">
                      <div className="cm-2do-status-pill">{lane.status}</div>
                      <div className="cm-2do-trucks" aria-hidden="true">
                        {lane.trucks > 0 ? Array.from({ length: lane.trucks }).map((_, i) => (
                          <span key={i} className="cm-2do-truck-icon" style={{ color: lane.color }}>
                            <AppIcon name="freight-truck" size={22} active />
                          </span>
                        )) : <span style={{ color:"rgba(226,232,240,.36)", fontSize:"18px", fontWeight:900 }}>—</span>}
                      </div>
                    </div>
                  </button>
                ));
              })()}
            </div>
          </div>

          <div className="cm-2do-bottom-row">
            <div className="cm-2do-left-controls">
              <div className="cm-2do-direction-row">
                <span style={{ color:"#f97316" }}>↓ Hacia ciudad</span>
                <div
                  className="cm-2do-legend-area"
                  onMouseEnter={() => setSegundoLegendOpen(true)}
                  onMouseLeave={() => setSegundoLegendOpen(false)}
                >
                  <button
                    className="cm-2do-legend-btn"
                    type="button"
                    onClick={() => setSegundoLegendOpen(v => !v)}
                    onFocus={() => setSegundoLegendOpen(true)}
                    onBlur={() => setSegundoLegendOpen(false)}
                    onTouchStart={() => setSegundoLegendOpen(true)}
                    title="Mostrar índice del diagrama"
                  >
                    <AppIcon name={segundoLegendOpen ? "xmark" : "info"} size={20} active />
                  </button>
                  {segundoLegendOpen && (
                    <div className="cm-2do-legend-panel">
                      <div className="cm-2do-legend-title">Índice del diagrama</div>
                      {CARRIL_ESTADO_OPTS.map(({ id, color, label }) => (
                        <div className="cm-2do-legend-row" key={id}>
                          <div className="cm-2do-legend-color" style={{ background:color, color }} />
                          <div>
                            <strong>{label}</strong>
                            <span>{id === "libre" ? "Operación normal" : id === "lento" ? "Alta densidad con avance" : id === "moderado" ? "Tránsito medio" : id === "saturado" ? "Demora fuerte" : id === "bloqueo" ? "Obstrucción o bloqueo" : id === "cerrado" ? "No disponible temporalmente" : "Carril sin operación"}</span>
                          </div>
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              </div>
            </div>
            <div className="cm-2do-direction-row is-right">
              <span style={{ color:"#14b8a6" }}>↑ Hacia el puerto</span>
            </div>
          </div>
        </div>

        <SectionLabel text="CARRILES DE INGRESO (C1–C3)" rightBtn={<NormalBtn onClick={resetAll} label="TODO NORMAL" />} />
        {SEGUNDO_CARRILES_INGRESO.map(renderSegundoIngresoCard)}

        <SectionLabel text="CARRIL DE SALIDA (C4)" />
        {renderSegundoSalidaCard()}

        {/* ── Segundo Acceso Por Fases ── */}
        <div style={{ marginTop:"8px" }}>
          <div style={{ display:"flex", alignItems:"center", gap:"8px", marginBottom:"12px" }}>
            <div style={{ flex:1, height:"1px", background:"rgba(52,211,153,0.2)" }} />
            <div style={{ display:"flex", alignItems:"center", gap:"6px", padding:"5px 12px", background:"rgba(52,211,153,0.08)", border:"1px solid rgba(52,211,153,0.25)", borderRadius:"20px" }}>
              <span style={{ fontSize:"13px" }}>🗺️</span>
              <span style={{ fontFamily:getFont(theme,"secondary"), fontSize:"11px", color:"#34d399", fontWeight:"800", letterSpacing:"1px" }}>SEGUNDO ACCESO POR FASES</span>
            </div>
            <div style={{ flex:1, height:"1px", background:"rgba(52,211,153,0.2)" }} />
          </div>
          <TrafficMapSegundo theme={theme} myId={myId} />
        </div>
      </>}

      {/* ════════════════════════════════════════════════════
          SUB-TAB: CONFINADA
      ════════════════════════════════════════════════════ */}
      {subTab === "confinada" && <>
        {/* ── DIAGRAMA CONFINADA — vista industrial 3D ── */}
        {(() => {
          const statusBrief = {
            libre: "Flujo óptimo, mínima espera",
            lento: "Tráfico lento con avance",
            moderado: "Densidad operativa media",
            saturado: "Alta capacidad, demoras fuertes",
            bloqueo: "Carril bloqueado u obstruido",
            cerrado: "Carril cerrado temporalmente",
            sin_uso: "Carril sin operación"
          };
          const truckCount = (id) => ({ libre:1, lento:2, moderado:2, saturado:3, bloqueo:3, cerrado:0, sin_uso:0 }[id] ?? 1);
          const getTermShort = (id) => {
            const st = confinada[id];
            if (!st) return "—";
            if (getCarrilEstadoId(st) === "sin_uso" || st.terminal === "sin_uso") return "SIN USO";
            if (st.terminal === "general") return "GENERAL";
            const found = TODAS_TERMINALES.find(t => t.id === st.terminal);
            return found ? found.name : String(st.terminal || "GENERAL").toUpperCase();
          };
          const confinadaLanes = CONFINADA_CARRILES.map((c, idx) => {
            const st = confinada[c.id] || {};
            const opt = getCarrilEstadoOpt(st);
            const accent = opt.id === "libre" && st.transferencia ? "#ffcc00" : opt.id === "libre" ? "#22c55e" : opt.color;
            return {
              id: c.id,
              label: c.label.replace("Carril ", "C"),
              terminal: getTermShort(c.id),
              statusId: opt.id,
              status: opt.label,
              color: accent,
              trucks: truckCount(opt.id),
              selected: selectedConfinadaLane === c.id,
              glow: idx === 0 ? "green" : idx === 1 ? "magenta" : "red"
            };
          });
          return (
            <div className="cm-conf-shell">
              <style>{`
                .cm-conf-shell{position:relative;margin-bottom:18px;border-radius:20px;border:1px solid rgba(255,255,255,.10);background:radial-gradient(circle at 15% 12%,rgba(56,189,248,.12),transparent 34%),linear-gradient(180deg,#050b14 0%,#081120 100%);box-shadow:0 24px 58px rgba(0,0,0,.48),inset 0 1px 0 rgba(255,255,255,.06);overflow:hidden;min-height:520px;display:grid;grid-template-columns:74px minmax(0,1fr) 74px;}
                .cm-conf-shell:before{content:"";position:absolute;inset:0;background-image:linear-gradient(rgba(255,255,255,.035) 1px,transparent 1px),linear-gradient(90deg,rgba(255,255,255,.035) 1px,transparent 1px);background-size:28px 28px;mask-image:radial-gradient(circle at center,black 30%,transparent 82%);pointer-events:none;}
                .cm-conf-side{position:relative;z-index:3;background:#0a101d;border-right:1px solid rgba(255,255,255,.10);display:flex;align-items:center;justify-content:center;box-shadow:5px 0 20px rgba(0,0,0,.30);}
                .cm-conf-side.right{border-right:none;border-left:1px solid rgba(255,255,255,.10);box-shadow:-5px 0 20px rgba(0,0,0,.30);}
                .cm-conf-vertical{display:flex;flex-direction:column;align-items:center;gap:14px;writing-mode:vertical-rl;transform:rotate(180deg);}
                .cm-conf-side.right .cm-conf-vertical{transform:none;}
                .cm-conf-v-title{color:#fff;font-family:'DM Sans',sans-serif;font-size:20px;font-weight:950;letter-spacing:.18em;text-transform:uppercase;white-space:nowrap;text-shadow:0 0 20px rgba(255,255,255,.18);}
                .cm-conf-v-line{width:4px;height:54px;border-radius:999px;background:rgba(34,211,238,.60);box-shadow:0 0 20px rgba(34,211,238,.34);}
                .cm-conf-side.right .cm-conf-v-line{background:rgba(217,70,239,.60);box-shadow:0 0 20px rgba(217,70,239,.34);}
                .cm-conf-v-sub{color:#22d3ee;font-family:'DM Sans',sans-serif;font-size:11px;font-weight:900;letter-spacing:.22em;text-transform:uppercase;white-space:nowrap;}
                .cm-conf-side.right .cm-conf-v-sub{color:#f0abfc;}
                .cm-conf-main{position:relative;z-index:2;min-width:0;padding:28px 30px 26px;display:flex;flex-direction:column;gap:22px;overflow:hidden;}
                .cm-conf-head{display:flex;align-items:flex-start;justify-content:space-between;gap:14px;}
                .cm-conf-kicker{font-family:'DM Sans',sans-serif;font-size:11px;color:#22d3ee;font-weight:800;letter-spacing:.14em;text-transform:uppercase;margin-bottom:4px;}
                .cm-conf-title{font-family:'DM Sans',sans-serif;color:#fff;font-size:clamp(26px,3.2vw,40px);font-weight:950;letter-spacing:-.045em;text-transform:uppercase;line-height:1.02;}
                .cm-conf-sub{font-family:'DM Sans',sans-serif;color:rgba(226,232,240,.58);font-size:12px;margin-top:6px;letter-spacing:.05em;}
                .cm-conf-live{display:flex;align-items:center;gap:8px;padding:9px 12px;border-radius:999px;border:1px solid rgba(34,197,94,.30);background:rgba(34,197,94,.08);color:#34d399;font-family:'DM Sans',sans-serif;font-size:10px;font-weight:900;letter-spacing:.12em;text-transform:uppercase;white-space:nowrap;}
                .cm-conf-stage{flex:1;display:flex;align-items:center;justify-content:center;perspective:980px;min-height:310px;overflow:visible;}
                .cm-conf-road{width:min(100%,980px);display:flex;flex-direction:column;gap:24px;transform:rotateX(9deg) rotateY(-7deg);transform-style:preserve-3d;}
                .cm-conf-lane{--lane-color:#22c55e;position:relative;min-height:98px;border-radius:16px;border:2px solid var(--lane-color);background:linear-gradient(180deg,rgba(13,18,27,.98),rgba(4,7,12,.98));box-shadow:0 0 22px color-mix(in srgb,var(--lane-color) 26%,transparent),inset 0 1px 0 rgba(255,255,255,.10);display:grid;grid-template-columns:170px minmax(0,1fr) 210px;align-items:center;gap:16px;padding:18px 28px;cursor:pointer;transition:transform .24s ease,box-shadow .24s ease,border-color .24s ease;overflow:hidden;text-align:left;}
                .cm-conf-lane:before{content:"";position:absolute;left:0;right:0;top:50%;height:9px;transform:translateY(-50%);background:#ffcc00;opacity:.72;z-index:0;box-shadow:0 0 18px rgba(255,204,0,.22);}
                .cm-conf-lane:after{content:"";position:absolute;inset:0;background:linear-gradient(90deg,transparent,rgba(255,255,255,.08),transparent);opacity:0;transition:opacity .28s ease;pointer-events:none;}
                .cm-conf-lane:hover{transform:translateZ(22px) translateY(-8px) scale(1.015);box-shadow:0 18px 42px rgba(0,0,0,.46),0 0 28px color-mix(in srgb,var(--lane-color) 38%,transparent),inset 0 1px 0 rgba(255,255,255,.12);}
                .cm-conf-lane:hover:after{opacity:1;}
                .cm-conf-lane.is-selected{transform:translateZ(38px) scale(1.045);box-shadow:0 20px 48px rgba(0,0,0,.55),0 0 34px color-mix(in srgb,var(--lane-color) 45%,transparent);outline:2px solid rgba(255,255,255,.88);outline-offset:2px;}
                .cm-conf-lane-chip{position:relative;z-index:1;width:max-content;min-width:78px;text-align:center;padding:5px 14px;border-radius:999px;background:rgba(0,0,0,.62);border:1px solid rgba(255,255,255,.13);color:var(--lane-color);font-family:'DM Sans',sans-serif;font-size:42px;font-weight:950;letter-spacing:-.08em;text-shadow:0 0 16px color-mix(in srgb,var(--lane-color) 65%,transparent);}
                .cm-conf-center{position:relative;z-index:1;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:8px;min-width:0;}
                .cm-conf-terminal{max-width:100%;padding:5px 22px;border-radius:999px;background:rgba(0,0,0,.82);border:1px solid rgba(255,255,255,.18);box-shadow:0 12px 26px rgba(0,0,0,.36);color:#fff;font-family:'DM Sans',sans-serif;font-weight:950;font-size:clamp(18px,2.2vw,30px);letter-spacing:.12em;text-transform:uppercase;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;}
                .cm-conf-trucks{display:flex;align-items:center;justify-content:center;gap:12px;min-height:38px;opacity:.78;transition:opacity .2s;}
                .cm-conf-lane:hover .cm-conf-trucks{opacity:1;}
                .cm-conf-truck{display:grid;place-items:center;width:38px;height:38px;color:var(--lane-color);filter:drop-shadow(0 0 10px color-mix(in srgb,var(--lane-color) 58%,transparent));}
                .cm-conf-status-wrap{position:relative;z-index:1;display:flex;justify-content:flex-end;}
                .cm-conf-status{border:2px solid var(--lane-color);background:rgba(0,0,0,.92);padding:8px 18px;border-radius:999px;box-shadow:0 0 22px color-mix(in srgb,var(--lane-color) 42%,transparent);color:var(--lane-color);font-family:'DM Sans',sans-serif;font-size:15px;font-weight:950;letter-spacing:.12em;text-transform:uppercase;white-space:nowrap;}
                .cm-conf-footer{display:flex;align-items:center;justify-content:space-between;gap:12px;}
                .cm-conf-route{font-family:'DM Sans',sans-serif;color:rgba(226,232,240,.58);font-size:11px;font-weight:800;letter-spacing:.14em;text-transform:uppercase;}
                .cm-conf-route strong{color:#22d3ee;}
                .cm-conf-route.right strong{color:#f0abfc;}
                .cm-conf-legend-wrap{position:relative;z-index:10;}
                .cm-conf-legend-btn{width:48px;height:48px;border-radius:999px;border:1px solid rgba(255,255,255,.18);background:rgba(17,21,32,.82);backdrop-filter:blur(16px);display:grid;place-items:center;color:#22d3ee;cursor:pointer;box-shadow:0 14px 28px rgba(0,0,0,.42),inset 0 1px 0 rgba(255,255,255,.08);transition:transform .18s,background .18s;}
                .cm-conf-legend-btn:hover{transform:translateY(-2px);background:rgba(255,255,255,.08);}
                .cm-conf-legend-panel{position:absolute;right:0;bottom:calc(100% + 12px);width:300px;border-radius:16px;border:1px solid rgba(255,255,255,.12);background:rgba(11,16,26,.96);backdrop-filter:blur(22px);box-shadow:0 22px 55px rgba(0,0,0,.70);padding:16px;transform-origin:bottom right;}
                .cm-conf-legend-title{font-family:'DM Sans',sans-serif;color:#fff;font-size:12px;font-weight:950;letter-spacing:.12em;text-transform:uppercase;padding-bottom:10px;border-bottom:1px solid rgba(255,255,255,.10);margin-bottom:12px;}
                .cm-conf-legend-list{display:grid;gap:12px;}
                .cm-conf-legend-row{display:flex;align-items:flex-start;gap:11px;min-width:0;}
                .cm-conf-legend-dot{width:12px;height:12px;border-radius:999px;flex:0 0 auto;margin-top:3px;box-shadow:0 0 12px currentColor;}
                .cm-conf-legend-row strong{display:block;color:#f8fafc;font-family:'DM Sans',sans-serif;font-size:11px;font-weight:950;text-transform:uppercase;letter-spacing:.09em;line-height:1.2;}
                .cm-conf-legend-row span{display:block;color:rgba(226,232,240,.46);font-family:'DM Sans',sans-serif;font-size:10px;line-height:1.28;margin-top:2px;}
                .cm-conf-mobile-rail{display:none;}
                @media (max-width:760px){
                  .cm-conf-shell{grid-template-columns:1fr;min-height:auto;border-radius:18px;margin-left:-2px;margin-right:-2px;}
                  .cm-conf-side{display:none;}
                  .cm-conf-mobile-rail{display:grid;grid-template-columns:1fr 1fr;gap:8px;position:relative;z-index:3;padding:12px 12px 0;}
                  .cm-conf-mobile-rail span{display:flex;align-items:center;justify-content:center;min-height:36px;border-radius:999px;border:1px solid rgba(255,255,255,.10);background:rgba(10,16,29,.82);font-family:'DM Sans',sans-serif;font-size:9px;font-weight:900;letter-spacing:.12em;text-transform:uppercase;}
                  .cm-conf-main{padding:14px 12px 16px;gap:14px;}
                  .cm-conf-head{align-items:flex-start;}
                  .cm-conf-title{font-size:22px;letter-spacing:-.025em;}
                  .cm-conf-sub{font-size:11px;line-height:1.35;}
                  .cm-conf-live{padding:7px 9px;font-size:8px;letter-spacing:.08em;}
                  .cm-conf-stage{perspective:none;min-height:auto;justify-content:flex-start;overflow-x:auto;overflow-y:hidden;padding:2px 0 10px;-webkit-overflow-scrolling:touch;}
                  .cm-conf-road{width:max-content;min-width:100%;gap:12px;transform:none;}
                  .cm-conf-lane{width:min(690px,calc(100vw - 56px));min-height:122px;grid-template-columns:78px minmax(0,1fr);grid-template-areas:"chip status" "center center";gap:10px;padding:14px 12px;border-radius:14px;}
                  .cm-conf-lane:hover,.cm-conf-lane.is-selected{transform:translateY(-2px) scale(1.01);outline-width:1px;}
                  .cm-conf-lane-chip{grid-area:chip;min-width:62px;font-size:28px;padding:5px 10px;letter-spacing:-.06em;}
                  .cm-conf-center{grid-area:center;gap:7px;align-items:flex-start;}
                  .cm-conf-terminal{font-size:17px;padding:5px 14px;max-width:100%;}
                  .cm-conf-trucks{justify-content:flex-start;gap:8px;min-height:28px;}
                  .cm-conf-truck{width:28px;height:28px;}
                  .cm-conf-status-wrap{grid-area:status;justify-content:flex-end;}
                  .cm-conf-status{font-size:10px;padding:6px 10px;letter-spacing:.08em;}
                  .cm-conf-footer{align-items:flex-end;}
                  .cm-conf-route{font-size:8px;letter-spacing:.08em;line-height:1.35;}
                  .cm-conf-legend-btn{width:42px;height:42px;}
                  .cm-conf-legend-panel{right:0;bottom:calc(100% + 10px);width:min(calc(100vw - 34px),330px);padding:13px;}
                }
              `}</style>

              <div className="cm-conf-mobile-rail">
                <span style={{ color:"#22d3ee" }}>Segundo Acceso · Zona Norte</span>
                <span style={{ color:"#f0abfc" }}>Puerto Zona Sur</span>
              </div>

              <aside className="cm-conf-side">
                <div className="cm-conf-vertical">
                  <h2 className="cm-conf-v-title">Segundo Acceso</h2>
                  <div className="cm-conf-v-line" />
                  <span className="cm-conf-v-sub">Zona Norte</span>
                </div>
              </aside>

              <div className="cm-conf-main">
                <div className="cm-conf-head">
                  <div>
                    <div className="cm-conf-kicker">CONFINADA · VISTA OPERATIVA</div>
                    <div className="cm-conf-title">Diagrama de carriles</div>
                    <div className="cm-conf-sub">Real-time status monitor · Terminal North Entrance</div>
                  </div>
                  <div className="cm-conf-live"><AppIcon name="status-live" size={14} active /> En vivo</div>
                </div>

                <div className="cm-conf-stage">
                  <div className="cm-conf-road">
                    {confinadaLanes.map(lane => (
                      <button
                        key={lane.id}
                        type="button"
                        className={`cm-conf-lane ${lane.selected ? "is-selected" : ""}`}
                        onClick={() => setSelectedConfinadaLane(lane.id)}
                        style={{ "--lane-color": lane.color }}
                        title={`${lane.label} · ${lane.status}`}
                      >
                        <div className="cm-conf-lane-chip">{lane.label}</div>
                        <div className="cm-conf-center">
                          <div className="cm-conf-terminal">{lane.terminal}</div>
                          <div className="cm-conf-trucks" aria-hidden="true">
                            {lane.trucks > 0 ? Array.from({ length: lane.trucks }).map((_, i) => (
                              <span key={i} className="cm-conf-truck">
                                <AppIcon name="freight-truck" size={32} active />
                              </span>
                            )) : <span style={{ color:"rgba(226,232,240,.36)", fontSize:"20px", fontWeight:900 }}>—</span>}
                          </div>
                        </div>
                        <div className="cm-conf-status-wrap">
                          <div className="cm-conf-status">{lane.status}</div>
                        </div>
                      </button>
                    ))}
                  </div>
                </div>

                <div className="cm-conf-footer">
                  <div className="cm-conf-route"><strong>←</strong> Conexión segundo acceso</div>
                  <div
                    className="cm-conf-legend-wrap"
                    onMouseEnter={() => setConfinadaLegendOpen(true)}
                    onMouseLeave={() => setConfinadaLegendOpen(false)}
                  >
                    <button
                      className="cm-conf-legend-btn"
                      type="button"
                      onClick={() => setConfinadaLegendOpen(v => !v)}
                      onFocus={() => setConfinadaLegendOpen(true)}
                      onBlur={() => setConfinadaLegendOpen(false)}
                      onTouchStart={() => setConfinadaLegendOpen(true)}
                      title="Mostrar índice del diagrama"
                    >
                      <AppIcon name={confinadaLegendOpen ? "xmark" : "info"} size={22} active />
                    </button>
                    {confinadaLegendOpen && (
                      <div className="cm-conf-legend-panel">
                        <div className="cm-conf-legend-title">Índice del diagrama</div>
                        <div className="cm-conf-legend-list">
                          {CARRIL_ESTADO_OPTS.map(({ id, color, label }) => (
                            <div className="cm-conf-legend-row" key={id}>
                              <div className="cm-conf-legend-dot" style={{ background:color, color }} />
                              <div>
                                <strong>{label}</strong>
                                <span>{statusBrief[id] || "Estado operativo del carril"}</span>
                              </div>
                            </div>
                          ))}
                        </div>
                      </div>
                    )}
                  </div>
                  <div className="cm-conf-route right"><strong>→</strong> Entrada puerto zona sur</div>
                </div>
              </div>

              <aside className="cm-conf-side right">
                <div className="cm-conf-vertical">
                  <h2 className="cm-conf-v-title">Puerto Zona Sur</h2>
                  <div className="cm-conf-v-line" />
                  <span className="cm-conf-v-sub">Pez Vela o Puerta 15</span>
                </div>
              </aside>
            </div>
          );
        })()}

        <SectionLabel text="CARRILES DE INGRESO (C1–C3) · ZONA SUR" rightBtn={<NormalBtn onClick={resetAllConfinada} label="TODO NORMAL" />} />
        {CONFINADA_CARRILES.map(renderConfinadaCard)}
      </>}

      <ToastBox toast={toast} />
    </div>
  );
}

// ─── TAB: CARRILES ────────────────────────────────────────────────────────────
function CarrilesTab() {
  const theme = React.useContext(ThemeContext);
  const carrilesMobile = useWindowWidth() < 720;
  const [estado,  setEstado]  = useState(mkCarrilesState);
  const [accView, setAccView] = useState(() => {
    try { return sessionStorage.getItem("carriles_acc") || "pezvela"; } catch { return "pezvela"; }
  });
  const setAccViewPersist = (v) => {
    try { sessionStorage.setItem("carriles_acc", v); } catch {}
    setAccView(v);
  };
  const [toast,   setToast]   = useState(null);
  const notify = (msg, color = "#38bdf8") => { setToast({ msg, color }); setTimeout(() => setToast(null), 2500); };

  const TABLA  = "carriles";
  const ROW_ID = "expo_impo";

  const saveToSupa = async (newState) => {
    await sb.from(TABLA).upsert({ id: ROW_ID, data: newState });
  };

  useEffect(() => {
    sb.from(TABLA).select("*").eq("id", ROW_ID).single().then(({ data }) => {
      if (data?.data) setEstado(data.data);
    });
    const chan = sb.channel("carriles-rt")
      .on("postgres_changes", { event: "*", schema: "public", table: TABLA }, ({ new: r }) => {
        if (r?.id === ROW_ID && r?.data) setEstado(r.data);
      }).subscribe();
    return () => sb.removeChannel(chan);
  }, []);

  const toggle = async (cid, value) => {
    const next = { ...estado, [cid]: { ...estado[cid], abierto: value, lastUpdate: Date.now(), updatedBy: "Tú" } };
    setEstado(next);
    await saveToSupa(next);
    await auditLog({ action:"modificar_carril_expo_impo", section:"carriles", entityId:cid, before:estado[cid], after:{ carril:cid, campo:"abierto", value, valor_label:value ? "Abierto" : "Cerrado", summary:`${getDeviceId()} marcó ${cid.toUpperCase()} como ${value ? "Abierto" : "Cerrado"}` }, actor:`Usuario_${getDeviceId().slice(-4)}` });
    notify(value ? "✓ Carril abierto" : "⛔ Carril cerrado", value ? "#22c55e" : "#6b7280");
    await publicarNoticia({ tipo: "carril", icono: "🚦", color: value ? "#22c55e" : "#6b7280", titulo: `Carril ${cid.toUpperCase()} — ${value ? "Abierto" : "Cerrado"}`, detalle: "Estado de carril expo/impo actualizado" });
  };

  const resetAcceso = async (acc) => {
    const next = { ...estado };
    acc.carriles.forEach(c => { next[c.id] = { abierto: true, lastUpdate: Date.now(), updatedBy: "Reset" }; });
    setEstado(next);
    await saveToSupa(next);
    notify("✓ Acceso restablecido", "#22c55e");
  };

  const resetAll = async () => {
    const next = mkCarrilesState();
    setEstado(next);
    await saveToSupa(next);
    notify("✓ Todo restablecido", "#22c55e");
  };

  const currentAcc   = ACCESOS_CARRILES.find(a => a.id === accView);
  const expoCarriles = currentAcc?.carriles.filter(c => c.tipo === "expo") || [];
  const impoCarriles = currentAcc?.carriles.filter(c => c.tipo === "impo") || [];
  const EXPO_COLOR = "#f59e0b";
  const IMPO_COLOR = "#60a5fa";
  const ACCESS_CONTROL_ICON = "data:image/png;base64,";

  const laneCardShell = (accent) => ({
    background:"linear-gradient(180deg, rgba(255,255,255,0.08), rgba(8,15,30,0.96))",
    backdropFilter:"blur(14px)", WebkitBackdropFilter:"blur(14px)",
    border:`1px solid ${accent}52`, borderRadius:"18px", padding:"14px",
    boxShadow:`0 18px 40px ${accent}14, inset 0 1px 0 rgba(255,255,255,0.07)`
  });
  const laneMiniLabelStyle = { fontSize:"9px", color:"rgba(255,255,255,0.46)", fontFamily:getFont(theme, "secondary"), letterSpacing:"1.2px", textTransform:"uppercase" };
  const laneHeroTitleStyle = { color:"#f8fafc", fontFamily:getFont(theme, "title"), fontWeight:"800", fontSize:"17px", letterSpacing:"-.01em" };
  const laneFieldTitleStyle = { fontSize:"10px", color:"rgba(255,255,255,0.54)", fontFamily:getFont(theme, "secondary"), letterSpacing:"1.1px", textTransform:"uppercase" };
  const laneBlockStyle = (accent, soft = true) => ({
    background: soft ? `linear-gradient(180deg, ${accent}10, rgba(7,17,31,0.92))` : "rgba(7,17,31,0.92)",
    border:`1px solid ${accent}3f`, borderRadius:"14px", padding:"12px", boxShadow:`0 8px 22px ${accent}16`
  });
  const laneHeaderNode = (iconName, title, subtitle, accent, iconSize = 26) => (
    <div style={{ display:"flex", alignItems:"center", gap:"10px", marginBottom:"10px" }}>
      <div style={{ width:"44px", height:"44px", borderRadius:"12px", display:"grid", placeItems:"center", background:`linear-gradient(180deg, ${accent}24, rgba(255,255,255,0.03))`, border:`1px solid ${accent}44`, boxShadow:`inset 0 1px 0 rgba(255,255,255,0.08), 0 10px 24px ${accent}22` }}>
        <AppIcon name={iconName} size={iconSize} active />
      </div>
      <div style={{ minWidth:0 }}>
        <div style={laneFieldTitleStyle}>{title}</div>
        <div style={{ color:"#f8fafc", fontFamily:getFont(theme, "secondary"), fontWeight:"800", fontSize:"13px", lineHeight:1.15 }}>{subtitle}</div>
      </div>
    </div>
  );
  const selectorButtonStyle = (active, accent) => ({
    width:"100%",
    display:"flex",
    alignItems:"center",
    justifyContent:"space-between",
    gap:"12px",
    padding:"11px 14px",
    background: active ? `linear-gradient(180deg, ${accent}14, rgba(2,12,27,0.96))` : "linear-gradient(180deg, rgba(255,255,255,0.04), rgba(2,12,27,0.96))",
    border:`1px solid ${active ? accent : "rgba(56,189,248,0.26)"}`,
    borderRadius:"14px",
    boxShadow: active ? `0 10px 22px ${accent}16, inset 0 1px 0 rgba(255,255,255,0.08)` : "inset 0 1px 0 rgba(255,255,255,0.04)",
    color: active ? "#f8fafc" : "#cbd5e1",
    cursor:"pointer",
    transition:"all 0.18s ease",
    textAlign:"left"
  });
  const selectorMenuIcon = (active, accent) => (
    <div style={{ color: active ? accent : "rgba(148,163,184,0.72)", fontSize:"22px", lineHeight:1, paddingLeft:"8px" }}>≡</div>
  );
  const renderCarrilVoteCard = (carril, accent, tipoLabel, iconName) => {
    const st = estado[carril.id] || {};
    const abierto = st.abierto !== false;
    const baseType = tipoLabel.toUpperCase();
    return (
      <div key={carril.id} style={laneCardShell(abierto ? accent : "#6b7280")}>
        <div style={{ display:"flex", alignItems:"flex-start", justifyContent:"space-between", gap:"12px", flexWrap:"wrap", marginBottom:"12px" }}>
          <div>
            <div style={{ display:"flex", alignItems:"center", gap:"8px", flexWrap:"wrap" }}>
              <div style={{ background:`${accent}18`, border:`1px solid ${accent}44`, borderRadius:"999px", padding:"4px 10px", color:accent, fontFamily:getFont(theme, "secondary"), fontSize:"12px", fontWeight:"800", letterSpacing:".05em", textTransform:"uppercase" }}>{carril.label}</div>
              <Badge color={accent} small>{baseType}</Badge>
            </div>
            <div style={{ color:"rgba(255,255,255,0.42)", fontSize:"10px", fontFamily:getFont(theme, "secondary"), marginTop:"5px" }}>{timeAgo(st.lastUpdate)} · {st.updatedBy || "Tú"}</div>
          </div>
          <Badge color={abierto ? "#22c55e" : "#6b7280"} small>{abierto ? "ABIERTO" : "CERRADO"}</Badge>
        </div>

        <div style={{ display:"grid", gridTemplateColumns:carrilesMobile ? "1fr" : "repeat(auto-fit,minmax(240px,1fr))", gap:"12px" }}>
          <div style={laneBlockStyle(accent)}>
            {laneHeaderNode(iconName, `Control de ${tipoLabel.toLowerCase()}`, abierto ? `${tipoLabel} habilitada` : `${tipoLabel} detenida`, accent, 30)}
            <div style={{ ...laneMiniLabelStyle, marginBottom:"4px" }}>Acceso asignado</div>
            <div style={{ ...laneHeroTitleStyle, color:accent, fontSize:"16px", marginBottom:"2px" }}>{currentAcc?.label || "Acceso actual"}</div>
            <div style={{ color:"rgba(255,255,255,0.46)", fontSize:"11px", marginBottom:"10px" }}>Zona {currentAcc?.zona || "—"} · {tipoLabel}</div>
            <div style={{ padding:"8px 10px", background: abierto ? "rgba(34,197,94,.10)" : "rgba(107,114,128,.12)", border:`1px solid ${abierto ? "rgba(34,197,94,.28)" : "rgba(148,163,184,.20)"}`, borderRadius:"10px", color: abierto ? "#22c55e" : "#9ca3af", fontSize:"11px", fontFamily:getFont(theme, "secondary"), fontWeight:"800", letterSpacing:".04em", textTransform:"uppercase" }}>
              {abierto ? "Operando con normalidad" : "Temporalmente cerrado"}
            </div>
          </div>

          <div style={laneBlockStyle(abierto ? "#14b8a6" : "#64748b")}>
            {laneHeaderNode(iconName, "Sistema de selección", abierto ? "Carril abierto" : "Carril cerrado", abierto ? "#14b8a6" : "#64748b", 28)}
            <div style={{ ...laneMiniLabelStyle, marginBottom:"8px" }}>Selecciona el estado del carril</div>
            <div style={{ display:"grid", gap:"10px", marginBottom:"10px" }}>
              <button onClick={() => toggle(carril.id, true)} style={selectorButtonStyle(abierto, "#22c55e")}>
                <div style={{ display:"flex", alignItems:"center", gap:"10px", minWidth:0 }}>
                  <div style={{ width:"28px", height:"28px", borderRadius:"10px", display:"grid", placeItems:"center", background: abierto ? "rgba(34,197,94,.12)" : "rgba(255,255,255,.04)", border:`1px solid ${abierto ? "rgba(34,197,94,.35)" : "rgba(255,255,255,.10)"}` }}><span style={{ color: abierto ? "#22c55e" : "#94a3b8", fontWeight:"900", fontSize:"18px", lineHeight:1 }}>✓</span></div>
                  <div style={{ minWidth:0 }}>
                    <div style={{ fontSize:"10px", color: abierto ? "#22c55e" : "rgba(148,163,184,0.78)", letterSpacing:".12em", textTransform:"uppercase", fontWeight:"800", marginBottom:"2px" }}>Estado seleccionado</div>
                    <div style={{ fontSize:"14px", color: abierto ? "#f8fafc" : "#cbd5e1", fontWeight:"800" }}>Abierto</div>
                  </div>
                </div>
                {selectorMenuIcon(abierto, "#22c55e")}
              </button>
              <button onClick={() => toggle(carril.id, false)} style={selectorButtonStyle(!abierto, "#ef4444")}>
                <div style={{ display:"flex", alignItems:"center", gap:"10px", minWidth:0 }}>
                  <div style={{ width:"28px", height:"28px", borderRadius:"10px", display:"grid", placeItems:"center", background: !abierto ? "rgba(239,68,68,.12)" : "rgba(255,255,255,.04)", border:`1px solid ${!abierto ? "rgba(239,68,68,.35)" : "rgba(255,255,255,.10)"}` }}><span style={{ color: !abierto ? "#ef4444" : "#94a3b8", fontWeight:"900", fontSize:"18px", lineHeight:1 }}>⛔</span></div>
                  <div style={{ minWidth:0 }}>
                    <div style={{ fontSize:"10px", color: !abierto ? "#ef4444" : "rgba(148,163,184,0.78)", letterSpacing:".12em", textTransform:"uppercase", fontWeight:"800", marginBottom:"2px" }}>Estado seleccionado</div>
                    <div style={{ fontSize:"14px", color: !abierto ? "#f8fafc" : "#cbd5e1", fontWeight:"800" }}>Cerrado</div>
                  </div>
                </div>
                {selectorMenuIcon(!abierto, "#ef4444")}
              </button>
            </div>
            <div style={{ color:"rgba(255,255,255,0.42)", fontSize:"10px", fontFamily:getFont(theme, "secondary") }}>Última actualización: {timeAgo(st.lastUpdate)}</div>
          </div>
        </div>
      </div>
    );
  };

  return (
    <div style={{ padding:carrilesMobile ? "12px" : "16px", paddingBottom:"96px", minHeight:"100vh", overflowX:"hidden" }}>
      <div style={{ background:"rgba(255,255,255,0.08)", backdropFilter:"blur(12px)", WebkitBackdropFilter:"blur(12px)", border:"1px solid rgba(255,255,255,0.15)", borderRadius:"12px", padding:"12px", marginBottom:"14px" }}>
        <div style={{ fontSize:"10px", color:"#38bdf8", fontFamily:getFont(theme, "secondary"), letterSpacing:"2px", marginBottom:"4px" }}>CARRILES — PUERTO MANZANILLO</div>
        <div style={{ color:"rgba(255,255,255,0.7)", fontSize:"12px" }}>Estado de carriles de exportación e importación por acceso.</div>
      </div>
      <div style={{ background:"rgba(255,255,255,0.05)", border:"1px solid rgba(255,255,255,0.15)", borderRadius:"12px", padding:"12px", marginBottom:"14px" }}>
        <div style={{ fontSize:"10px", color:"rgba(255,255,255,0.5)", fontFamily:getFont(theme, "secondary"), letterSpacing:"1px", marginBottom:"10px" }}>RESUMEN GENERAL</div>
        {ACCESOS_CARRILES.map(acc => {
          const total    = acc.carriles.length;
          const abiertos = acc.carriles.filter(c => estado[c.id]?.abierto !== false).length;
          const pct      = Math.round((abiertos / total) * 100);
          return (
            <div key={acc.id} style={{ marginBottom:"8px" }}>
              <div style={{ display:"flex", justifyContent:"space-between", marginBottom:"3px" }}>
                <span style={{ fontSize:"11px", color:acc.color, fontFamily:getFont(theme, "secondary"), fontWeight:"700" }}>{acc.label}</span>
                <span style={{ fontSize:"10px", color:"rgba(255,255,255,0.5)", fontFamily:getFont(theme, "secondary") }}>{abiertos}/{total} abiertos</span>
              </div>
              <div style={{ background:"#1e3a5f", borderRadius:"3px", height:"5px", overflow:"hidden" }}>
                <div style={{ width:`${pct}%`, height:"100%", background: pct===100?"#22c55e": pct>50? acc.color:"#ef4444", transition:"width 0.4s", borderRadius:"3px" }} />
              </div>
            </div>
          );
        })}
        <div style={{ display:"flex", justifyContent:"center", gap:"12px", marginTop:"10px", flexWrap:"wrap" }}>
          {[["#f59e0b","EXPORTACIÓN"],["#60a5fa","IMPORTACIÓN"],["#22c55e","ABIERTO"],["#ef4444","CERRADO"]].map(([c,l]) => (
            <div key={l} style={{ display:"flex", alignItems:"center", gap:"3px" }}>
              <div style={{ width:"8px", height:"8px", background:c, borderRadius:"2px" }} />
              <span style={{ fontSize:"8px", color:"rgba(255,255,255,0.5)", fontFamily:getFont(theme, "secondary") }}>{l}</span>
            </div>
          ))}
        </div>
      </div>
      <div style={{ display:"grid", gridTemplateColumns:carrilesMobile ? "1fr" : "repeat(3, minmax(0,1fr))", gap:"12px", marginBottom:"16px" }}>
        {ACCESOS_CARRILES.map(acc => {
          const active = accView===acc.id;
          return (
            <button
              key={acc.id}
              onClick={() => setAccViewPersist(acc.id)}
              style={{
                width:"100%",
                display:"flex",
                alignItems:"center",
                justifyContent:"space-between",
                gap:"12px",
                minHeight:"72px",
                padding:"12px 16px",
                background: active ? `linear-gradient(180deg, ${acc.color}14, rgba(2,12,27,0.96))` : "linear-gradient(180deg, rgba(255,255,255,0.04), rgba(2,12,27,0.96))",
                border:`1px solid ${active ? acc.color : "rgba(56,189,248,0.24)"}`,
                borderRadius:"18px",
                color: active ? "#f8fafc" : "#dbe7f5",
                fontFamily:getFont(theme, "secondary"),
                cursor:"pointer",
                transition:"all 0.18s ease",
                boxShadow: active ? `0 12px 28px ${acc.color}18, inset 0 1px 0 rgba(255,255,255,0.08)` : "inset 0 1px 0 rgba(255,255,255,0.04)",
                textAlign:"left"
              }}
            >
              <div style={{ display:"flex", alignItems:"center", gap:"12px", minWidth:0, flex:1 }}>
                <img src={ACCESS_CONTROL_ICON} alt="Acceso" style={{ width:"30px", height:"30px", objectFit:"contain", opacity: active ? 1 : 0.88, filter: active ? `drop-shadow(0 0 8px ${acc.color}55)` : "none" }} />
                <div style={{ minWidth:0 }}>
                  <div style={{ fontSize:"10px", color: active ? acc.color : "rgba(148,163,184,0.8)", letterSpacing:".14em", textTransform:"uppercase", marginBottom:"4px", fontWeight:"800" }}>Control de acceso</div>
                  <div style={{ fontSize:"14px", lineHeight:1.15, fontWeight:"800", color: active ? "#f8fafc" : "#dbe7f5" }}>{acc.label}</div>
                </div>
              </div>
              <div style={{ flex:"0 0 auto", color: active ? acc.color : "rgba(148,163,184,0.72)", fontSize:"24px", lineHeight:1 }}>≡</div>
            </button>
          );
        })}
      </div>
      {currentAcc && (
        <>
          <div style={{ display:"flex", justifyContent:"space-between", alignItems:carrilesMobile ? "flex-start" : "center", marginBottom:"14px", gap:"10px", flexWrap:"wrap" }}>
            <div style={{ display:"flex", alignItems:"center", gap:"8px", flexWrap:"wrap" }}>
              <div style={{ width:"10px", height:"10px", background:currentAcc.color, borderRadius:"50%", boxShadow:`0 0 8px ${currentAcc.color}` }} />
              <span style={{ color:currentAcc.color, fontFamily:getFont(theme, "secondary"), fontWeight:"700", fontSize:"14px" }}>{currentAcc.label}</span>
              <Badge color={currentAcc.zona==="Norte"?"#38bdf8":"#a78bfa"} small>ZONA {currentAcc.zona.toUpperCase()}</Badge>
            </div>
            <NormalBtn onClick={() => resetAcceso(currentAcc)} label="TODO ABIERTO" />
          </div>
          {expoCarriles.length > 0 && (
            <>
              <div style={{ fontSize:"10px", color:EXPO_COLOR, fontFamily:getFont(theme, "secondary"), letterSpacing:"2px", marginBottom:"10px" }}>EXPORTACIÓN</div>
              <div style={{ display:"grid", gridTemplateColumns: carrilesMobile || expoCarriles.length===1 ? "1fr" : "1fr 1fr", gap:"12px", marginBottom:"16px" }}>
                {expoCarriles.map(carril => renderCarrilVoteCard(carril, EXPO_COLOR, "Exportación", "truck-export"))}
              </div>
            </>
          )}
          {impoCarriles.length > 0 && (
            <>
              <div style={{ fontSize:"10px", color:IMPO_COLOR, fontFamily:getFont(theme, "secondary"), letterSpacing:"2px", marginBottom:"10px" }}>IMPORTACIÓN</div>
              <div style={{ display:"grid", gridTemplateColumns: carrilesMobile || impoCarriles.length===1 ? "1fr" : "1fr 1fr", gap:"12px", marginBottom:"14px" }}>
                {impoCarriles.map(carril => renderCarrilVoteCard(carril, IMPO_COLOR, "Importación", "truck-import"))}
              </div>
            </>
          )}
        </>
      )}
      <ToastBox toast={toast} />
    </div>
  );
}

// ─── TAB: NOTICIAS ────────────────────────────────────────────────────────────
// ─── VISOR FULLSCREEN ─────────────────────────────────────────────────────────
function VisorFullscreen({ item, onClose, items = [], currentIndex = 0, onNavigate = null, onDownload = null, downloading = false }) {
  const theme = React.useContext(ThemeContext);
  const isPdf = item?.archivo_url?.toLowerCase().includes(".pdf") || item?.archivo_tipo === "application/pdf";
  const canNavigate = Array.isArray(items) && items.length > 1 && typeof onNavigate === "function";
  const safeIndex = Number.isFinite(currentIndex) ? currentIndex : 0;

  const goPrev = useCallback(() => {
    if (!canNavigate) return;
    onNavigate((safeIndex - 1 + items.length) % items.length);
  }, [canNavigate, onNavigate, safeIndex, items.length]);

  const goNext = useCallback(() => {
    if (!canNavigate) return;
    onNavigate((safeIndex + 1) % items.length);
  }, [canNavigate, onNavigate, safeIndex, items.length]);

  useEffect(() => {
    const prevOverflow = document.body.style.overflow;
    document.body.style.overflow = "hidden";
    const handler = (e) => {
      if (e.key === "Escape") onClose();
      if (canNavigate && e.key === "ArrowLeft") goPrev();
      if (canNavigate && e.key === "ArrowRight") goNext();
    };
    document.addEventListener("keydown", handler);
    return () => {
      document.body.style.overflow = prevOverflow;
      document.removeEventListener("keydown", handler);
    };
  }, [onClose, canNavigate, goPrev, goNext]);

  if (!item) return null;

  const iconBtn = {
    width:"42px",
    height:"42px",
    borderRadius:"999px",
    background:"rgba(10,22,40,0.62)",
    border:"1px solid rgba(255,255,255,0.20)",
    color:"#fff",
    fontSize:"18px",
    cursor:"pointer",
    display:"flex",
    alignItems:"center",
    justifyContent:"center",
    backdropFilter:"blur(10px)",
    WebkitBackdropFilter:"blur(10px)",
    boxShadow:"0 12px 36px rgba(0,0,0,.45)",
    textDecoration:"none"
  };

  return (
    <div onClick={onClose} style={{ position:"fixed", inset:0, zIndex:9999, background:"rgba(0,0,0,0.96)", display:"flex", alignItems:"center", justifyContent:"center", padding:"10px", overflow:"hidden" }}>
      <div onClick={e => e.stopPropagation()} style={{ position:"relative", width:"100%", height:"100%", display:"flex", alignItems:"center", justifyContent:"center" }}>
        {isPdf ? (
          <iframe src={item.archivo_url} title="Documento" style={{ width:"min(1180px, 100%)", height:"94vh", border:"none", background:"#fff", borderRadius:"10px", boxShadow:"0 22px 90px rgba(0,0,0,.70)" }} />
        ) : (
          <img src={item.archivo_url} alt="Imagen ampliada" style={{ maxWidth:"100%", maxHeight:"96vh", width:"auto", height:"auto", objectFit:"contain", display:"block", background:"#061428", borderRadius:"10px", boxShadow:"0 22px 90px rgba(0,0,0,.70)" }} />
        )}

        <button onClick={onClose} title="Cerrar" style={{ ...iconBtn, position:"absolute", top:"14px", right:"14px", fontSize:"22px" }}>×</button>

        {canNavigate && (
          <>
            <button onClick={goPrev} title="Anterior" style={{ ...iconBtn, position:"absolute", left:"14px", top:"50%", transform:"translateY(-50%)", width:"50px", height:"50px", fontSize:"30px" }}>‹</button>
            <button onClick={goNext} title="Siguiente" style={{ ...iconBtn, position:"absolute", right:"14px", top:"50%", transform:"translateY(-50%)", width:"50px", height:"50px", fontSize:"30px" }}>›</button>
            <div style={{ position:"absolute", left:"50%", bottom:"14px", transform:"translateX(-50%)", padding:"7px 12px", borderRadius:"999px", background:"rgba(10,22,40,0.46)", border:"1px solid rgba(255,255,255,.14)", color:"rgba(255,255,255,.70)", fontFamily:getFont(theme, "secondary"), fontSize:"10px", fontWeight:700, backdropFilter:"blur(10px)", WebkitBackdropFilter:"blur(10px)" }}>
              {safeIndex + 1} / {items.length}
            </div>
          </>
        )}

        <div style={{ position:"absolute", right:"14px", bottom:"14px", display:"flex", gap:"8px", alignItems:"center" }}>
          <a href={item.archivo_url} target="_blank" rel="noopener noreferrer" title="Abrir en nueva pestaña" style={iconBtn}>↗</a>
          {onDownload ? (
            <button onClick={() => onDownload(item)} disabled={downloading} title={downloading ? "Preparando descarga" : "Descargar con marca de agua"} style={{ ...iconBtn, opacity: downloading ? 0.55 : 1, cursor: downloading ? "not-allowed" : "pointer" }}>{downloading ? "…" : "⬇"}</button>
          ) : (
            <a href={item.archivo_url} download title="Descargar" style={iconBtn}>⬇</a>
          )}
        </div>
      </div>
    </div>
  );
}



// ─── CAPTURA WEB CON RECORTE (solo admin) ────────────────────────────────────
function ScreenshotCropModal({ onClose, onApply }) {
  const theme = React.useContext(ThemeContext);
  const [url, setUrl] = useState("");
  const [imageDataUrl, setImageDataUrl] = useState("");
  const [sourceUrl, setSourceUrl] = useState("");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [zone, setZone] = useState({ x: 0.08, y: 0.12, w: 0.84, h: 0.48 });
  const [natural, setNatural] = useState({ width: 1024, height: 768 });
  const dragRef = useRef(null);

  useEffect(() => {
    const prevOverflow = document.body.style.overflow;
    const prevOverscroll = document.body.style.overscrollBehavior;
    document.body.style.overflow = "hidden";
    document.body.style.overscrollBehavior = "none";
    return () => {
      document.body.style.overflow = prevOverflow;
      document.body.style.overscrollBehavior = prevOverscroll;
    };
  }, []);

  useEffect(() => {
    const move = (ev) => {
      const d = dragRef.current;
      if (!d) return;
      ev.preventDefault?.();
      const clientX = ev.touches?.[0]?.clientX ?? ev.clientX;
      const clientY = ev.touches?.[0]?.clientY ?? ev.clientY;
      const dx = (clientX - d.startX) / Math.max(1, d.rect.width);
      const dy = (clientY - d.startY) / Math.max(1, d.rect.height);
      let { x, y, w, h } = d.zone;
      if (d.mode === "move") {
        x = Math.min(1 - w, Math.max(0, x + dx));
        y = Math.min(1 - h, Math.max(0, y + dy));
      } else {
        w = Math.min(1 - x, Math.max(0.08, w + dx));
        h = Math.min(1 - y, Math.max(0.06, h + dy));
      }
      setZone({ x, y, w, h });
    };
    const up = () => { dragRef.current = null; };
    window.addEventListener("mousemove", move);
    window.addEventListener("mouseup", up);
    window.addEventListener("touchmove", move, { passive: false });
    window.addEventListener("touchend", up);
    return () => {
      window.removeEventListener("mousemove", move);
      window.removeEventListener("mouseup", up);
      window.removeEventListener("touchmove", move);
      window.removeEventListener("touchend", up);
    };
  }, []);

  const normalizedUrl = (value) => {
    let u = String(value || "").trim();
    if (!u) return "";
    if (!/^https?:\/\//i.test(u)) u = "https://" + u;
    return u;
  };

  const takeScreenshot = async () => {
    const target = normalizedUrl(url);
    if (!target) {
      setError("Escribe una URL para capturar.");
      return;
    }
    setLoading(true);
    setError("");
    setImageDataUrl("");
    try {
      let data = null;
      let invokeError = null;
      try {
        const result = await sb.functions.invoke("screenshot-web", { body: { url: target, dimension: "1024x768" } });
        data = result.data;
        invokeError = result.error;
      } catch (e) {
        invokeError = e;
      }
      if (invokeError || !data?.base64) {
        const detail = data?.error || invokeError?.message || "La Edge Function screenshot-web no devolvió imagen.";
        const lastAttempt = Array.isArray(data?.attempts) && data.attempts.length
          ? data.attempts.map(a => `${a.label || "proveedor"}: HTTP ${a.status || "?"} ${a.contentType || ""}`).join(" · ")
          : "";
        throw new Error(`${detail}${lastAttempt ? ` (${lastAttempt})` : ""}`);
      }
      setSourceUrl(data.url || target);
      setImageDataUrl(data.base64);
      setZone({ x: 0.08, y: 0.12, w: 0.84, h: 0.48 });
    } catch (e) {
      console.error(e);
      setError(e?.message || "No se pudo tomar la captura web.");
    } finally {
      setLoading(false);
    }
  };

  const startDrag = (ev, mode) => {
    const rect = ev.currentTarget.closest("[data-screenshot-stage]")?.getBoundingClientRect();
    if (!rect) return;
    const clientX = ev.touches?.[0]?.clientX ?? ev.clientX;
    const clientY = ev.touches?.[0]?.clientY ?? ev.clientY;
    dragRef.current = { mode, startX: clientX, startY: clientY, rect, zone: { ...zone } };
    ev.preventDefault?.();
    ev.stopPropagation?.();
  };

  const applyCrop = async () => {
    if (!imageDataUrl) {
      setError("Primero toma una captura.");
      return;
    }
    setLoading(true);
    setError("");
    try {
      const img = await loadImage(imageDataUrl);
      const sx = Math.round(zone.x * img.width);
      const sy = Math.round(zone.y * img.height);
      const sw = Math.max(1, Math.round(zone.w * img.width));
      const sh = Math.max(1, Math.round(zone.h * img.height));
      const canvas = document.createElement("canvas");
      canvas.width = sw;
      canvas.height = sh;
      const ctx = canvas.getContext("2d");
      ctx.drawImage(img, sx, sy, sw, sh, 0, 0, sw, sh);
      const blob = await new Promise(resolve => canvas.toBlob(resolve, "image/jpeg", 0.92));
      if (!blob) throw new Error("No se pudo crear la imagen recortada.");
      const file = new File([blob], `captura-web-${Date.now()}.jpg`, { type: "image/jpeg" });
      const dataUrl = canvas.toDataURL("image/jpeg", 0.92);
      await onApply?.({ file, dataUrl, url: sourceUrl || normalizedUrl(url), zone: { ...zone } });
      onClose?.();
    } catch (e) {
      console.error(e);
      setError(e?.message || "No se pudo preparar el recorte.");
    } finally {
      setLoading(false);
    }
  };

  return createPortal(
    <div style={{ position:"fixed", inset:0, zIndex:10000, background:"rgba(2,6,23,.88)", display:"flex", alignItems:"center", justifyContent:"center", padding:"14px", overflow:"hidden", overscrollBehavior:"none" }} onClick={onClose}>
      <div onClick={e=>e.stopPropagation()} style={{ width:"min(1120px, 100%)", maxHeight:"94vh", overflow:"hidden", background:"#0b1b33", border:"1px solid rgba(56,189,248,.35)", borderRadius:"16px", boxShadow:"0 20px 80px rgba(0,0,0,.45)", display:"flex", flexDirection:"column" }}>
        <div style={{ padding:"13px 15px", borderBottom:"1px solid rgba(255,255,255,.10)", display:"flex", justifyContent:"space-between", alignItems:"center", gap:"10px" }}>
          <div>
            <div style={{ fontFamily:getFont(theme,"secondary"), fontWeight:900, color:"#fff", fontSize:"14px" }}>Captura web con recorte</div>
            <div style={{ fontFamily:getFont(theme,"secondary"), color:"rgba(255,255,255,.55)", fontSize:"11px", marginTop:"2px" }}>Solo admin. Toma screenshot, centra la zona y úsala para publicar en Noticias.</div>
          </div>
          <button onClick={onClose} style={{ width:"34px", height:"34px", borderRadius:"999px", border:"1px solid rgba(255,255,255,.16)", background:"rgba(255,255,255,.08)", color:"#fff", cursor:"pointer" }}>✕</button>
        </div>

        <div style={{ padding:"12px", display:"grid", gridTemplateColumns:"1fr auto", gap:"8px", borderBottom:"1px solid rgba(255,255,255,.08)" }}>
          <input value={url} onChange={e=>setUrl(e.target.value)} placeholder="https://ejemplo.com" onKeyDown={e=>{ if(e.key === "Enter") takeScreenshot(); }} style={{ minWidth:0, background:"#061428", border:"1px solid rgba(56,189,248,.30)", borderRadius:"10px", padding:"11px 12px", color:"#fff", fontFamily:getFont(theme,"secondary"), outline:"none" }} />
          <button onClick={takeScreenshot} disabled={loading} style={{ padding:"10px 14px", borderRadius:"10px", border:"1px solid #2563eb", background:loading ? "#1e3a8a" : "#2563eb", color:"#fff", fontFamily:getFont(theme,"secondary"), fontWeight:900, cursor:loading ? "wait" : "pointer" }}>{loading ? "Capturando…" : "Tomar screenshot"}</button>
        </div>

        {error && <div style={{ margin:"12px", padding:"10px 12px", borderRadius:"10px", color:"#f87171", border:"1px solid rgba(239,68,68,.45)", background:"rgba(239,68,68,.10)", fontFamily:getFont(theme,"secondary"), fontSize:"11px" }}>{error}</div>}

        <div style={{ padding:"12px", overflow:"auto", overscrollBehavior:"contain", WebkitOverflowScrolling:"touch" }}>
          {!imageDataUrl ? (
            <div style={{ padding:"42px", textAlign:"center", color:"#94a3b8", fontFamily:getFont(theme,"secondary"), border:"1px dashed rgba(148,163,184,.25)", borderRadius:"14px" }}>Ingresa una URL y toma una captura para elegir la zona de recorte.</div>
          ) : (
            <>
              <div style={{ display:"flex", justifyContent:"space-between", gap:"8px", flexWrap:"wrap", marginBottom:"10px" }}>
                <div style={{ color:"#cbd5e1", fontFamily:getFont(theme,"secondary"), fontSize:"11px", fontWeight:800, wordBreak:"break-all" }}>{sourceUrl}</div>
                <div style={{ display:"flex", gap:"8px", flexWrap:"wrap" }}>
                  <button onClick={()=>setZone({ x:0.08, y:0.12, w:0.84, h:0.48 })} style={{ padding:"8px 10px", borderRadius:"9px", border:"1px solid rgba(251,191,36,.35)", background:"rgba(251,191,36,.10)", color:"#fbbf24", cursor:"pointer" }}>Restablecer cuadro</button>
                  <button onClick={()=>setZone({ x:0, y:0, w:1, h:1 })} style={{ padding:"8px 10px", borderRadius:"9px", border:"1px solid rgba(148,163,184,.30)", background:"rgba(148,163,184,.10)", color:"#cbd5e1", cursor:"pointer" }}>Toda la captura</button>
                </div>
              </div>
              <div data-screenshot-stage style={{ position:"relative", width:"min(100%, 920px)", aspectRatio:`${natural.width} / ${natural.height}`, margin:"0 auto", borderRadius:"12px", overflow:"hidden", border:"1px solid rgba(255,255,255,.14)", background:"#fff", lineHeight:0, userSelect:"none", touchAction:"none" }}>
                <img src={imageDataUrl} alt="Captura web" draggable={false} onLoad={(e)=>setNatural({ width:e.currentTarget.naturalWidth || 1024, height:e.currentTarget.naturalHeight || 768 })} style={{ position:"absolute", inset:0, width:"100%", height:"100%", display:"block" }} />
                <div onMouseDown={(e)=>startDrag(e,"move")} onTouchStart={(e)=>startDrag(e,"move")} style={{ position:"absolute", left:`${zone.x*100}%`, top:`${zone.y*100}%`, width:`${zone.w*100}%`, height:`${zone.h*100}%`, border:"2px solid #22c55e", background:"rgba(34,197,94,.14)", boxShadow:"0 0 0 9999px rgba(0,0,0,.36)", cursor:"move", boxSizing:"border-box", touchAction:"none" }}>
                  <div style={{ position:"absolute", left:"8px", top:"8px", background:"rgba(2,6,23,.82)", color:"#fff", borderRadius:"999px", padding:"4px 8px", fontSize:"10px", fontFamily:getFont(theme,"secondary"), lineHeight:1 }}>Zona de publicación</div>
                  <div onMouseDown={(e)=>startDrag(e,"resize")} onTouchStart={(e)=>startDrag(e,"resize")} style={{ position:"absolute", right:"-7px", bottom:"-7px", width:"18px", height:"18px", borderRadius:"5px", background:"#22c55e", border:"2px solid #052e16", cursor:"nwse-resize", touchAction:"none" }} />
                </div>
              </div>
            </>
          )}
        </div>

        <div style={{ padding:"12px", borderTop:"1px solid rgba(255,255,255,.10)", display:"flex", justifyContent:"flex-end", gap:"8px", flexWrap:"wrap" }}>
          <button onClick={onClose} style={{ padding:"10px 14px", borderRadius:"10px", border:"1px solid rgba(255,255,255,.14)", background:"rgba(255,255,255,.06)", color:"#cbd5e1", fontFamily:getFont(theme,"secondary"), fontWeight:800, cursor:"pointer" }}>Cancelar</button>
          <button onClick={applyCrop} disabled={loading || !imageDataUrl} style={{ padding:"10px 14px", borderRadius:"10px", border:"1px solid #22c55e", background:(loading || !imageDataUrl) ? "rgba(34,197,94,.25)" : "#22c55e", color:(loading || !imageDataUrl) ? "#86efac" : "#052e16", fontFamily:getFont(theme,"secondary"), fontWeight:900, cursor:(loading || !imageDataUrl) ? "not-allowed" : "pointer" }}>Usar recorte para publicar</button>
        </div>
      </div>
    </div>,
    document.body
  );
}

// ─── SUBIR COMUNICADO (con fechas y aprobación) ──────────────────────────────
function SubirComunicadoPanel({ onSubido, isAdmin }) {
  const theme = React.useContext(ThemeContext);
  const [titulo, setTitulo] = useState("");
  const [detalle, setDetalle] = useState("");
  const [archivo, setArchivo] = useState(null);
  const [preview, setPreview] = useState(null);
  const [fechaInicio, setFechaInicio] = useState("");
  const [fechaFin, setFechaFin] = useState("");
  const [fechaFinModo, setFechaFinModo] = useState("fecha"); // "fecha" | "fecha_hora"
  const [fechaFinHora, setFechaFinHora] = useState("");
  const [subiendo, setSubiendo] = useState(false);
  const [error, setError] = useState("");
  const [exito, setExito] = useState(false);
  const [toolBusy, setToolBusy] = useState(false);
  const [toolMsg, setToolMsg] = useState(null);
  const [aiAssistOpen, setAiAssistOpen] = useState(false);
  const [aiAction, setAiAction] = useState("resumir"); // "resumir" | "crear"
  const [aiOutput, setAiOutput] = useState("");
  const [aiBusy, setAiBusy] = useState(false);
  const [zonePickerOpen, setZonePickerOpen] = useState(false);
  const [converterOpen, setConverterOpen] = useState(false);
  const [screenshotOpen, setScreenshotOpen] = useState(false);
  const [graphicBusy, setGraphicBusy] = useState(false);
  const [graphicPreviewUrl, setGraphicPreviewUrl] = useState("");
  const [generatedGraphicFile, setGeneratedGraphicFile] = useState(null);
  const [graphicEditorOpen, setGraphicEditorOpen] = useState(false);
  const [graphicEditorText, setGraphicEditorText] = useState("");
  const [textAlignMode, setTextAlignMode] = useState("left"); // "left" | "center" | "right" | "justify"
  const [canvasElements, setCanvasElements] = useState([]);
  const [canvasMetrics, setCanvasMetrics] = useState(null);
  const [inlineEditor, setInlineEditor] = useState(null);
  const inputRef = useRef();
  const comunicadoCanvasRef = useRef(null);
  const generatedGraphicObjectUrlRef = useRef(null);
  const graphicEditorTextareaRef = useRef(null);
  const canvasPreviewWrapRef = useRef(null);
  const canvasTemplateRef = useRef(null);
  const dragStateRef = useRef({ activeId: null, pointerId: null, startX: 0, startY: 0, originX: 0, originY: 0, moved: false });
  const exportDebounceRef = useRef(null);

  useEffect(() => {
    return () => {
      if (generatedGraphicObjectUrlRef.current) {
        URL.revokeObjectURL(generatedGraphicObjectUrlRef.current);
      }
      if (exportDebounceRef.current) {
        clearTimeout(exportDebounceRef.current);
      }
    };
  }, []);

  const localDateInput = (offsetDays = 0) => {
    const d = new Date();
    d.setDate(d.getDate() + offsetDays);
    d.setMinutes(d.getMinutes() - d.getTimezoneOffset());
    return d.toISOString().slice(0, 10);
  };

  const localDateTimeInput = (offsetDays = 0, hhmm = "23:59") => `${localDateInput(offsetDays)}T${hhmm}`;

  const ensureFechaInicio = () => {
    if (!fechaInicio) setFechaInicio(localDateInput(0));
  };

  const plantillasAdmin = [
    {
      id: "tarifa",
      label: "Tarifa pública",
      titulo: "Tarifa pública actualizada",
      detalle: "Se comparte comunicado oficial con tarifa pública vigente para consulta de la comunidad portuaria.",
      duracionDias: 30
    },
    {
      id: "operativo",
      label: "Aviso operativo",
      titulo: "Aviso operativo importante",
      detalle: "Se informa a usuarios y operadores sobre actualización operativa. Favor de revisar el documento adjunto y tomar previsiones.",
      duracionDias: 7
    },
    {
      id: "mantenimiento",
      label: "Mantenimiento",
      titulo: "Mantenimiento programado",
      detalle: "Se informa mantenimiento programado. Considerar posibles ajustes operativos durante el periodo indicado.",
      duracionDias: 3
    },
    {
      id: "horario",
      label: "Horario especial",
      titulo: "Horario especial de atención",
      detalle: "Se comunica horario especial de atención. Revisar el archivo adjunto para mayor detalle.",
      duracionDias: 5
    },
    {
      id: "general",
      label: "Comunicado general",
      titulo: "Comunicado oficial",
      detalle: "Comunicado oficial para conocimiento de usuarios, operadores y comunidad logística.",
      duracionDias: 10
    }
  ];

  const aplicarPlantilla = (tpl) => {
    const inicio = localDateInput(0);
    setTitulo(tpl.titulo);
    setDetalle(tpl.detalle);
    setFechaInicio(inicio);
    const finPlantilla = localDateInput(tpl.duracionDias || 7);
    setFechaFin(finPlantilla);
    setFechaFinModo("fecha");
    setFechaFinHora(`${finPlantilla}T23:59`);
    setError("");
  };

  const onFileChange = (e) => {
    const f = e.target.files[0];
    if (!f) return;
    const allowed = ["image/jpeg", "image/png", "image/webp", "application/pdf"];
    if (!allowed.includes(f.type)) {
      setError("Solo se permiten JPG, PNG o PDF");
      return;
    }
    if (f.size > 10 * 1024 * 1024) {
      setError("El archivo no debe superar 10 MB");
      return;
    }
    setError("");
    setArchivo(f);
    setGeneratedGraphicFile(null);
    setGraphicPreviewUrl("");
    if (f.type !== "application/pdf") {
      const reader = new FileReader();
      reader.onload = (ev) => setPreview(ev.target.result);
      reader.readAsDataURL(f);
    } else {
      setPreview("pdf");
    }
  };

  const setToolNotice = (message, color = "#2563eb") => {
    setToolMsg({ message, color });
    setTimeout(() => setToolMsg(null), 3800);
  };

  const formatearFechaComunicado = (date = new Date()) => {
    const meses = ["enero", "febrero", "marzo", "abril", "mayo", "junio", "julio", "agosto", "septiembre", "octubre", "noviembre", "diciembre"];
    const day = String(date.getDate()).padStart(2, "0");
    const month = meses[date.getMonth()] || "";
    const year = date.getFullYear();
    return `${day} de ${month} del ${year}`;
  };

  const cargarImagenParaCanvas = (src) => new Promise((resolve, reject) => {
    const img = new Image();
    img.crossOrigin = "anonymous";
    img.onload = () => resolve(img);
    img.onerror = () => reject(new Error(`No se pudo cargar la imagen de plantilla: ${src}`));
    img.src = src;
  });

  const segmentarPalabraCanvas = (ctx, word, maxWidth) => {
    if (!word) return [""];
    if (ctx.measureText(word).width <= maxWidth) return [word];
    const partes = [];
    let actual = "";
    for (const char of word) {
      const candidato = `${actual}${char}`;
      if (actual && ctx.measureText(candidato).width > maxWidth) {
        partes.push(actual);
        actual = char;
      } else {
        actual = candidato;
      }
    }
    if (actual) partes.push(actual);
    return partes.length ? partes : [word];
  };

  // Canvas no genera saltos de línea automáticamente. Esta función mide cada palabra
  // y devuelve las líneas necesarias sin rebasar el ancho disponible.
  const wrapTextCanvas = (ctx, text, maxWidth) => {
    const paragraphs = String(text || "")
      .replace(/\r/g, "")
      .split("\n");

    const lines = [];

    paragraphs.forEach((paragraph, paragraphIndex) => {
      const cleanParagraph = paragraph.trim();

      if (!cleanParagraph) {
        if (paragraphIndex < paragraphs.length - 1) lines.push("");
        return;
      }

      const rawWords = cleanParagraph.split(/\s+/).filter(Boolean);
      const words = [];

      rawWords.forEach((word) => {
        const trozos = segmentarPalabraCanvas(ctx, word, maxWidth);
        trozos.forEach((trozo) => words.push(trozo));
      });

      let currentLine = "";
      words.forEach((word) => {
        const testLine = currentLine ? `${currentLine} ${word}` : word;
        if (currentLine && ctx.measureText(testLine).width > maxWidth) {
          lines.push(currentLine);
          currentLine = word;
        } else {
          currentLine = testLine;
        }
      });

      if (currentLine) lines.push(currentLine);
      if (paragraphIndex < paragraphs.length - 1) lines.push("");
    });

    return lines;
  };

  // Escribe texto multilínea en canvas respetando el textAlign actual solicitado
  // y retorna la nueva coordenada Y para continuar con el siguiente bloque,
  // evitando que los textos se encimen entre sí.
  const drawWrappedTextCanvas = ({
    ctx,
    text,
    x,
    y,
    maxWidth,
    lineHeight,
    textAlign = "left",
    fillStyle = "#0f172a",
    paragraphSpacing = 0,
  }) => {
    const lines = wrapTextCanvas(ctx, text, maxWidth);

    ctx.save();
    ctx.fillStyle = fillStyle;
    ctx.textAlign = textAlign;
    ctx.textBaseline = "top";

    let currentY = y;
    lines.forEach((line) => {
      if (!line) {
        currentY += paragraphSpacing || lineHeight;
        return;
      }
      ctx.fillText(line, x, currentY);
      currentY += lineHeight;
    });

    ctx.restore();
    return currentY;
  };

  const tokenizeRichText = (text) => {
    const source = String(text || "").replace(/\r/g, "");
    const regex = /\*\*(.+?)\*\*/g;

    const rawSegments = [];
    let lastIndex = 0;
    let match;

    while ((match = regex.exec(source)) !== null) {
      if (match.index > lastIndex) {
        rawSegments.push({
          text: source.slice(lastIndex, match.index),
          bold: false,
        });
      }

      rawSegments.push({
        text: match[1],
        bold: true,
      });

      lastIndex = regex.lastIndex;
    }

    if (lastIndex < source.length) {
      rawSegments.push({
        text: source.slice(lastIndex),
        bold: false,
      });
    }

    const tokens = [];

    rawSegments.forEach((segment) => {
      const parts = segment.text.split(/(\n|\s+)/).filter((part) => part !== "");

      parts.forEach((part) => {
        if (part === "\n") {
          tokens.push({ type: "newline" });
        } else if (/^\s+$/.test(part)) {
          tokens.push({
            type: "space",
            text: part,
            bold: segment.bold,
          });
        } else {
          tokens.push({
            type: "word",
            text: part,
            bold: segment.bold,
          });
        }
      });
    });

    return tokens;
  };

  const measureRichToken = (ctx, token, normalFont, boldFont) => {
    if (!token?.text) return 0;
    ctx.font = token.bold ? boldFont : normalFont;
    return ctx.measureText(token.text).width;
  };

  const splitRichWordIfNeeded = (ctx, token, maxWidth, normalFont, boldFont) => {
    if (!token?.text || token.type !== "word") return [token];

    ctx.font = token.bold ? boldFont : normalFont;
    if (ctx.measureText(token.text).width <= maxWidth) return [token];

    const chars = token.text.split("");
    const result = [];
    let current = "";

    chars.forEach((char) => {
      const candidate = current + char;
      ctx.font = token.bold ? boldFont : normalFont;

      if (current && ctx.measureText(candidate).width > maxWidth) {
        result.push({
          ...token,
          text: current,
        });
        current = char;
      } else {
        current = candidate;
      }
    });

    if (current) {
      result.push({
        ...token,
        text: current,
      });
    }

    return result;
  };

  // RICH TEXT CANVAS:
  // Interpreta **texto** como negritas, mide cada fragmento con su fuente real,
  // hace salto de línea manual y devuelve la nueva coordenada Y.
  const drawRichText = ({
    ctx,
    text,
    x,
    y,
    maxWidth,
    lineHeight,
    textAlign = "left",
    fillStyle = "#1f2937",
    normalFont = 'normal 20px "Noto Sans"',
    boldFont = 'bold 20px "Noto Sans"',
    paragraphSpacing = 0,
  }) => {
    const originalFont = ctx.font;
    const tokens = tokenizeRichText(text);

    const expandedTokens = [];
    tokens.forEach((token) => {
      if (token.type === "word") {
        const parts = splitRichWordIfNeeded(ctx, token, maxWidth, normalFont, boldFont);
        parts.forEach((part) => expandedTokens.push(part));
      } else {
        expandedTokens.push(token);
      }
    });

    const lines = [];
    let currentLine = [];
    let currentLineWidth = 0;

    const pushLine = (isParagraphBreak = false) => {
      // Limpia espacios finales para que la alineación no se vea desplazada.
      while (currentLine.length && currentLine[currentLine.length - 1]?.type === "space") {
        const removed = currentLine.pop();
        currentLineWidth -= measureRichToken(ctx, removed, normalFont, boldFont);
      }

      lines.push({
        tokens: currentLine,
        width: Math.max(0, currentLineWidth),
        isParagraphBreak,
      });

      currentLine = [];
      currentLineWidth = 0;
    };

    expandedTokens.forEach((token) => {
      if (token.type === "newline") {
        pushLine(true);
        return;
      }

      if (token.type === "space" && currentLine.length === 0) return;

      const tokenWidth = measureRichToken(ctx, token, normalFont, boldFont);
      const nextWidth = currentLineWidth + tokenWidth;

      if (token.type !== "space" && currentLine.length > 0 && nextWidth > maxWidth) {
        pushLine(false);
      }

      if (token.type === "space" && currentLine.length === 0) return;

      currentLine.push(token);
      currentLineWidth += tokenWidth;
    });

    if (currentLine.length > 0) {
      pushLine(false);
    }

    ctx.save();
    ctx.fillStyle = fillStyle;
    ctx.textBaseline = "top";

    let currentY = y;

    lines.forEach((line, lineIndex) => {
      if (line.isParagraphBreak && line.tokens.length === 0) {
        currentY += paragraphSpacing || lineHeight;
        return;
      }

      if (!line.tokens.length) {
        currentY += lineHeight;
        return;
      }

      const nextLine = lines[lineIndex + 1];
      const isLastLineOfText = lineIndex === lines.length - 1;
      const isLastLineBeforeParagraphBreak =
        nextLine?.isParagraphBreak === true && nextLine?.tokens?.length === 0;

      // Regla editorial: la última línea del texto o la última antes de salto
      // de párrafo nunca se justifica para evitar "ríos de blanco".
      const isLastEditorialLine =
        isLastLineOfText || isLastLineBeforeParagraphBreak || line.isParagraphBreak;

      const spaceTokens = line.tokens.filter((token) => token.type === "space");
      const MAX_EXTRA_SPACE_PER_GAP = 24;

      const extraSpacePerGap =
        spaceTokens.length > 0
          ? Math.max(0, (maxWidth - line.width) / spaceTokens.length)
          : 0;

      const canJustify =
        textAlign === "justify" &&
        !isLastEditorialLine &&
        spaceTokens.length > 0 &&
        extraSpacePerGap <= MAX_EXTRA_SPACE_PER_GAP;

      // Fallback editorial: si la justificación requiere espacios demasiado grandes,
      // esa línea se renderiza alineada a la izquierda.
      const effectiveAlign =
        textAlign === "justify"
          ? canJustify
            ? "justify"
            : "left"
          : textAlign;

      let startX = x;
      if (effectiveAlign === "center") {
        startX = x - (line.width / 2);
      } else if (effectiveAlign === "right") {
        startX = x - line.width;
      }

      let currentX = startX;

      line.tokens.forEach((token) => {
        if (!token?.text) return;

        ctx.font = token.bold ? boldFont : normalFont;
        ctx.fillText(token.text, currentX, currentY);

        currentX += ctx.measureText(token.text).width;

        if (canJustify && token.type === "space") {
          currentX += extraSpacePerGap;
        }
      });

      currentY += lineHeight;
    });

    ctx.restore();
    ctx.font = originalFont;

    return currentY;
  };

  // DRY RUN RICH TEXT:
  // Replica la lógica de drawRichText, pero no dibuja. Solo calcula altura total.
  // Sirve para autoescalar el cuerpo del comunicado antes del render final.
  const calculateRichTextHeight = ({
    ctx,
    text,
    maxWidth,
    lineHeight,
    normalFont = 'normal 20px "Noto Sans"',
    boldFont = 'bold 20px "Noto Sans"',
    paragraphSpacing = 0,
  }) => {
    const originalFont = ctx.font;
    const tokens = tokenizeRichText(text);

    const expandedTokens = [];
    tokens.forEach((token) => {
      if (token.type === "word") {
        const parts = splitRichWordIfNeeded(ctx, token, maxWidth, normalFont, boldFont);
        parts.forEach((part) => expandedTokens.push(part));
      } else {
        expandedTokens.push(token);
      }
    });

    const lines = [];
    let currentLine = [];
    let currentLineWidth = 0;

    const pushLine = (isParagraphBreak = false) => {
      while (currentLine.length && currentLine[currentLine.length - 1]?.type === "space") {
        const removed = currentLine.pop();
        currentLineWidth -= measureRichToken(ctx, removed, normalFont, boldFont);
      }

      lines.push({
        tokens: currentLine,
        width: Math.max(0, currentLineWidth),
        isParagraphBreak,
      });

      currentLine = [];
      currentLineWidth = 0;
    };

    expandedTokens.forEach((token) => {
      if (token.type === "newline") {
        pushLine(true);
        return;
      }

      if (token.type === "space" && currentLine.length === 0) return;

      const tokenWidth = measureRichToken(ctx, token, normalFont, boldFont);
      const nextWidth = currentLineWidth + tokenWidth;

      if (token.type !== "space" && currentLine.length > 0 && nextWidth > maxWidth) {
        pushLine(false);
      }

      if (token.type === "space" && currentLine.length === 0) return;

      currentLine.push(token);
      currentLineWidth += tokenWidth;
    });

    if (currentLine.length > 0) {
      pushLine(false);
    }

    let totalHeight = 0;

    lines.forEach((line) => {
      if (line.isParagraphBreak && line.tokens.length === 0) {
        totalHeight += paragraphSpacing || lineHeight;
        return;
      }

      totalHeight += lineHeight;
    });

    ctx.font = originalFont;

    return {
      height: totalHeight,
      linesCount: lines.length,
      lines,
    };
  };

  const agregarTextoExtraidoADetalle = (rawText) => {
    const cleanText = stripFileNamesFromOcrText(String(rawText || ""), archivo ? [archivo] : []);
    if (!cleanText.trim()) return false;
    setDetalle(prev => [prev, cleanText.trim()].filter(Boolean).join(prev?.trim() ? "\n\n" : ""));
    return true;
  };

  const procesarArchivoComunicado = async () => {
    if (!archivo) {
      setError("Selecciona un archivo para extraer texto");
      return;
    }
    setToolBusy(true);
    setError("");
    try {
      const localUrl = URL.createObjectURL(archivo);
      let extracted = "";
      try {
        if (archivo.type?.startsWith("image/")) {
          const r = await callMediaProcessor({ action: "image_ocr", sourceUrl: localUrl, fileType: archivo.type, title: titulo, bucketPath: "comunicados/ocr" });
          extracted = r?.text || "";
        } else if (archivo.type === "application/pdf") {
          const r = await callMediaProcessor({ action: "pdf_to_images_ocr", sourceUrl: localUrl, fileType: archivo.type, title: titulo, bucketPath: "comunicados/pdf" });
          extracted = r?.text || "";
        }
      } finally {
        setTimeout(() => URL.revokeObjectURL(localUrl), 1500);
      }

      const cleanExtracted = stripFileNamesFromOcrText(String(extracted || ""), archivo ? [archivo] : []);
      const ok = agregarTextoExtraidoADetalle(cleanExtracted);

      if (ok) {
        setToolNotice("Texto extraído. Generando título automático con IA...", "#2563eb");
        const tituloGenerado = await generarTituloDesdeTextoExtraido(cleanExtracted);
        if (tituloGenerado) {
          setTitulo(tituloGenerado);
          setToolNotice("Texto extraído y título generado automáticamente.", "#22c55e");
        } else {
          setToolNotice("Texto extraído y agregado en Descripción breve. No se pudo generar el título automático.", "#f97316");
        }
      } else {
        setToolNotice("No se detectó texto legible. Puedes escribir la descripción manualmente.", "#f97316");
      }
    } catch (e) {
      console.error(e);
      setToolNotice("No se pudo extraer texto. Intenta elegir una zona o escribe la descripción manualmente.", "#ef4444");
    } finally {
      setToolBusy(false);
    }
  };

  const aplicarTextoDeZonasComunicado = async ({ text }) => {
    const cleanText = String(text || "").trim();
    const ok = agregarTextoExtraidoADetalle(cleanText);

    if (ok) {
      setToolNotice("Texto de la zona agregado. Generando título automático con IA...", "#2563eb");
      const tituloGenerado = await generarTituloDesdeTextoExtraido(cleanText);
      if (tituloGenerado) {
        setTitulo(tituloGenerado);
        setToolNotice("Texto de la zona agregado y título generado automáticamente.", "#22c55e");
      } else {
        setToolNotice("Texto de la zona agregado en Descripción breve. No se pudo generar el título automático.", "#f97316");
      }
    } else {
      setToolNotice("No se detectó texto legible dentro de la zona seleccionada.", "#f97316");
    }
  };

  const extraerRespuestaIA = (data) => {
    if (!data) return "";
    if (typeof data === "string") return data;
    const directKeys = ["reply", "text", "message", "output", "content", "answer", "result", "response", "respuesta"];
    for (const key of directKeys) {
      const val = data?.[key];
      if (typeof val === "string" && val.trim()) return val;
      if (val && typeof val === "object") {
        const nested = extraerRespuestaIA(val);
        if (nested) return nested;
      }
    }
    const candidateText = data?.candidates?.[0]?.content?.parts?.map(p => p?.text || "").join(" ");
    if (candidateText?.trim()) return candidateText;
    const choiceText = data?.choices?.[0]?.message?.content || data?.choices?.[0]?.text;
    if (choiceText?.trim()) return choiceText;
    return "";
  };

  const getSupabaseSessionToken = async () => {
    try {
      const { data } = await sb.auth.getSession();
      return data?.session?.access_token || SUPA_KEY;
    } catch {
      return SUPA_KEY;
    }
  };

  const readFunctionErrorDetail = async (error) => {
    const baseMessage = error?.message || "Edge Function returned a non-2xx status code";
    const response = error?.context;
    if (!response || typeof response.text !== "function") return baseMessage;
    try {
      const raw = await response.text();
      if (!raw) return baseMessage;
      try {
        const json = JSON.parse(raw);
        return json?.error || json?.message || json?.details || raw;
      } catch {
        return raw;
      }
    } catch {
      return baseMessage;
    }
  };

  const invokeGeminiChatDirect = async (body) => {
    const token = await getSupabaseSessionToken();
    const response = await fetch(`${SUPA_URL}/functions/v1/gemini-chat`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "apikey": SUPA_KEY,
        "Authorization": `Bearer ${token || SUPA_KEY}`,
      },
      body: JSON.stringify(body),
    });
    const raw = await response.text();
    let payload = raw;
    try { payload = raw ? JSON.parse(raw) : {}; } catch {}
    if (!response.ok) {
      const msg = typeof payload === "string" ? payload : (payload?.error || payload?.message || payload?.details || raw);
      throw new Error(msg || `HTTP ${response.status}`);
    }
    return payload;
  };

  const callGeminiChatForComunicados = async ({ prompt, inputText, actionLabel }) => {
    // FALLBACK DE CONTRATO IA:
    // La captura muestra 5XX en gemini-chat. Para evitar que Comunicados dependa
    // de un único shape de body, probamos primero el contrato usado por el chat
    // global y después variantes frecuentes del backend IA (prompt/text/action).
    const payloads = [
      {
        message: prompt,
        history: [{ role: "user", content: prompt }],
        section: "comunicados",
        isAdmin: !!isAdmin,
      },
      {
        message: prompt,
        section: "comunicados",
        isAdmin: !!isAdmin,
      },
      {
        prompt,
        text: inputText,
        action: actionLabel,
        section: "comunicados",
        isAdmin: !!isAdmin,
      },
      {
        input_text: inputText,
        tipo: actionLabel,
        action: actionLabel,
        prompt,
        section: "comunicados",
      },
    ];

    const attempts = [];
    for (let i = 0; i < payloads.length; i += 1) {
      const body = payloads[i];
      try {
        const { data, error } = await sb.functions.invoke("gemini-chat", { body });
        if (error) throw error;
        const reply = extraerRespuestaIA(data);
        if (String(reply).trim()) return { data, reply: String(reply).trim(), attempt: `invoke-${i + 1}` };
        attempts.push(`invoke-${i + 1}: respuesta sin texto`);
      } catch (err) {
        attempts.push(`invoke-${i + 1}: ${await readFunctionErrorDetail(err)}`);
      }
    }

    // DIAGNÓSTICO DIRECTO:
    // fetch directo permite leer el cuerpo de error de Supabase, algo que
    // sb.functions.invoke suele ocultar detrás de "non-2xx status code".
    try {
      const data = await invokeGeminiChatDirect(payloads[0]);
      const reply = extraerRespuestaIA(data);
      if (String(reply).trim()) return { data, reply: String(reply).trim(), attempt: "direct-fetch" };
      attempts.push("direct-fetch: respuesta sin texto");
    } catch (err) {
      attempts.push(`direct-fetch: ${err?.message || err}`);
    }

    const detail = attempts.filter(Boolean).join(" | ").slice(0, 900);
    throw new Error(detail || "gemini-chat no devolvió una respuesta utilizable");
  };

  const respuestaIATituloInvalida = (value) => {
    const s = String(value || "").toLowerCase();
    return !s.trim() || /no\s+tengo\s+la\s+capacidad|b[uú]squedas?\s+en\s+tiempo\s+real|no\s+puedo\s+(acceder|realizar|buscar)|como\s+modelo\s+de\s+lenguaje|no\s+tengo\s+acceso\s+a\s+internet/i.test(s);
  };

  const limpiarTituloGeneradoIA = (value) => {
    const firstLine = String(value || "")
      .trim()
      .replace(/^["'“”‘’]+|["'“”‘’]+$/g, "")
      .replace(/^[-•*\s]+/, "")
      .replace(/^t[ií]tulo\s*:\s*/i, "")
      .split("\n")[0]
      .trim();

    if (respuestaIATituloInvalida(firstLine)) return "";

    const words = firstLine.split(/\s+/).filter(Boolean);
    const title = words.length <= 10 ? firstLine : words.slice(0, 10).join(" ");
    return title.replace(/[.,;:]+$/g, "").trim();
  };

  const generarTituloLocalDesdeTextoExtraido = (textoExtraido) => {
    const raw = String(textoExtraido || "")
      .replace(/https?:\/\/\S+/gi, " ")
      .replace(/#[\wÁÉÍÓÚÑáéíóúñ-]+/g, " ")
      .replace(/\s+/g, " ")
      .trim();

    if (!raw) return "";

    let title = "";

    if (/pospon(er|e|dr[aá]|iendo)|pospuesto|pospone/i.test(raw) && /conten(eriz|edor)/i.test(raw) && /exportaci[oó]n/i.test(raw)) {
      title = "Posponen envío de contenerizados de exportación";
    } else if (/mantenimiento/i.test(raw)) {
      title = "Aviso de mantenimiento operativo";
    } else if (/horario\s+especial|horario/i.test(raw)) {
      title = "Horario especial de atención";
    } else if (/tarifa/i.test(raw)) {
      title = "Tarifa pública actualizada";
    } else if (/comunicado/i.test(raw)) {
      title = "Comunicado operativo importante";
    } else if (/aviso/i.test(raw)) {
      title = "Aviso operativo importante";
    } else if (/zona\s+sur/i.test(raw) && /19:00|19\s*horas/i.test(raw)) {
      title = "Ajuste operativo para zona sur";
    } else {
      title = raw
        .replace(/^por\s+medio\s+del\s+presente\s*/i, "")
        .replace(/^(el\s+)?centro\s+de\s+control\s+de\s+tr[aá]fico\s+terrestre\s*\(?cctt\)?[,\s]*/i, "")
        .replace(/^solicita\s+(de\s+)?la\s+colaboraci[oó]n\s+para\s*/i, "")
        .replace(/^se\s+solicita\s*/i, "")
        .split(/[.\n]/)[0]
        .trim();
    }

    const words = title.split(/\s+/).filter(Boolean);
    return words.slice(0, 10).join(" ").replace(/[.,;:]+$/g, "").trim();
  };

  const generarTituloDesdeTextoExtraido = async (textoExtraido) => {
    const inputText = String(textoExtraido || "").trim();
    if (!inputText) return "";

    const prompt =
      "Genera un título para un comunicado operativo usando únicamente el texto proporcionado. " +
      "No hagas búsquedas en internet, no menciones limitaciones ni digas que no puedes buscar; esto no requiere información en tiempo real. " +
      "El título debe ser formal, descriptivo, directo y tener máximo 8 a 10 palabras. " +
      "Devuelve estrictamente solo el título, sin comillas, sin viñetas y sin texto introductorio.\n\n" +
      inputText;

    try {
      const { reply } = await callGeminiChatForComunicados({
        prompt,
        inputText,
        actionLabel: "titulo",
      });

      const aiTitle = limpiarTituloGeneradoIA(reply);
      if (aiTitle) return aiTitle;

      return generarTituloLocalDesdeTextoExtraido(inputText);
    } catch (err) {
      console.warn("No se pudo generar título automático desde OCR:", err);
      return generarTituloLocalDesdeTextoExtraido(inputText);
    }
  };

  const solicitarTextoConIA = async (requestedAction = aiAction) => {
    const inputText = detalle.trim();
    const actionLabel = requestedAction === "crear" ? "crear" : "resumir";
    setAiAction(actionLabel);
    if (!inputText) {
      setError("Escribe el texto o las especificaciones para usar la IA");
      return;
    }
    setAiBusy(true);
    setError("");
    setAiOutput("");
    try {
      const emphasisInstruction =
        "Revisa el texto final y encierra estrictamente entre dobles asteriscos ** los siguientes elementos para que se resalten en negritas: " +
        "fechas completas, horas (ej. **15:00 horas** o **15:00**), y palabras clave de alerta logística " +
        "(específicamente: **abstener**, **abstenerse**, **posponer traslados**, **hasta nuevo aviso**, **intermitencia**). " +
        "No uses asteriscos para nada más.";

      const prompt = actionLabel === "resumir"
        ? `Actúa como asistente de redacción de Conect Manzanillo. Resume el siguiente contenido para un comunicado operativo. Devuelve únicamente el texto final, claro, formal y breve. ${emphasisInstruction}\n\n${inputText}`
        : `Actúa como asistente de redacción de Conect Manzanillo. Crea un texto listo para comunicado operativo a partir de estas especificaciones. Devuelve únicamente el texto final, claro, formal y útil para usuarios del puerto. ${emphasisInstruction}\n\n${inputText}`;

      const { reply, attempt } = await callGeminiChatForComunicados({ prompt, inputText, actionLabel });
      setAiOutput(reply);
      setToolNotice(actionLabel === "resumir" ? `Resumen generado por IA (${attempt}).` : `Texto creado por IA (${attempt}).`, "#22c55e");
    } catch (e) {
      console.error("Error al solicitar asistencia IA para comunicados:", e);
      const msg = e?.message || "No se pudo conectar con la función de IA";
      setError(`No se pudo generar el texto con IA. Detalle: ${msg}`);
      setToolNotice("gemini-chat devolvió error. Revisa Logs en Supabase para ver el stack real de la Edge Function.", "#ef4444");
    } finally {
      setAiBusy(false);
    }
  };

  const aplicarResultadoIAADescripcion = () => {
    if (!aiOutput.trim()) return;
    setDetalle(aiOutput.trim());
    setToolNotice("Resultado de IA copiado en Descripción breve.", "#22c55e");
  };

  const aplicarCapturaWebRecortada = ({ file, dataUrl, url }) => {
    if (!isAdmin || !file) return;
    setArchivo(file);
    setPreview(dataUrl || null);
    if (!titulo.trim()) setTitulo("Captura web");
    if (url && !detalle.trim()) setDetalle(`Captura tomada desde: ${url}`);
    setToolNotice("Captura recortada lista. Puedes publicarla en Noticias.", "#22c55e");
  };

  const publicarArchivoEnNoticias = async () => {
    if (!isAdmin) return;
    if (!titulo.trim()) {
      setError("Escribe un título para publicar en Noticias");
      return;
    }
    if (!archivo) {
      setError("Selecciona un archivo para publicar en Noticias");
      return;
    }
    setToolBusy(true);
    setError("");
    try {
      const safeName = sanitizeStorageName(archivo.name);
      const pathNoticias = `noticias/${Date.now()}_${Math.random().toString(36).slice(2)}_${safeName}`;
      let publicUrl = "";
      let uploadError = null;

      const upNoticias = await sb.storage.from("noticias").upload(pathNoticias, archivo, { contentType: archivo.type, upsert: false });
      if (!upNoticias.error) {
        publicUrl = sb.storage.from("noticias").getPublicUrl(pathNoticias).data.publicUrl;
      } else {
        uploadError = upNoticias.error;
        const pathComunicados = `comunicados/noticias_${Date.now()}_${Math.random().toString(36).slice(2)}_${safeName}`;
        const upComunicados = await sb.storage.from("comunicados").upload(pathComunicados, archivo, { contentType: archivo.type, upsert: false });
        if (upComunicados.error) throw uploadError || upComunicados.error;
        publicUrl = sb.storage.from("comunicados").getPublicUrl(pathComunicados).data.publicUrl;
      }

      const payload = {
        tipo: "comunicado",
        titulo: titulo.trim(),
        detalle: detalle.trim() || "Comunicado oficial publicado por administración.",
        icono: "document",
        color: "#2563eb",
        origen: "comunicados",
        fecha_publicacion: new Date().toISOString().slice(0, 10),
        texto_extraido: detalle.trim() || null,
        media_urls: archivo.type?.startsWith("image/") ? [publicUrl] : [],
        pdf_urls: archivo.type === "application/pdf" ? [publicUrl] : [],
        archivo_url: publicUrl,
        archivo_tipo: archivo.type,
        ocultar_en_feed: false,
      };
      await insertNoticiaConFallback(payload);
      setToolNotice(uploadError ? "Publicado en Noticias usando el bucket comunicados." : "Publicado en Noticias.", "#22c55e");
    } catch (e) {
      console.error(e);
      setToolNotice("No se pudo publicar en Noticias. Revisa bucket/políticas de Supabase.", "#ef4444");
    } finally {
      setToolBusy(false);
    }
  };


  const ensureCanvasTemplate = async () => {
    if (canvasTemplateRef.current) return canvasTemplateRef.current;
    const template = await cargarImagenParaCanvas("/comunicado formato.jpg");
    canvasTemplateRef.current = template;
    return template;
  };

  const buildCanvasElementsState = async ({
    bodyText,
    titleText,
    alignMode = textAlignMode,
    preservePositions = true,
  }) => {
    const cleanBodyText = String(bodyText || "").trim();
    const cleanTitleText = String(titleText || "").trim();

    if (!cleanBodyText) {
      throw new Error("Primero extrae o escribe el texto del comunicado antes de crear el formato.");
    }

    if (!cleanTitleText) {
      throw new Error("Primero genera o escribe el título del comunicado.");
    }

    if (document?.fonts?.load) {
      await Promise.all([
        document.fonts.load('400 20px "Noto Sans"'),
        document.fonts.load('700 24px "Noto Sans"'),
        document.fonts.load('700 22px "Noto Sans"'),
      ]);
    }

    const template = await ensureCanvasTemplate();
    const canvas = comunicadoCanvasRef.current || document.createElement("canvas");
    const width = template.naturalWidth || template.width || 1024;
    const height = template.naturalHeight || template.height || 1448;
    canvas.width = width;
    canvas.height = height;

    const ctx = canvas.getContext("2d");
    if (!ctx) throw new Error("No fue posible obtener el contexto 2D del canvas.");

    const scale = width / 1024;
    const leftMargin = 80 * scale;
    const rightMargin = 80 * scale;
    const rightX = width - rightMargin;
    const centerX = width / 2;
    const bodyMaxWidth = width - (leftMargin * 2);
    const corporateBlue = "#113f79";
    const textDark = "#1f2937";

    const dateFontSize = Math.round(20 * scale);
    const titleFontSize = Math.round(24 * scale);
    const headerFontSize = Math.round(22 * scale);

    const dateLineHeight = Math.round(dateFontSize * 1.3);
    const titleLineHeight = Math.round(titleFontSize * 1.28);
    const headerLineHeight = Math.round(headerFontSize * 1.25);

    const dateText = formatearFechaComunicado(new Date());
    const dateMaxWidth = width * 0.30;
    ctx.font = `normal ${dateFontSize}px "Noto Sans"`;
    const dateLines = wrapTextCanvas(ctx, dateText, dateMaxWidth);
    const dateHeight = Math.max(dateLineHeight, dateLines.length * dateLineHeight);
    const dateY = 265 * scale;
    const dateX = rightX - dateMaxWidth;

    const titleMaxWidth = width * 0.42;
    ctx.font = `bold ${titleFontSize}px "Noto Sans"`;
    const titleLines = wrapTextCanvas(ctx, cleanTitleText, titleMaxWidth);
    const titleHeight = Math.max(titleLineHeight, titleLines.length * titleLineHeight);
    const titleY = dateY + dateHeight + (36 * scale);
    const titleX = rightX - titleMaxWidth;

    const headerText = "CONECT MANZANILLO INFORMA:";
    ctx.font = `bold ${headerFontSize}px "Noto Sans"`;
    const headerLines = wrapTextCanvas(ctx, headerText, width * 0.70);
    const headerHeight = Math.max(headerLineHeight, headerLines.length * headerLineHeight);
    const headerY = titleY + titleHeight + (60 * scale);

    const bodyYStart = headerY + headerHeight + (50 * scale);
    const bodyYEnd = height - (170 * scale);
    const availableHeight = Math.max(120 * scale, bodyYEnd - bodyYStart);

    // Autoescalado más agresivo para textos cortos.
    const maxBodyFontSize = Math.round(40 * scale);
    const minBodyFontSize = Math.round(20 * scale);
    const paragraphSpacingFactor = 0.65;

    let selectedBodyFontSize = maxBodyFontSize;
    let selectedBodyLineHeight = Math.round(selectedBodyFontSize * 1.5);
    let selectedParagraphSpacing = Math.round(selectedBodyLineHeight * paragraphSpacingFactor);
    let selectedBodyHeight = 0;

    for (let testFontSize = maxBodyFontSize; testFontSize >= minBodyFontSize; testFontSize -= 1) {
      const testLineHeight = Math.round(testFontSize * 1.5);
      const testParagraphSpacing = Math.round(testLineHeight * paragraphSpacingFactor);
      const testNormalFont = `normal ${testFontSize}px "Noto Sans"`;
      const testBoldFont = `bold ${testFontSize}px "Noto Sans"`;

      const measured = calculateRichTextHeight({
        ctx,
        text: cleanBodyText,
        maxWidth: bodyMaxWidth,
        lineHeight: testLineHeight,
        normalFont: testNormalFont,
        boldFont: testBoldFont,
        paragraphSpacing: testParagraphSpacing,
      });

      if (measured.height <= availableHeight || testFontSize === minBodyFontSize) {
        selectedBodyFontSize = testFontSize;
        selectedBodyLineHeight = testLineHeight;
        selectedParagraphSpacing = testParagraphSpacing;
        selectedBodyHeight = measured.height;
        break;
      }
    }

    const safeAlignMode = ["left", "center", "right", "justify"].includes(alignMode)
      ? alignMode
      : "left";

    const verticalExtraSpace = Math.max(0, availableHeight - selectedBodyHeight);
    const bodyRenderY = bodyYStart + (verticalExtraSpace / 2);
    const bodyX = safeAlignMode === "center"
      ? centerX - (bodyMaxWidth / 2)
      : safeAlignMode === "right"
        ? width - rightMargin - bodyMaxWidth
        : leftMargin;

    const previousById = new Map((preservePositions ? canvasElements : []).map((item) => [item.id, item]));
    const withPreviousPosition = (element, fallbackX, fallbackY) => {
      const previous = previousById.get(element.id);
      if (!previous) return { ...element, x: fallbackX, y: fallbackY };
      return { ...element, x: previous.x, y: previous.y };
    };

    const elements = [
      withPreviousPosition({
        id: "date",
        type: "date",
        text: dateText,
        x: dateX,
        y: dateY,
        width: dateMaxWidth,
        height: dateHeight,
        maxWidth: dateMaxWidth,
        fontSize: dateFontSize,
        fontFamily: '"Noto Sans"',
        fontWeight: 400,
        lineHeight: dateLineHeight,
        fillStyle: textDark,
        textAlign: "right",
      }, dateX, dateY),
      withPreviousPosition({
        id: "title",
        type: "title",
        text: cleanTitleText,
        x: titleX,
        y: titleY,
        width: titleMaxWidth,
        height: titleHeight,
        maxWidth: titleMaxWidth,
        fontSize: titleFontSize,
        fontFamily: '"Noto Sans"',
        fontWeight: 700,
        lineHeight: titleLineHeight,
        fillStyle: "#111827",
        textAlign: "right",
      }, titleX, titleY),
      withPreviousPosition({
        id: "body",
        type: "body",
        text: cleanBodyText,
        x: bodyX,
        y: bodyRenderY,
        width: bodyMaxWidth,
        height: selectedBodyHeight,
        maxWidth: bodyMaxWidth,
        fontSize: selectedBodyFontSize,
        fontFamily: '"Noto Sans"',
        fontWeight: 400,
        lineHeight: selectedBodyLineHeight,
        paragraphSpacing: selectedParagraphSpacing,
        fillStyle: textDark,
        textAlign: safeAlignMode,
      }, bodyX, bodyRenderY),
    ];

    const metrics = {
      width,
      height,
      scale,
      leftMargin,
      rightMargin,
      centerX,
      rightX,
      bodyMaxWidth,
      corporateBlue,
      textDark,
      headerText,
      headerY,
      headerHeight,
      headerMaxWidth: width * 0.70,
      headerLineHeight,
      template,
    };

    return { elements, metrics };
  };

  const drawCanvasElement = ({ ctx, element }) => {
    if (!element) return;

    if (element.type === "body") {
      const drawX = element.textAlign === "center"
        ? element.x + (element.width / 2)
        : element.textAlign === "right"
          ? element.x + element.width
          : element.x;

      drawRichText({
        ctx,
        text: element.text,
        x: drawX,
        y: element.y,
        maxWidth: element.maxWidth || element.width,
        lineHeight: element.lineHeight,
        textAlign: element.textAlign || "left",
        fillStyle: element.fillStyle || "#1f2937",
        normalFont: `normal ${element.fontSize}px ${element.fontFamily || '"Noto Sans"'}`,
        boldFont: `bold ${element.fontSize}px ${element.fontFamily || '"Noto Sans"'}`,
        paragraphSpacing: element.paragraphSpacing || Math.round(element.lineHeight * 0.65),
      });
      return;
    }

    const drawX = element.textAlign === "right"
      ? element.x + element.width
      : element.textAlign === "center"
        ? element.x + (element.width / 2)
        : element.x;

    drawWrappedTextCanvas({
      ctx,
      text: element.text,
      x: drawX,
      y: element.y,
      maxWidth: element.maxWidth || element.width,
      lineHeight: element.lineHeight,
      textAlign: element.textAlign || "left",
      fillStyle: element.fillStyle || "#0f172a",
    });
  };

  const renderCanvasScene = async ({
    elements = canvasElements,
    metrics = canvasMetrics,
    skipElementId = inlineEditor?.elementId || null,
  } = {}) => {
    if (!elements?.length || !metrics) return;

    const template = metrics.template || await ensureCanvasTemplate();
    const canvas = comunicadoCanvasRef.current;
    if (!canvas) return;

    canvas.width = metrics.width;
    canvas.height = metrics.height;

    const ctx = canvas.getContext("2d");
    if (!ctx) return;

    ctx.clearRect(0, 0, metrics.width, metrics.height);
    ctx.drawImage(template, 0, 0, metrics.width, metrics.height);

    ctx.font = `bold ${Math.round(22 * metrics.scale)}px "Noto Sans"`;
    drawWrappedTextCanvas({
      ctx,
      text: metrics.headerText,
      x: metrics.centerX,
      y: metrics.headerY,
      maxWidth: metrics.headerMaxWidth,
      lineHeight: metrics.headerLineHeight,
      textAlign: "center",
      fillStyle: metrics.corporateBlue,
    });

    elements.forEach((element) => {
      if (skipElementId && element.id === skipElementId) return;
      drawCanvasElement({ ctx, element });
    });
  };

  const exportCanvasToGraphic = async ({ silent = true } = {}) => {
    const canvas = comunicadoCanvasRef.current;
    if (!canvas) return null;

    const blob = await new Promise((resolve, reject) => {
      canvas.toBlob((result) => {
        if (result) resolve(result);
        else reject(new Error("No se pudo exportar el canvas a imagen JPEG."));
      }, "image/jpeg", 0.95);
    });

    if (generatedGraphicObjectUrlRef.current) {
      URL.revokeObjectURL(generatedGraphicObjectUrlRef.current);
    }

    const objectUrl = URL.createObjectURL(blob);
    generatedGraphicObjectUrlRef.current = objectUrl;
    setGraphicPreviewUrl(objectUrl);

    const titleElement = canvasElements.find((item) => item.id === "title");
    const safeTitle = String(titleElement?.text || titulo || "comunicado")
      .normalize("NFD")
      .replace(/[\u0300-\u036f]/g, "")
      .replace(/[^a-zA-Z0-9]+/g, "_")
      .replace(/^_+|_+$/g, "")
      .toLowerCase();

    const generatedFile = new File([blob], `${safeTitle || "comunicado"}_formato.jpg`, { type: "image/jpeg" });
    setGeneratedGraphicFile(generatedFile);

    if (!silent) {
      setToolNotice("Comunicado gráfico generado correctamente. Ya puedes descargarlo o adjuntarlo.", "#22c55e");
    }

    return { objectUrl, file: generatedFile };
  };

  const getCanvasPointerPosition = (event) => {
    const canvas = comunicadoCanvasRef.current;
    if (!canvas) return { x: 0, y: 0 };
    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;
    return {
      x: (event.clientX - rect.left) * scaleX,
      y: (event.clientY - rect.top) * scaleY,
    };
  };

  const getHitCanvasElement = (x, y) => {
    const ordered = [...canvasElements].reverse();
    return ordered.find((element) => (
      x >= element.x && x <= element.x + element.width && y >= element.y && y <= element.y + element.height
    )) || null;
  };

  const openInlineEditorForElement = (element) => {
    if (!element) return;
    setInlineEditor({
      elementId: element.id,
      value: element.text,
      multiline: element.type === "body",
    });
  };

  const commitInlineEditor = async () => {
    if (!inlineEditor?.elementId) {
      setInlineEditor(null);
      return;
    }

    const nextValue = String(inlineEditor.value || "").trim();
    const elementId = inlineEditor.elementId;
    const nextTitle = elementId === "title"
      ? nextValue
      : (canvasElements.find((item) => item.id === "title")?.text || titulo || "");
    const nextBody = elementId === "body"
      ? nextValue
      : (canvasElements.find((item) => item.id === "body")?.text || detalle || "");

    setInlineEditor(null);

    if (elementId === "title") setTitulo(nextTitle);
    if (elementId === "body") {
      setDetalle(nextBody);
      setGraphicEditorText(nextBody);
    }

    if (elementId === "date") {
      setCanvasElements((prev) => prev.map((item) => item.id === elementId ? { ...item, text: nextValue || item.text } : item));
      return;
    }

    try {
      await renderComunicadoCanvas({
        bodyText: nextBody,
        titleText: nextTitle,
        alignMode: textAlignMode,
        silent: true,
        preservePositions: true,
      });
    } catch (e) {
      console.error('No se pudo aplicar la edición in-situ:', e);
      setCanvasElements((prev) => prev.map((item) => item.id === elementId ? { ...item, text: nextValue || item.text } : item));
    }
  };

  const syncBodyAlignment = (alignMode) => {
    setCanvasElements((prev) => prev.map((element) => {
      if (element.id !== "body") return element;
      if (!canvasMetrics) return { ...element, textAlign: alignMode };

      const safeAlignMode = ["left", "center", "right", "justify"].includes(alignMode) ? alignMode : "left";
      const nextX = safeAlignMode === "center"
        ? canvasMetrics.centerX - (element.width / 2)
        : safeAlignMode === "right"
          ? canvasMetrics.width - canvasMetrics.rightMargin - element.width
          : canvasMetrics.leftMargin;

      return {
        ...element,
        x: nextX,
        textAlign: safeAlignMode,
      };
    }));
  };

  const handleCanvasPointerDown = (event) => {
    if (!canvasElements.length) return;
    const point = getCanvasPointerPosition(event);
    const hit = getHitCanvasElement(point.x, point.y);
    if (!hit) return;

    setInlineEditor(null);

    dragStateRef.current = {
      activeId: hit.id,
      pointerId: event.pointerId,
      startX: point.x,
      startY: point.y,
      originX: hit.x,
      originY: hit.y,
      moved: false,
    };

    try {
      event.currentTarget.setPointerCapture?.(event.pointerId);
    } catch (_) {}
  };

  const handleCanvasPointerMove = (event) => {
    const drag = dragStateRef.current;
    if (!drag?.activeId) return;

    const point = getCanvasPointerPosition(event);
    const dx = point.x - drag.startX;
    const dy = point.y - drag.startY;

    if (Math.abs(dx) > 2 || Math.abs(dy) > 2) {
      drag.moved = true;
    }

    setCanvasElements((prev) => prev.map((element) => {
      if (element.id !== drag.activeId) return element;
      return {
        ...element,
        x: drag.originX + dx,
        y: drag.originY + dy,
      };
    }));
  };

  const handleCanvasPointerUp = async (event) => {
    const drag = dragStateRef.current;
    if (!drag?.activeId) return;

    const point = getCanvasPointerPosition(event);
    const hit = getHitCanvasElement(point.x, point.y);
    const activeElement = canvasElements.find((item) => item.id === drag.activeId) || hit;
    const shouldOpenEditor = !drag.moved && activeElement;

    dragStateRef.current = { activeId: null, pointerId: null, startX: 0, startY: 0, originX: 0, originY: 0, moved: false };

    try {
      event.currentTarget.releasePointerCapture?.(event.pointerId);
    } catch (_) {}

    if (shouldOpenEditor) {
      openInlineEditorForElement(activeElement);
      return;
    }

    try {
      await exportCanvasToGraphic({ silent: true });
    } catch (e) {
      console.error('No se pudo exportar tras el arrastre:', e);
    }
  };

  const getInlineEditorStyle = () => {
    if (!inlineEditor?.elementId) return null;
    const element = canvasElements.find((item) => item.id === inlineEditor.elementId);
    const canvas = comunicadoCanvasRef.current;
    const wrapper = canvasPreviewWrapRef.current;
    if (!element || !canvas || !wrapper) return null;

    const canvasRect = canvas.getBoundingClientRect();
    const wrapperRect = wrapper.getBoundingClientRect();
    const scaleX = canvasRect.width / canvas.width;
    const scaleY = canvasRect.height / canvas.height;

    return {
      position: 'absolute',
      left: (canvasRect.left - wrapperRect.left) + (element.x * scaleX),
      top: (canvasRect.top - wrapperRect.top) + (element.y * scaleY),
      width: Math.max(120, element.width * scaleX),
      minHeight: Math.max(34, element.height * scaleY),
      padding: '6px 8px',
      background: 'rgba(255,255,255,.92)',
      color: '#0f172a',
      border: '1px dashed rgba(236,72,153,.65)',
      borderRadius: '8px',
      outline: 'none',
      boxSizing: 'border-box',
      resize: inlineEditor?.multiline ? 'vertical' : 'none',
      fontFamily: '"Noto Sans", sans-serif',
      fontSize: `${Math.max(12, element.fontSize * scaleY)}px`,
      lineHeight: 1.35,
      zIndex: 3,
    };
  };

  const copiarTextoComunicadoGrafico = async () => {
    const dateElement = canvasElements.find((item) => item.id === "date");
    const titleElement = canvasElements.find((item) => item.id === "title");
    const bodyElement = canvasElements.find((item) => item.id === "body");

    const finalText = [
      dateElement?.text || formatearFechaComunicado(new Date()),
      titleElement?.text || titulo,
      "CONECT MANZANILLO INFORMA:",
      bodyElement?.text || graphicEditorText || detalle,
    ]
      .map((part) => String(part || "").replace(/\*\*/g, "").trim())
      .filter(Boolean)
      .join("\n\n");

    try {
      await navigator.clipboard.writeText(finalText);
      setToolNotice("Texto copiado", "#22c55e");
    } catch (e) {
      console.error("No se pudo copiar el texto:", e);
      setToolNotice("No se pudo copiar automáticamente. Selecciona el texto manualmente.", "#ef4444");
    }
  };

  const descargarComunicadoGenerado = () => {
    if (!graphicPreviewUrl) return;
    const safeTitle = (titulo || "comunicado")
      .normalize("NFD")
      .replace(/[̀-ͯ]/g, "")
      .replace(/[^a-zA-Z0-9]+/g, "_")
      .replace(/^_+|_+$/g, "")
      .toLowerCase();

    const a = document.createElement("a");
    a.href = graphicPreviewUrl;
    a.download = `${safeTitle || "comunicado"}_formato.jpg`;
    document.body.appendChild(a);
    a.click();
    a.remove();
  };

  const adjuntarComunicadoGenerado = () => {
    if (!generatedGraphicFile || !graphicPreviewUrl) return;
    setArchivo(generatedGraphicFile);
    setPreview(graphicPreviewUrl);
    if (inputRef.current) inputRef.current.value = "";
    setToolNotice("La imagen generada se adjuntó automáticamente al comunicado actual.", "#22c55e");
  };

  const renderComunicadoCanvas = async ({
    bodyText,
    titleText,
    alignMode = textAlignMode,
    silent = false,
    preservePositions = true,
  }) => {
    const { elements, metrics } = await buildCanvasElementsState({
      bodyText,
      titleText,
      alignMode,
      preservePositions,
    });

    setCanvasMetrics(metrics);
    setCanvasElements(elements);

    if (!silent) {
      setToolNotice("Comunicado gráfico generado correctamente. Ya puedes arrastrar, editar o descargar.", "#22c55e");
    }

    return { elements, metrics };
  };

  const aplicarNegritasEditor = () => {
    const textarea = graphicEditorTextareaRef.current;
    if (!textarea) return;

    const start = textarea.selectionStart ?? 0;
    const end = textarea.selectionEnd ?? 0;
    const currentText = graphicEditorText || "";
    if (start === end) return;

    const selectedText = currentText.slice(start, end);
    const wrappedText =
      selectedText.startsWith("**") && selectedText.endsWith("**")
        ? selectedText
        : `**${selectedText}**`;

    const nextText = currentText.slice(0, start) + wrappedText + currentText.slice(end);
    setGraphicEditorText(nextText);

    setTimeout(() => {
      textarea.focus();
      textarea.setSelectionRange(start, start + wrappedText.length);
    }, 0);
  };

  const abrirEditorComunicadoGrafico = () => {
    const bodyElement = canvasElements.find((item) => item.id === "body");
    setGraphicEditorText(String(bodyElement?.text || detalle || "").trim());
    setGraphicEditorOpen(true);
  };

  const aplicarEdicionComunicadoGrafico = async () => {
    const nextText = String(graphicEditorText || "").trim();
    setDetalle(nextText);
    setGraphicEditorOpen(false);

    try {
      setGraphicBusy(true);
      await renderComunicadoCanvas({
        bodyText: nextText,
        titleText: titulo,
        alignMode: textAlignMode,
        silent: false,
        preservePositions: true,
      });
    } catch (e) {
      console.error("Error al aplicar edición del comunicado gráfico:", e);
      setToolNotice(`No se pudo aplicar la edición: ${e?.message || e}`, "#ef4444");
    } finally {
      setGraphicBusy(false);
    }
  };

  const crearComunicadoPorFormato = async () => {
    if (!isAdmin) return;

    const bodyText = String(detalle || "").trim();
    const titleText = String(titulo || "").trim();

    if (!bodyText) {
      setError("Primero extrae o escribe el texto del comunicado antes de crear el formato.");
      return;
    }

    if (!titleText) {
      setError("Primero genera o escribe el título del comunicado.");
      return;
    }

    setGraphicBusy(true);
    setError("");
    setGraphicEditorText(bodyText);

    try {
      await renderComunicadoCanvas({
        bodyText,
        titleText,
        alignMode: textAlignMode,
        silent: false,
        preservePositions: false,
      });
    } catch (e) {
      console.error("Error al crear comunicado por formato:", e);
      setToolNotice(`No se pudo generar el comunicado gráfico: ${e?.message || e}`, "#ef4444");
    } finally {
      setGraphicBusy(false);
    }
  };

  useEffect(() => {
    if (!graphicEditorOpen || !isAdmin || !titulo.trim()) return;

    const nextText = String(graphicEditorText || "").trim();
    if (!nextText) return;

    const debounceId = setTimeout(() => {
      renderComunicadoCanvas({
        bodyText: nextText,
        titleText: titulo,
        alignMode: textAlignMode,
        silent: true,
        preservePositions: true,
      }).catch((e) => {
        console.error("Error actualizando vista previa en vivo:", e);
      });
    }, 280);

    return () => clearTimeout(debounceId);
  }, [graphicEditorOpen, graphicEditorText, textAlignMode, titulo, isAdmin]);



  useEffect(() => {
    if (!canvasElements.length || !canvasMetrics) return;

    renderCanvasScene({
      elements: canvasElements,
      metrics: canvasMetrics,
      skipElementId: inlineEditor?.elementId || null,
    }).catch((e) => {
      console.error("Error redibujando el canvas:", e);
    });

    if (exportDebounceRef.current) clearTimeout(exportDebounceRef.current);
    exportDebounceRef.current = setTimeout(() => {
      exportCanvasToGraphic({ silent: true }).catch((e) => console.error("Error exportando la vista previa:", e));
    }, 180);

    return () => {
      if (exportDebounceRef.current) clearTimeout(exportDebounceRef.current);
    };
  }, [canvasElements, canvasMetrics, inlineEditor?.elementId]);

  useEffect(() => {
    syncBodyAlignment(textAlignMode);
  }, [textAlignMode]);

  const handleSubir = async () => {
    if (!titulo.trim()) {
      setError("Escribe un título para el comunicado");
      return;
    }
    if (!archivo) {
      setError("Selecciona un archivo");
      return;
    }
    if (!fechaInicio) {
      setError("Especifica la fecha de inicio");
      return;
    }
    if (!fechaFin) {
      setError("Especifica la fecha de término");
      return;
    }

    if (fechaFinModo === "fecha_hora" && !fechaFinHora) {
      setError("Especifica la fecha y hora de término");
      return;
    }

    // Vigencia flexible:
    // Inicio: 00:00:00 del día seleccionado.
    // Fin modalidad "solo fecha": 23:59:59 del día seleccionado.
    // Fin modalidad "fecha y hora": hora exacta seleccionada por el usuario.
    const inicioDate = new Date(`${fechaInicio}T00:00:00`);
    const finDate = fechaFinModo === "fecha_hora"
      ? new Date(fechaFinHora)
      : new Date(`${fechaFin}T23:59:59.999`);

    if (isNaN(inicioDate.getTime()) || isNaN(finDate.getTime())) {
      setError("Las fechas ingresadas no son válidas");
      return;
    }

    const inicio = inicioDate.toISOString();
    const fin = finDate.toISOString();

    if (finDate < inicioDate) {
      setError("La fecha de término debe ser igual o posterior a la fecha de inicio");
      return;
    }

    setSubiendo(true);
    setError("");
    try {
      const ext = archivo.name.split(".").pop();
      const path = `comunicados/${Date.now()}_${Math.random().toString(36).slice(2)}.${ext}`;
      const { error: upErr } = await sb.storage
        .from("comunicados")
        .upload(path, archivo, { contentType: archivo.type, upsert: false });
      if (upErr) throw upErr;
      const { data: { publicUrl } } = sb.storage.from("comunicados").getPublicUrl(path);
      
      const { data: comunicadoInsertado, error: insErr } = await sb.from("comunicados").insert({
        titulo: titulo.trim(),
        detalle: detalle.trim() || null,
        archivo_url: publicUrl,
        archivo_tipo: archivo.type,
        fecha_inicio: inicio,
        fecha_fin: fin,
        aprobado: isAdmin === true,
        created_at: new Date().toISOString()
      }).select("*").single();
      if (insErr) throw insErr;

      // Si lo publica un admin, ya está aprobado y se replica automáticamente a Noticias.
      if (isAdmin === true && comunicadoInsertado) {
        try {
          await syncComunicadoToNoticia(comunicadoInsertado, { processMedia: false });
          setToolNotice("Comunicado publicado y replicado en Noticias.", "#22c55e");
        } catch (syncErr) {
          console.error("No se pudo replicar el comunicado en Noticias:", syncErr);
          setToolNotice("Comunicado publicado, pero no se pudo replicar en Noticias. Revisa permisos INSERT/RLS de la tabla noticias.", "#ef4444");
        }
      }

      setExito(true);
      setTitulo("");
      setDetalle("");
      setArchivo(null);
      setPreview(null);
      setGeneratedGraphicFile(null);
      setGraphicPreviewUrl("");
      setFechaInicio("");
      setFechaFin("");
      setFechaFinModo("fecha");
      setFechaFinHora("");
      if (inputRef.current) inputRef.current.value = "";
      setTimeout(() => setExito(false), 3000);
      if (onSubido) onSubido();
    } catch (err) {
      setError("Error al subir: " + (err.message || "Intenta de nuevo"));
    }
    setSubiendo(false);
  };

  const comunicadoInputStyle = { width: "100%", background: "#010f1f", border: "1px solid #2c3a4c", borderRadius: "8px", padding: "13px 14px", color: "#ffffff", fontFamily: getFont(theme, "secondary"), fontSize: "12px", marginBottom: "12px", boxSizing: "border-box", outline: "none", transition: "border-color .2s, box-shadow .2s" };
  const comunicadoTextareaStyle = (active = false) => ({ width: "100%", background: "#010f1f", border: active ? "1px solid rgba(0,150,255,.55)" : "1px solid #2c3a4c", borderRadius: "8px", padding: "13px 14px", color: "#ffffff", fontFamily: getFont(theme, "secondary"), fontSize: "12px", marginBottom: "12px", boxSizing: "border-box", outline: "none", resize: "vertical", lineHeight: "1.55", minHeight: active ? "124px" : "90px", transition: "border-color .2s, box-shadow .2s" });
  const comunicadoLabelStyle = { display: "block", fontSize: "11px", color: "rgba(148,163,184,.86)", fontFamily: getFont(theme, "secondary"), marginBottom: "7px", letterSpacing: ".04em", fontWeight: 700 };
  const comunicadoToolButtonStyle = (accent, disabled = false) => ({ padding:"12px", borderRadius:"8px", border:`1px solid ${accent}66`, background: disabled ? "rgba(44,58,76,.18)" : "rgba(44,58,76,.30)", color: disabled ? "rgba(148,163,184,.62)" : accent, fontFamily:getFont(theme,"secondary"), fontSize:"11px", fontWeight:800, cursor:disabled?"not-allowed":"pointer", display:"flex", alignItems:"center", justifyContent:"center", gap:"8px", transition:"all .2s" });

  return (
    <div style={{ background: "rgba(18,33,49,0.72)", backdropFilter:"blur(12px)", WebkitBackdropFilter:"blur(12px)", border: "1px solid #2c3a4c", borderRadius: "8px", padding: "24px", marginBottom: "16px", boxShadow:"0 18px 44px rgba(0,0,0,.24), inset 0 1px 0 rgba(255,255,255,.04)" }}>
      <div style={{ display: "flex", alignItems: "center", gap: "12px", paddingBottom:"14px", marginBottom: "22px", borderBottom:"1px solid #2c3a4c" }}>
        <span style={{ display:"inline-flex", alignItems:"center", justifyContent:"center", width:"32px", height:"32px", borderRadius:"8px", color:"#f59e0b", background:"rgba(245,158,11,.10)", border:"1px solid rgba(245,158,11,.25)" }}>
          <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m21.44 11.05-9.19 9.19a6 6 0 0 1-8.49-8.49l8.57-8.57A4 4 0 1 1 18 8.84l-8.59 8.51a2 2 0 0 1-2.83-2.83l8.49-8.48"/></svg>
        </span>
        <span style={{ fontFamily: getFont(theme, "secondary"), fontWeight: "800", fontSize: "12px", letterSpacing: "1.5px", color: "#f59e0b", textTransform:"uppercase" }}>
          {isAdmin ? "Subir comunicado (Admin)" : "Proponer comunicado"}
        </span>
      </div>

      {isAdmin && (
        <div style={{ background: "rgba(56,189,248,0.06)", border: "1px solid rgba(56,189,248,0.20)", borderRadius: "12px", padding: "12px", marginBottom: "12px" }}>
          <div style={{ fontFamily: getFont(theme, "secondary"), fontSize: "10px", color: "#7dd3fc", fontWeight: "700", letterSpacing: "1px", marginBottom: "8px" }}>
            PLANTILLAS RÁPIDAS
          </div>
          <div style={{ display: "flex", gap: "7px", flexWrap: "wrap" }}>
            {plantillasAdmin.map(tpl => (
              <button
                key={tpl.id}
                type="button"
                onClick={() => aplicarPlantilla(tpl)}
                style={{ padding: "7px 9px", borderRadius: "999px", border: "1px solid rgba(56,189,248,0.35)", background: "rgba(56,189,248,0.12)", color: "#bae6fd", fontFamily: getFont(theme, "secondary"), fontSize: "10px", fontWeight: "700", cursor: "pointer" }}
              >
                {tpl.label}
              </button>
            ))}
          </div>
          <div style={{ fontFamily: getFont(theme, "secondary"), fontSize: "9px", color: "rgba(226,232,240,0.45)", marginTop: "8px", lineHeight: "1.5" }}>
            Selecciona una plantilla para llenar título, descripción y vigencia. Puedes ajustar cualquier dato antes de publicar.
          </div>
        </div>
      )}
      
      <div>
        <label style={comunicadoLabelStyle}>Título del comunicado <span style={{ color:"#f59e0b" }}>*</span></label>
        <input
          type="text"
          placeholder="Ingrese el título..."
          value={titulo}
          onChange={(e) => {
            const v = e.target.value;
            setTitulo(v);
            if (v.trim()) ensureFechaInicio();
          }}
          maxLength={120}
          style={comunicadoInputStyle}
        />
      </div>
      
      <button
        type="button"
        onClick={() => setAiAssistOpen(prev => !prev)}
        style={{ width:"100%", padding:"10px 12px", borderRadius:"8px", border:`1px solid ${aiAssistOpen ? "#0096ff" : "rgba(0,150,255,.30)"}`, background: aiAssistOpen ? "rgba(0,150,255,.20)" : "rgba(0,150,255,.10)", color:"#7dd3fc", fontFamily:getFont(theme,"secondary"), fontSize:"12px", fontWeight:800, cursor:"pointer", marginBottom:"12px", display:"flex", justifyContent:"center", alignItems:"center", gap:"8px" }}
      >
        ✨ Resumir o crear texto con IA
      </button>

      <div>
        <label style={comunicadoLabelStyle}>{aiAssistOpen ? "Texto para IA" : "Descripción breve (opcional)"}</label>
        <textarea
          placeholder={aiAssistOpen ? "Redacta tu texto que deseas resumir o las especificaciones para generar un texto" : "Escriba el contenido aquí..."}
          aria-label={aiAssistOpen ? "Texto para resumir o especificaciones para crear con IA" : "Descripción breve"}
          value={detalle}
          onChange={(e) => setDetalle(e.target.value)}
          rows={aiAssistOpen ? 5 : 4}
          style={comunicadoTextareaStyle(aiAssistOpen)}
        />
      </div>

      {aiAssistOpen && (
        <div style={{ background:"rgba(167,139,250,.07)", border:"1px solid rgba(167,139,250,.24)", borderRadius:"10px", padding:"10px", marginBottom:"10px" }}>
          <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:"8px", marginBottom:"9px" }}>
            {[
              { id:"resumir", label:"Resumir" },
              { id:"crear", label:"Crear" }
            ].map(opt => (
              <button
                key={opt.id}
                type="button"
                onClick={() => solicitarTextoConIA(opt.id)}
                disabled={aiBusy || !detalle.trim()}
                style={{ padding:"9px", borderRadius:"9px", border:`1px solid ${aiAction === opt.id ? "#a78bfa" : "rgba(148,163,184,.28)"}`, background: aiAction === opt.id ? "rgba(167,139,250,.20)" : "rgba(2,6,23,.42)", color: aiAction === opt.id ? "#d8b4fe" : "rgba(226,232,240,.62)", fontFamily:getFont(theme,"secondary"), fontSize:"11px", fontWeight:900, cursor:(aiBusy || !detalle.trim()) ? "not-allowed" : "pointer" }}
              >
                {aiBusy && aiAction === opt.id ? "Procesando…" : opt.label}
              </button>
            ))}
          </div>
          <button
            type="button"
            onClick={solicitarTextoConIA}
            disabled={aiBusy || !detalle.trim()}
            style={{ width:"100%", padding:"10px", borderRadius:"9px", border:"1px solid rgba(34,197,94,.55)", background:(aiBusy || !detalle.trim()) ? "rgba(100,116,139,.16)" : "rgba(34,197,94,.13)", color:(aiBusy || !detalle.trim()) ? "#94a3b8" : "#86efac", fontFamily:getFont(theme,"secondary"), fontSize:"11px", fontWeight:900, cursor:(aiBusy || !detalle.trim()) ? "not-allowed" : "pointer", marginBottom:"9px" }}
          >
            {aiBusy ? "Procesando con IA…" : aiAction === "resumir" ? "Generar resumen" : "Crear texto"}
          </button>
          <textarea
            value={aiOutput}
            onChange={(e) => setAiOutput(e.target.value)}
            placeholder="Aquí aparecerá el texto final devuelto por la IA"
            rows={5}
            readOnly={aiBusy}
            style={{ width:"100%", boxSizing:"border-box", background:"rgba(2,6,23,.72)", border:"1px solid rgba(167,139,250,.34)", borderRadius:"9px", padding:"10px 12px", color:"rgba(255,255,255,.92)", fontFamily:getFont(theme,"secondary"), fontSize:"12px", resize:"vertical", lineHeight:1.45, minHeight:"112px", outline:"none", marginBottom:"8px" }}
          />
          <div style={{ display:"flex", gap:"8px", flexWrap:"wrap" }}>
            <button
              type="button"
              onClick={aplicarResultadoIAADescripcion}
              disabled={aiBusy || !aiOutput.trim()}
              style={{ flex:"1 1 180px", padding:"9px 10px", borderRadius:"9px", border:"1px solid rgba(37,99,235,.5)", background:(aiBusy || !aiOutput.trim()) ? "rgba(100,116,139,.14)" : "rgba(37,99,235,.14)", color:(aiBusy || !aiOutput.trim()) ? "#94a3b8" : "#93c5fd", fontFamily:getFont(theme,"secondary"), fontSize:"11px", fontWeight:900, cursor:(aiBusy || !aiOutput.trim()) ? "not-allowed" : "pointer" }}
            >
              Usar este texto en la descripción
            </button>
          </div>
        </div>
      )}

      {/* Fechas de vigencia: solo fechas, sin horas */}
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(240px, 1fr))", gap: "18px", marginBottom: "14px" }}>
        <div>
          <div style={comunicadoLabelStyle}>FECHA INICIO <span style={{ color:"#f59e0b" }}>*</span></div>
          <input
            type="date"
            value={fechaInicio}
            onChange={(e) => setFechaInicio(e.target.value)}
            style={{ ...comunicadoInputStyle, marginBottom:0, padding:"12px 12px" }}
          />
        </div>
        <div>
          <div style={comunicadoLabelStyle}>FECHA FIN <span style={{ color:"#f59e0b" }}>*</span></div>
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "5px", marginBottom: "6px" }}>
            <button
              type="button"
              onClick={() => setFechaFinModo("fecha")}
              style={{ padding: "7px 6px", borderRadius: "8px", border: `1px solid ${fechaFinModo === "fecha" ? "#22c55e" : "#1e3a5f"}`, background: fechaFinModo === "fecha" ? "rgba(34,197,94,0.14)" : "#060e1a", color: fechaFinModo === "fecha" ? "#22c55e" : "rgba(226,232,240,0.55)", fontFamily: getFont(theme, "secondary"), fontSize: "10px", fontWeight: "700", cursor: "pointer" }}
            >Solo fecha</button>
            <button
              type="button"
              onClick={() => {
                const base = fechaFin || localDateInput(7);
                setFechaFin(base);
                setFechaFinHora(fechaFinHora || `${base}T23:59`);
                setFechaFinModo("fecha_hora");
              }}
              style={{ padding: "7px 6px", borderRadius: "8px", border: `1px solid ${fechaFinModo === "fecha_hora" ? "#38bdf8" : "#1e3a5f"}`, background: fechaFinModo === "fecha_hora" ? "rgba(56,189,248,0.14)" : "#060e1a", color: fechaFinModo === "fecha_hora" ? "#7dd3fc" : "rgba(226,232,240,0.55)", fontFamily: getFont(theme, "secondary"), fontSize: "10px", fontWeight: "700", cursor: "pointer" }}
            >Fecha y hora</button>
          </div>
          {fechaFinModo === "fecha_hora" ? (
            <input
              type="datetime-local"
              value={fechaFinHora}
              min={fechaInicio ? `${fechaInicio}T00:00` : undefined}
              onChange={(e) => {
                setFechaFinHora(e.target.value);
                if (e.target.value) setFechaFin(e.target.value.slice(0, 10));
              }}
              style={{ ...comunicadoInputStyle, marginBottom:0, padding:"12px 12px" }}
            />
          ) : (
            <input
              type="date"
              value={fechaFin}
              min={fechaInicio || undefined}
              onChange={(e) => {
                setFechaFin(e.target.value);
                if (fechaFinHora) setFechaFinHora(`${e.target.value}T${fechaFinHora.slice(11, 16) || "23:59"}`);
              }}
              style={{ ...comunicadoInputStyle, marginBottom:0, padding:"12px 12px" }}
            />
          )}
        </div>
      </div>
      <div style={{ background: "rgba(0,150,255,0.05)", borderLeft: "2px solid #0096ff", borderTop:"1px solid rgba(0,150,255,.12)", borderRight:"1px solid rgba(0,150,255,.12)", borderBottom:"1px solid rgba(0,150,255,.12)", borderRadius: "8px", padding: "12px 14px", marginBottom: "14px", fontFamily: getFont(theme, "secondary"), fontSize: "10px", color: "rgba(226,232,240,0.58)", lineHeight: "1.55" }}>
        La fecha de inicio se llena automáticamente con el día actual al escribir el título. En "Solo fecha", el comunicado permanece vigente hasta terminar el día seleccionado; en "Fecha y hora", finaliza exactamente en la hora indicada.
      </div>

      {/* Zona de archivo */}
      <div
        onClick={() => inputRef.current?.click()}
        style={{ border: "2px dashed #2c3a4c", borderRadius: "8px", padding: "30px 18px", textAlign: "center", cursor: "pointer", marginBottom: "14px", background: archivo ? "rgba(34,197,94,.08)" : "rgba(1,15,31,.50)", borderColor: archivo ? "rgba(34,197,94,.55)" : "#2c3a4c", transition: "all 0.2s" }}
      >
        {preview && preview !== "pdf" && (
          <img src={preview} alt="preview" style={{ maxWidth: "100%", maxHeight: "160px", objectFit: "contain", borderRadius: "6px", marginBottom: "8px", display: "block", margin: "0 auto 8px" }} />
        )}
        {preview === "pdf" && <div style={{ fontSize: "40px", marginBottom: "6px" }}>📄</div>}
        <div style={{ fontFamily: getFont(theme, "secondary"), fontSize: "11px", color: archivo ? "#22c55e" : "rgba(255,255,255,0.35)" }}>
          {archivo ? `✓ ${archivo.name}` : "Seleccionar JPG, PNG o PDF (máx. 10 MB)"}
        </div>
        <input ref={inputRef} type="file" accept="image/jpeg,image/png,image/webp,application/pdf" onChange={onFileChange} style={{ display: "none" }} />
      </div>

      <div style={{ background:"rgba(1,15,31,.45)", border:"1px solid #2c3a4c", borderRadius:"8px", padding:"14px", marginBottom:"14px" }}>
        <div style={{ fontFamily:getFont(theme,"secondary"), fontSize:"10px", color:"rgba(255,255,255,0.48)", marginBottom:"8px", lineHeight:"1.45" }}>
          Herramientas opcionales para preparar el comunicado. El texto extraído se agregará automáticamente en <b style={{ color:"rgba(255,255,255,0.78)" }}>Descripción breve</b>.
        </div>
        {toolMsg && <div style={{ padding:"8px 10px", borderRadius:"8px", background:toolMsg.color+"18", border:`1px solid ${toolMsg.color}55`, color:toolMsg.color, fontFamily:getFont(theme,"secondary"), fontSize:"10px", marginBottom:"8px" }}>{toolMsg.message}</div>}
        <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fit, minmax(170px, 1fr))", gap:"8px" }}>
          <button type="button" onClick={procesarArchivoComunicado} disabled={toolBusy || !archivo} style={comunicadoToolButtonStyle("#0096ff", toolBusy || !archivo)}>{toolBusy ? "Procesando…" : "Convertir / extraer texto"}</button>
          <button type="button" onClick={()=>setZonePickerOpen(true)} disabled={toolBusy || !archivo} style={comunicadoToolButtonStyle("#f59e0b", toolBusy || !archivo)}>Elegir zonas de extracción</button>
          <button type="button" onClick={()=>setConverterOpen(true)} disabled={toolBusy || !archivo} style={comunicadoToolButtonStyle("#38bdf8", toolBusy || !archivo)}>Conversor PDF / imagen</button>
          {isAdmin && <button type="button" onClick={()=>setScreenshotOpen(true)} disabled={toolBusy} style={comunicadoToolButtonStyle("#22c55e", toolBusy)}>Captura web / recorte</button>}
          {isAdmin && <button type="button" onClick={crearComunicadoPorFormato} disabled={graphicBusy || !detalle.trim() || !titulo.trim()} style={comunicadoToolButtonStyle("#ec4899", graphicBusy || !detalle.trim() || !titulo.trim())}>{graphicBusy ? "Generando formato…" : "Crear comunicado por formato"}</button>}
          {isAdmin && <button type="button" onClick={publicarArchivoEnNoticias} disabled={toolBusy || !archivo} style={comunicadoToolButtonStyle("#0096ff", toolBusy || !archivo)}>Publicar en Noticias</button>}
        </div>
      </div>

      {isAdmin && (
        <>
          {canvasElements.length > 0 && (
            <div style={{ background:"rgba(236,72,153,.06)", border:"1px solid rgba(236,72,153,.22)", borderRadius:"12px", padding:"12px", marginBottom:"10px" }}>
              <div style={{ fontFamily:getFont(theme,"secondary"), fontSize:"10px", color:"#f9a8d4", fontWeight:900, letterSpacing:".8px", marginBottom:"8px" }}>
                VISTA PREVIA DEL COMUNICADO GRÁFICO
              </div>

              <div ref={canvasPreviewWrapRef} style={{ position:"relative", width:"100%", marginBottom:"10px" }}>
                <canvas
                  ref={comunicadoCanvasRef}
                  onPointerDown={handleCanvasPointerDown}
                  onPointerMove={handleCanvasPointerMove}
                  onPointerUp={handleCanvasPointerUp}
                  onPointerLeave={handleCanvasPointerUp}
                  style={{ width:"100%", borderRadius:"10px", border:"1px solid rgba(255,255,255,.1)", background:"#fff", display:"block", touchAction:"none", cursor:"grab" }}
                />
                {inlineEditor?.elementId && getInlineEditorStyle() && (
                  inlineEditor.multiline ? (
                    <textarea
                      autoFocus
                      value={inlineEditor.value}
                      onChange={(e) => setInlineEditor((prev) => ({ ...prev, value: e.target.value }))}
                      onBlur={commitInlineEditor}
                      style={getInlineEditorStyle()}
                    />
                  ) : (
                    <input
                      autoFocus
                      value={inlineEditor.value}
                      onChange={(e) => setInlineEditor((prev) => ({ ...prev, value: e.target.value }))}
                      onBlur={commitInlineEditor}
                      onKeyDown={(e) => {
                        if (e.key === 'Enter') {
                          e.preventDefault();
                          commitInlineEditor();
                        }
                      }}
                      style={getInlineEditorStyle()}
                    />
                  )
                )}
              </div>

              <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fit, minmax(180px, 1fr))", gap:"8px" }}>
                <button type="button" onClick={descargarComunicadoGenerado} style={{ padding:"10px", borderRadius:"9px", border:"1px solid rgba(34,197,94,.55)", background:"rgba(34,197,94,.12)", color:"#86efac", fontFamily:getFont(theme,"secondary"), fontSize:"11px", fontWeight:900, cursor:"pointer" }}>Descargar imagen final</button>
                <button type="button" onClick={copiarTextoComunicadoGrafico} style={{ padding:"10px", borderRadius:"9px", border:"1px solid rgba(250,204,21,.55)", background:"rgba(250,204,21,.12)", color:"#fde68a", fontFamily:getFont(theme,"secondary"), fontSize:"11px", fontWeight:900, cursor:"pointer" }}>Copiar Texto</button>
                <button type="button" onClick={abrirEditorComunicadoGrafico} style={{ padding:"10px", borderRadius:"9px", border:"1px solid rgba(236,72,153,.55)", background:"rgba(236,72,153,.12)", color:"#f9a8d4", fontFamily:getFont(theme,"secondary"), fontSize:"11px", fontWeight:900, cursor:"pointer" }}>Editar texto</button>
                <button type="button" onClick={adjuntarComunicadoGenerado} disabled={!generatedGraphicFile} style={{ padding:"10px", borderRadius:"9px", border:"1px solid rgba(56,189,248,.55)", background:!generatedGraphicFile?"rgba(100,116,139,.16)":"rgba(56,189,248,.12)", color:!generatedGraphicFile?"#94a3b8":"#7dd3fc", fontFamily:getFont(theme,"secondary"), fontSize:"11px", fontWeight:900, cursor:!generatedGraphicFile?"not-allowed":"pointer" }}>Adjuntar imagen generada al comunicado</button>
              </div>

              <div style={{ marginTop:"8px", fontFamily:getFont(theme,"secondary"), fontSize:"9px", color:"rgba(226,232,240,.58)", lineHeight:1.5 }}>
                Arrastra Fecha, Título o Cuerpo directamente sobre el canvas. Haz clic simple sobre un elemento para editarlo in-situ.
              </div>

              {graphicEditorOpen && (
                <div style={{ marginTop:"12px", background:"rgba(2,6,23,.58)", border:"1px solid rgba(236,72,153,.25)", borderRadius:"12px", padding:"12px" }}>
                  <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", gap:"10px", marginBottom:"10px", flexWrap:"wrap" }}>
                    <div>
                      <div style={{ fontFamily:getFont(theme,"secondary"), fontSize:"10px", color:"#f9a8d4", fontWeight:900, letterSpacing:".8px" }}>EDICIÓN MANUAL DEL TEXTO</div>
                      <div style={{ fontFamily:getFont(theme,"secondary"), fontSize:"9px", color:"rgba(226,232,240,.50)", marginTop:"3px" }}>Selecciona texto y usa negritas. La vista previa del canvas se actualiza en vivo.</div>
                    </div>
                    <div style={{ display:"flex", gap:"8px", flexWrap:"wrap" }}>
                      <button type="button" onClick={copiarTextoComunicadoGrafico} style={{ padding:"8px 10px", borderRadius:"9px", border:"1px solid rgba(250,204,21,.55)", background:"rgba(250,204,21,.12)", color:"#fde68a", fontFamily:getFont(theme,"secondary"), fontSize:"10px", fontWeight:900, cursor:"pointer" }}>Copiar Texto</button>
                      <button type="button" onClick={aplicarEdicionComunicadoGrafico} disabled={graphicBusy || !graphicEditorText.trim()} style={{ padding:"8px 10px", borderRadius:"9px", border:"1px solid rgba(34,197,94,.55)", background:(graphicBusy || !graphicEditorText.trim())?"rgba(100,116,139,.16)":"rgba(34,197,94,.12)", color:(graphicBusy || !graphicEditorText.trim())?"#94a3b8":"#86efac", fontFamily:getFont(theme,"secondary"), fontSize:"10px", fontWeight:900, cursor:(graphicBusy || !graphicEditorText.trim())?"not-allowed":"pointer" }}>Guardar / aplicar</button>
                    </div>
                  </div>

                  <div style={{ display:"flex", gap:"8px", flexWrap:"wrap", marginBottom:"10px" }}>
                    <button type="button" onClick={aplicarNegritasEditor} style={{ padding:"8px 10px", borderRadius:"9px", border:"1px solid rgba(250,204,21,.55)", background:"rgba(250,204,21,.12)", color:"#fde68a", fontFamily:getFont(theme,"secondary"), fontSize:"10px", fontWeight:900, cursor:"pointer" }}>B Negritas</button>
                    {[
                      { id:"left", label:"Izquierda" },
                      { id:"center", label:"Centro" },
                      { id:"right", label:"Derecha" },
                      { id:"justify", label:"Justificado" },
                    ].map(opt => (
                      <button
                        key={opt.id}
                        type="button"
                        onClick={() => setTextAlignMode(opt.id)}
                        style={{
                          padding:"8px 10px",
                          borderRadius:"9px",
                          border:`1px solid ${textAlignMode === opt.id ? "rgba(56,189,248,.75)" : "rgba(148,163,184,.25)"}`,
                          background:textAlignMode === opt.id ? "rgba(56,189,248,.16)" : "rgba(15,23,42,.55)",
                          color:textAlignMode === opt.id ? "#7dd3fc" : "rgba(226,232,240,.65)",
                          fontFamily:getFont(theme,"secondary"),
                          fontSize:"9px",
                          fontWeight:900,
                          cursor:"pointer"
                        }}
                      >
                        {opt.label}
                      </button>
                    ))}
                  </div>

                  <textarea
                    ref={graphicEditorTextareaRef}
                    value={graphicEditorText}
                    onChange={(e) => setGraphicEditorText(e.target.value)}
                    rows={8}
                    placeholder="Edita el texto del comunicado. Usa **texto** para negritas."
                    style={{ width:"100%", boxSizing:"border-box", background:"rgba(2,6,23,.78)", border:"1px solid rgba(236,72,153,.32)", borderRadius:"10px", padding:"11px 12px", color:"rgba(255,255,255,.92)", fontFamily:getFont(theme,"secondary"), fontSize:"12px", lineHeight:1.55, resize:"vertical", outline:"none" }}
                  />
                </div>
              )}
            </div>
          )}
        </>
      )}
      {zonePickerOpen && <OcrZonePickerModal files={archivo ? [archivo] : []} onClose={()=>setZonePickerOpen(false)} onApply={aplicarTextoDeZonasComunicado} />}
      {converterOpen && <MediaConverterModal files={archivo ? [archivo] : []} onClose={()=>setConverterOpen(false)} onNotice={(message, color)=>setToolNotice(message, color)} />}
      {isAdmin && screenshotOpen && <ScreenshotCropModal onClose={()=>setScreenshotOpen(false)} onApply={aplicarCapturaWebRecortada} />}
      
      {!isAdmin && (
        <div style={{ background: "rgba(0,150,255,.08)", border: "1px solid rgba(0,150,255,.32)", borderRadius: "8px", padding: "12px 14px", marginBottom: "14px", fontSize: "11px", color: "#bfdbfe", fontFamily: getFont(theme, "secondary"), lineHeight: "1.6", display:"flex", gap:"10px", alignItems:"flex-start" }}>
          Info Tu comunicado será enviado a revisión y aparecerá después de ser aprobado por un administrador.
        </div>
      )}
      
      {error && (
        <div style={{ fontFamily: getFont(theme, "secondary"), fontSize: "11px", color: "#f87171", marginBottom: "8px", padding: "8px 12px", background: "#ef444411", borderRadius: "7px" }}>
          ⚠️ {error}
        </div>
      )}
      {exito && (
        <div style={{ fontFamily: getFont(theme, "secondary"), fontSize: "11px", color: "#22c55e", marginBottom: "8px", padding: "8px 12px", background: "#22c55e11", borderRadius: "7px" }}>
          Validado {isAdmin ? "Comunicado publicado correctamente" : "Comunicado enviado a revisión"}
        </div>
      )}
      
      <button
        onClick={handleSubir}
        disabled={subiendo}
        style={{ width: "100%", padding: "15px 18px", background: subiendo ? "rgba(44,58,76,.45)" : "linear-gradient(135deg,#f59e0b,#fbbf24)", border: "1px solid rgba(245,158,11,.55)", borderRadius: "8px", color: subiendo ? "rgba(255,255,255,0.45)" : "#010f1f", fontFamily: getFont(theme, "secondary"), fontWeight: "900", fontSize: "12px", cursor: subiendo ? "not-allowed" : "pointer", letterSpacing: "0.8px", boxShadow: subiendo ? "none" : "0 14px 32px rgba(245,158,11,.22)" }}
      >
        {subiendo ? "Procesando subida..." : isAdmin ? "PUBLICAR COMUNICADO" : "ENVIAR A REVISIÓN"}
      </button>
    </div>
  );
}

// ─── SECCIÓN COMUNICADOS (con sub-tabs: Ver / Proponer) ──────────────────────
function ComunicadosSection({ isAdmin, comunicados, onReload, setVisorItem, onDownloadItem, downloadingItemUrl, timeAgo, isPdf }) {
  const theme = React.useContext(ThemeContext);
  const comunicadosMobile = useWindowWidth() < 720;
  const [subTab, setSubTab] = useState("ver"); // "ver" | "proponer"
  const [pendientes, setPendientes] = useState([]);
  const [confirmId, setConfirmId] = useState(null); // id del comunicado a eliminar
  const [eliminando, setEliminando] = useState(false); // estado de eliminación en progreso
  const [selectedIndex, setSelectedIndex] = useState(0); // comunicado destacado en vista grande
  const COMUNICADOS_VER_ICON = "data:image/png;base64,";
  const COMUNICADOS_PROPONER_ICON = "data:image/png;base64,";
  const comunicadoTabButtonStyle = (active, accent) => ({
    flex: 1,
    minHeight: "52px",
    padding: "10px 12px",
    borderRadius: "13px",
    border: `1px solid ${active ? accent + "66" : "rgba(148,163,184,0.16)"}`,
    background: active ? `linear-gradient(180deg, ${accent}22, rgba(7,17,31,0.94))` : "rgba(7,17,31,0.72)",
    color: active ? "#ffffff" : "rgba(226,232,240,0.68)",
    fontFamily: getFont(theme, "secondary"),
    fontSize: "12px",
    fontWeight: "800",
    cursor: "pointer",
    letterSpacing: "0.2px",
    transition: "all 0.2s ease",
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    gap: "10px",
    boxShadow: active ? `0 12px 28px ${accent}22, inset 0 1px 0 rgba(255,255,255,0.10)` : "inset 0 1px 0 rgba(255,255,255,0.04)",
  });
  const comunicadoTabIconStyle = (active) => ({
    width: "24px",
    height: "24px",
    objectFit: "contain",
    flex: "0 0 auto",
    opacity: active ? 1 : 0.78,
    filter: active ? "drop-shadow(0 0 8px rgba(255,255,255,0.18))" : "none",
  });

  const formatDateTime = (timestamp) => {
    const d = new Date(toMs(timestamp));
    return d.toLocaleString("es-MX", { year: "numeric", month: "short", day: "numeric", hour: "2-digit", minute: "2-digit" });
  };

  // Normaliza aprobado para boolean, string o número.
  // Esto evita que Supabase lo regrese como "true"/"false" y rompa los filtros.
  const isComunicadoAprobado = (value) =>
    value === true || value === "true" || value === 1 || value === "1";

  // Filtrar comunicados para mostrar
  const ahora = Date.now();
  const vigentes = comunicados.filter(c => {
    if (!isComunicadoAprobado(c.aprobado)) return false;
    // Si no hay fecha_fin, mostrar siempre
    if (!c.fecha_fin) return true;
    const fin = toMs(c.fecha_fin);
    // Si no se puede parsear la fecha, mostrar de todas formas
    if (!fin || isNaN(fin)) return true;
    return fin > ahora;
  });

  useEffect(() => {
    if (!vigentes.length) {
      if (selectedIndex !== 0) setSelectedIndex(0);
      return;
    }
    if (selectedIndex > vigentes.length - 1) setSelectedIndex(0);
  }, [vigentes.length, selectedIndex]);

  const comunicadoActivo = vigentes[selectedIndex] || null;
  const totalVigentes = vigentes.length;
  const irAnterior = () => {
    if (totalVigentes < 2) return;
    setSelectedIndex(prev => (prev - 1 + totalVigentes) % totalVigentes);
  };
  const irSiguiente = () => {
    if (totalVigentes < 2) return;
    setSelectedIndex(prev => (prev + 1) % totalVigentes);
  };
  const abrirComunicadoActivo = () => {
    if (!comunicadoActivo) return;
    setVisorItem(comunicadoActivo, vigentes, selectedIndex);
  };

  const cargarPendientes = () => {
    if (!isAdmin) return;
    // Cargar y filtrar en cliente para soportar false, "false", 0 o null.
    // .eq("aprobado", false) puede fallar si el campo no es boolean puro.
    sb.from("comunicados")
      .select("*")
      .order("created_at", { ascending: false })
      .then(({ data, error }) => {
        if (error) {
          console.error("Error cargando pendientes:", error);
          return;
        }
        if (data) setPendientes(data.filter(c => !isComunicadoAprobado(c.aprobado)));
      });
  };

  // Cargar pendientes (solo admin)
  useEffect(() => {
    cargarPendientes();
  }, [isAdmin]);

  const [procesando, setProcesando] = useState(null); // id del que se está procesando

  const aprobar = async (id) => {
    if (procesando) return;
    setProcesando(id);

    const { data, error } = await sb
      .from("comunicados")
      .update({ aprobado: true })
      .eq("id", id)
      .select("*"); // confirma que Supabase realmente actualizó la fila

    setProcesando(null);

    if (error) {
      console.error("Error al aprobar comunicado:", error);
      alert("Error al aprobar: " + error.message);
      return;
    }

    if (!data || data.length === 0) {
      alert("No se pudo aprobar el comunicado. Revisa las políticas RLS de Supabase para UPDATE en la tabla comunicados.");
      cargarPendientes();
      return;
    }

    // Replica a Noticias sin aprobación adicional.
    if (data?.[0]) {
      await syncComunicadoToNoticia(data[0], { processMedia: true });
    }

    // UI inmediata: lo quitamos de pendientes sin esperar realtime.
    setPendientes(prev => prev.filter(p => p.id !== id));

    // Recarga diferida para evitar que vuelva visualmente como pendiente.
    if (onReload) {
      setTimeout(() => {
        onReload();
        cargarPendientes();
      }, 500);
    }
  };

  const rechazar = async (id) => {
    setProcesando(id);
    const com = pendientes.find(p => p.id === id);
    if (com?.archivo_url) {
      try {
        const pathParts = com.archivo_url.split("/comunicados/");
        if (pathParts[1]) {
          await sb.storage.from("comunicados").remove([`comunicados/${pathParts[1]}`]);
        }
      } catch {}
    }
    const { error } = await sb.from("comunicados").delete().eq("id", id);
    setProcesando(null);
    if (error) { alert("Error al rechazar: " + error.message); return; }
    setPendientes(prev => prev.filter(p => p.id !== id));
    onReload();
  };

  const pedirEliminar = (id) => setConfirmId(id);

  const eliminar = async (id) => {
    if (eliminando) return;
    setEliminando(true);

    const com = vigentes.find(v => v.id === id) || comunicados.find(c => c.id === id);

    // 1. Eliminar archivo de storage si existe
    if (com?.archivo_url) {
      try {
        const path = com.archivo_url.split("/comunicados/")[1];
        if (path) await sb.storage.from("comunicados").remove([`comunicados/${path}`]);
      } catch (err) {
        console.error("Error al eliminar archivo:", err);
      }
    }

    // 2. Delete con .select() para confirmar que Supabase realmente eliminó la fila
    const { data: deleted, error } = await sb
      .from("comunicados")
      .delete()
      .eq("id", id)
      .select();

    if (error) {
      console.error("Error al eliminar comunicado:", error);
      alert("Error al eliminar el comunicado: " + error.message);
      setEliminando(false);
      setConfirmId(null);
      return;
    }

    // 3. Si no se eliminó ninguna fila, probablemente hay un problema de RLS
    if (!deleted || deleted.length === 0) {
      alert("No se pudo eliminar el comunicado.\n\nVerifica que la política RLS de la tabla 'comunicados' en Supabase permita DELETE al rol anon o al usuario actual.");
      setEliminando(false);
      setConfirmId(null);
      return;
    }

    // 4. Cerrar modal y recargar
    setEliminando(false);
    setConfirmId(null);
    onReload();
  };

  const handleSubidoExitoso = () => {
    onReload();
    cargarPendientes();
    setSubTab("ver");
  };



  return (
    <>
      {/* Sub-tabs: Ver comunicado / Proponer comunicado */}
      <div style={{ display: "flex", flexDirection: comunicadosMobile ? "column" : "row", gap: "8px", marginBottom: "16px", background: "rgba(2,6,23,0.78)", borderRadius: "16px", padding: "6px", border: "1px solid rgba(30,58,95,0.78)", boxShadow: "inset 0 1px 0 rgba(255,255,255,0.04)" }}>
        <button
          onClick={() => setSubTab("ver")}
          style={comunicadoTabButtonStyle(subTab === "ver", "#fbbf24")}
        >
          <img src={COMUNICADOS_VER_ICON} alt="" style={comunicadoTabIconStyle(subTab === "ver")} />
          <span>Ver comunicado</span>
          {vigentes.length > 0 && (
            <span style={{ background: subTab === "ver" ? "rgba(255,255,255,0.18)" : "rgba(251,191,36,0.18)", color: subTab === "ver" ? "#fff" : "#fbbf24", borderRadius: "999px", padding: "2px 7px", fontSize: "9px", fontWeight: "900", lineHeight: 1 }}>
              {vigentes.length}
            </span>
          )}
        </button>
        <button
          onClick={() => setSubTab("proponer")}
          style={comunicadoTabButtonStyle(subTab === "proponer", "#38bdf8")}
        >
          <img src={COMUNICADOS_PROPONER_ICON} alt="" style={comunicadoTabIconStyle(subTab === "proponer")} />
          <span>Proponer comunicado</span>
          {isAdmin && pendientes.length > 0 && (
            <span style={{ background: "#f97316", color: "#fff", borderRadius: "999px", padding: "2px 7px", fontSize: "9px", fontWeight: "900", lineHeight: 1 }}>
              {pendientes.length}
            </span>
          )}
        </button>
      </div>

      {/* ── MODAL CONFIRMACIÓN ELIMINAR ── position:fixed cubre toda la pantalla sin necesitar portal */}
      {confirmId && (
        <div
          onClick={() => !eliminando && setConfirmId(null)}
          style={{ position: "fixed", inset: 0, zIndex: 99999, background: "rgba(0,0,0,0.80)", display: "flex", alignItems: "center", justifyContent: "center", padding: "20px" }}
        >
          <div onClick={e => e.stopPropagation()} style={{ background: "#0d1b2e", border: "1px solid rgba(239,68,68,0.4)", borderRadius: "16px", padding: "24px", maxWidth: "320px", width: "100%", textAlign: "center" }}>
            <div style={{ fontSize: "40px", marginBottom: "12px" }}>{eliminando ? "Procesando" : "Eliminar️"}</div>
            <div style={{ fontFamily: getFont(theme, "secondary"), fontWeight: "700", fontSize: "14px", color: "#fff", marginBottom: "8px" }}>
              {eliminando ? "Eliminando comunicado..." : "¿Eliminar comunicado?"}
            </div>
            <div style={{ fontFamily: getFont(theme, "secondary"), fontSize: "11px", color: "rgba(255,255,255,0.45)", marginBottom: "22px", lineHeight: "1.5" }}>
              {eliminando 
                ? "Por favor espera mientras se elimina el archivo y el registro."
                : <>Esta acción es permanente.<br/>Se eliminará el archivo y no podrá recuperarse.</>
              }
            </div>
            <div style={{ display: "flex", gap: "10px" }}>
              <button
                onClick={() => setConfirmId(null)}
                disabled={eliminando}
                style={{ 
                  flex: 1, 
                  padding: "12px", 
                  background: "transparent", 
                  border: "1px solid #1e3a5f", 
                  borderRadius: "10px", 
                  color: eliminando ? "rgba(255,255,255,0.3)" : "rgba(255,255,255,0.6)", 
                  fontFamily: getFont(theme, "secondary"), 
                  fontSize: "12px", 
                  fontWeight: "700", 
                  cursor: eliminando ? "not-allowed" : "pointer",
                  opacity: eliminando ? 0.5 : 1
                }}
              >Cancelar</button>
              <button
                onClick={() => eliminar(confirmId)}
                disabled={eliminando}
                style={{ 
                  flex: 1, 
                  padding: "12px", 
                  background: eliminando ? "#0a1628" : "linear-gradient(135deg,#ef4444,#dc2626)", 
                  border: "none", 
                  borderRadius: "10px", 
                  color: eliminando ? "rgba(255,255,255,0.4)" : "#fff", 
                  fontFamily: getFont(theme, "secondary"), 
                  fontSize: "12px", 
                  fontWeight: "700", 
                  cursor: eliminando ? "not-allowed" : "pointer",
                  opacity: eliminando ? 0.7 : 1
                }}
              >{eliminando ? "Eliminando..." : "Sí, eliminar"}</button>
            </div>
          </div>
        </div>
      )}

      {/* ── SUB-TAB: VER COMUNICADOS ── */}
      {subTab === "ver" && (
        <>
          {vigentes.length === 0 ? (
            <div style={{ textAlign: "center", padding: "50px 20px", border: "1px dashed #1e3a5f", borderRadius: "14px", color: "rgba(255,255,255,0.25)", fontFamily: getFont(theme, "secondary"), fontSize: "12px" }}>
              <div style={{ fontSize: "36px", marginBottom: "10px" }}>📭</div>
              Sin comunicados vigentes en este momento
            </div>
          ) : (
            <>
              {comunicadoActivo && (
                <div style={{ background: "linear-gradient(135deg, rgba(255,255,255,0.08), rgba(255,255,255,0.04))", border: "1px solid rgba(255,255,255,0.12)", borderRadius: "16px", overflow: "hidden", marginBottom: "14px" }}>
                  <div style={{ display: "flex", flexDirection: comunicadosMobile ? "column" : "row", justifyContent: "space-between", alignItems: comunicadosMobile ? "stretch" : "flex-start", gap: "12px", padding: comunicadosMobile ? "12px" : "14px 14px 10px" }}>
                    <div style={{ flex: 1, minWidth: 0 }}>
                      <div style={{ fontFamily: getFont(theme, "secondary"), fontWeight: "700", fontSize: "14px", color: "rgba(255,255,255,0.95)", marginBottom: "4px" }}>{comunicadoActivo.titulo}</div>
                      {comunicadoActivo.detalle && <details style={{ marginBottom:"8px", maxWidth:"100%" }}><summary style={{ cursor:"pointer", fontFamily:getFont(theme,"secondary"), fontSize:"10px", color:"#93c5fd", fontWeight:800 }}>Ver descripción</summary><div style={{ fontFamily: getFont(theme, "secondary"), fontSize: comunicadosMobile ? "12px" : "11px", color: "rgba(255,255,255,0.68)", lineHeight: "1.55", marginTop:"6px", maxHeight:comunicadosMobile ? "180px" : "120px", overflowY:"auto", overflowX:"hidden", whiteSpace:"pre-wrap", wordBreak:"break-word", overflowWrap:"anywhere", width:"100%", boxSizing:"border-box", padding:"8px 10px", borderRadius:"10px", background:"rgba(2,6,23,.28)", border:"1px solid rgba(255,255,255,.08)" }}>{comunicadoActivo.detalle}</div></details>}
                      <div style={{ display: "flex", flexWrap: "wrap", gap: "8px", alignItems: "center" }}>
                        <span style={{ fontFamily: getFont(theme, "secondary"), fontSize: "10px", color: "#fbbf24", fontWeight: "700" }}>Documento {selectedIndex + 1} de {totalVigentes}</span>
                        <span style={{ fontFamily: getFont(theme, "secondary"), fontSize: "10px", color: "rgba(255,255,255,0.35)" }}>🕐 Vence: {formatDateTime(comunicadoActivo.fecha_fin)}</span>
                      </div>
                    </div>
                    <div style={{ display: "flex", gap: "8px", flexWrap: "wrap", justifyContent: comunicadosMobile ? "stretch" : "flex-end" }}>
                      <button onClick={abrirComunicadoActivo} style={{ padding: "9px 12px", background: "rgba(56,189,248,0.12)", border: "1px solid rgba(56,189,248,0.35)", borderRadius: "10px", color: "#38bdf8", fontFamily: getFont(theme, "secondary"), fontSize: "11px", fontWeight: "700", cursor: "pointer" }}>Pantalla completa</button>
                      <a href={comunicadoActivo.archivo_url} target="_blank" rel="noreferrer" style={{ padding: "9px 12px", background: "rgba(251,191,36,0.10)", border: "1px solid rgba(251,191,36,0.35)", borderRadius: "10px", color: "#fbbf24", fontFamily: getFont(theme, "secondary"), fontSize: "11px", fontWeight: "700", textDecoration: "none" }}>Abrir</a>
                      {onDownloadItem ? (<button onClick={() => onDownloadItem(comunicadoActivo)} disabled={downloadingItemUrl === comunicadoActivo.archivo_url} style={{ padding: "9px 12px", background: downloadingItemUrl === comunicadoActivo.archivo_url ? "rgba(100,116,139,.18)" : "rgba(34,197,94,0.10)", border: "1px solid rgba(34,197,94,0.35)", borderRadius: "10px", color: downloadingItemUrl === comunicadoActivo.archivo_url ? "#94a3b8" : "#22c55e", fontFamily: getFont(theme, "secondary"), fontSize: "11px", fontWeight: "700", cursor: downloadingItemUrl === comunicadoActivo.archivo_url ? "not-allowed" : "pointer" }}>{downloadingItemUrl === comunicadoActivo.archivo_url ? "Preparando descarga…" : "Descargar con marca de agua"}</button>) : (<a href={comunicadoActivo.archivo_url} download style={{ padding: "9px 12px", background: "rgba(34,197,94,0.10)", border: "1px solid rgba(34,197,94,0.35)", borderRadius: "10px", color: "#22c55e", fontFamily: getFont(theme, "secondary"), fontSize: "11px", fontWeight: "700", textDecoration: "none" }}>Descargar</a>)}
                    </div>
                  </div>

                  <div style={{ position: "relative", width: "100%", minHeight: comunicadosMobile ? "280px" : "480px", maxHeight: comunicadosMobile ? "56vh" : "70vh", background: "#06101d", borderTop: "1px solid rgba(255,255,255,0.08)", display: "flex", alignItems: "center", justifyContent: "center" }}>
                    {isPdf(comunicadoActivo.archivo_url) ? (
                      <iframe src={comunicadoActivo.archivo_url} title={comunicadoActivo.titulo} style={{ width: "100%", height: comunicadosMobile ? "54vh" : "68vh", border: "none", background: "#fff" }} />
                    ) : (
                      <img src={comunicadoActivo.archivo_url} alt={comunicadoActivo.titulo} style={{ width: "100%", height: comunicadosMobile ? "54vh" : "68vh", objectFit: "contain", display: "block", background: "#061428" }} loading="lazy" />
                    )}

                    {totalVigentes > 1 && (
                      <>
                        <button onClick={irAnterior} style={{ position: "absolute", left: "12px", top: "50%", transform: "translateY(-50%)", width: "46px", height: "46px", borderRadius: "50%", border: "1px solid rgba(255,255,255,0.18)", background: "rgba(10,22,40,0.82)", color: "#fff", fontSize: "24px", cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", backdropFilter: "blur(8px)", zIndex: 2 }} aria-label="Comunicado anterior">‹</button>
                        <button onClick={irSiguiente} style={{ position: "absolute", right: "12px", top: "50%", transform: "translateY(-50%)", width: "46px", height: "46px", borderRadius: "50%", border: "1px solid rgba(255,255,255,0.18)", background: "rgba(10,22,40,0.82)", color: "#fff", fontSize: "24px", cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", backdropFilter: "blur(8px)", zIndex: 2 }} aria-label="Siguiente comunicado">›</button>
                        <div style={{ position: "absolute", bottom: "12px", left: "50%", transform: "translateX(-50%)", background: "rgba(10,22,40,0.72)", border: "1px solid rgba(255,255,255,0.10)", borderRadius: "999px", padding: "6px 12px", fontFamily: getFont(theme, "secondary"), fontSize: "10px", color: "rgba(255,255,255,0.85)", zIndex: 2 }}>
                          Usa las flechas para cambiar de archivo
                        </div>
                      </>
                    )}
                  </div>
                </div>
              )}

              <div style={{ display: "grid", gridTemplateColumns: comunicadosMobile ? "1fr" : "repeat(auto-fill, minmax(180px, 1fr))", gap: "10px" }}>
                {vigentes.map((c, idx) => {
                  const activo = idx === selectedIndex;
                  return (
                    <div
                      key={c.id}
                      onClick={() => setSelectedIndex(idx)}
                      style={{ background: activo ? "rgba(251,191,36,0.12)" : "rgba(255,255,255,0.07)", border: `1px solid ${activo ? "rgba(251,191,36,0.45)" : "rgba(255,255,255,0.10)"}`, borderRadius: "12px", overflow: "hidden", cursor: "pointer", transition: "transform 0.15s, border-color 0.15s", position: "relative", boxShadow: activo ? "0 0 0 1px rgba(251,191,36,0.18) inset" : "none" }}
                      onMouseEnter={(e) => { e.currentTarget.style.transform = "scale(1.02)"; if (!activo) e.currentTarget.style.borderColor = "rgba(251,191,36,0.4)"; }}
                      onMouseLeave={(e) => { e.currentTarget.style.transform = "scale(1)"; e.currentTarget.style.borderColor = activo ? "rgba(251,191,36,0.45)" : "rgba(255,255,255,0.1)"; }}
                    >
                      <div style={{ width: "100%", aspectRatio: "4/3", background: "#060e1a", display: "flex", alignItems: "center", justifyContent: "center", overflow: "hidden" }}>
                        {isPdf(c.archivo_url) ? (
                          <div style={{ textAlign: "center" }}>
                            <div style={{ fontSize: "38px" }}>📄</div>
                            <div style={{ fontFamily: getFont(theme, "secondary"), fontSize: "9px", color: "rgba(255,255,255,0.4)", marginTop: "4px" }}>PDF</div>
                          </div>
                        ) : (
                          <img src={c.archivo_url} alt={c.titulo} style={{ width: "100%", height: "100%", objectFit: "cover" }} loading="lazy" />
                        )}
                      </div>
                      <div style={{ padding: "8px 10px" }}>
                        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", gap: "6px", marginBottom: "3px" }}>
                          <div style={{ fontFamily: getFont(theme, "secondary"), fontWeight: "700", fontSize: "11px", color: "rgba(255,255,255,0.9)", overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap", flex: 1 }}>{c.titulo}</div>
                          {activo && <span style={{ fontFamily: getFont(theme, "secondary"), fontSize: "9px", fontWeight: "700", color: "#fbbf24" }}>ACTIVO</span>}
                        </div>
                        {c.detalle && <div style={{ fontFamily: getFont(theme, "secondary"), fontSize: "10px", color: "rgba(255,255,255,0.4)", overflow: "hidden", textOverflow: "ellipsis", whiteSpace: comunicadosMobile ? "normal" : "nowrap", wordBreak:"break-word", overflowWrap:"anywhere", lineHeight:1.4, marginBottom: "4px" }}>{c.detalle}</div>}
                        <div style={{ fontFamily: getFont(theme, "secondary"), fontSize: "9px", color: "rgba(255,255,255,0.25)" }}>🕐 Vence: {formatDateTime(c.fecha_fin)}</div>
                      </div>
                      {isAdmin && (
                        <button
                          onClick={(e) => { e.stopPropagation(); pedirEliminar(c.id); }}
                          style={{ position: "absolute", top: "6px", right: "6px", minWidth: "28px", height: "28px", padding: "0 8px", background: "rgba(239,68,68,0.85)", border: "1px solid rgba(239,68,68,0.6)", borderRadius: "999px", color: "#fff", fontSize: "11px", cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", backdropFilter: "blur(4px)", fontFamily: getFont(theme, "secondary"), fontWeight: "700" }}
                          title="Eliminar comunicado"
                        >Eliminar</button>
                      )}
                    </div>
                  );
                })}
              </div>
              <div style={{ textAlign: "center", padding: "16px", color: "rgba(255,255,255,0.3)", fontFamily: getFont(theme, "secondary"), fontSize: "10px" }}>
                Vista previa ampliada activa. Selecciona una tarjeta o usa las flechas laterales para cambiar de archivo.
              </div>
            </>
          )}
        </>
      )}

      {/* ── SUB-TAB: PROPONER / PUBLICAR ── */}
      {subTab === "proponer" && (
        <>
          {/* Descripción contextual */}
          <div style={{ background: isAdmin ? "rgba(56,189,248,0.06)" : "rgba(251,191,36,0.06)", border: `1px solid ${isAdmin ? "rgba(56,189,248,0.2)" : "rgba(251,191,36,0.2)"}`, borderRadius: "12px", padding: "12px 14px", marginBottom: "16px", display: "flex", alignItems: "flex-start", gap: "10px" }}>
            <span style={{ fontSize: "20px", flexShrink: 0 }}>{isAdmin ? "📤" : "✉️"}</span>
            <div>
              <div style={{ fontFamily: getFont(theme, "secondary"), fontWeight: "700", fontSize: "12px", color: isAdmin ? "#38bdf8" : "#fbbf24", marginBottom: "3px", letterSpacing: "0.5px" }}>
                {isAdmin ? "PUBLICAR COMUNICADO OFICIAL" : "PROPONER COMUNICADO"}
              </div>
              <div style={{ fontFamily: getFont(theme, "secondary"), fontSize: "10px", color: "rgba(255,255,255,0.45)", lineHeight: "1.5" }}>
                {isAdmin
                  ? "Tus comunicados se publican de inmediato, aparecen en Ver Comunicados y se replican automáticamente en Noticias."
                  : "Tu propuesta será revisada por un administrador antes de ser visible para la comunidad."}
              </div>
            </div>
          </div>

          <SubirComunicadoPanel onSubido={handleSubidoExitoso} isAdmin={isAdmin} />

          {/* ── PENDIENTES DE APROBACIÓN (solo admin) ── */}
          {isAdmin && (
            <div style={{ marginTop: "24px" }}>
              <div style={{ display: "flex", alignItems: "center", gap: "8px", marginBottom: "12px" }}>
                <div style={{ flex: 1, height: "1px", background: "#1e3a5f" }} />
                <div style={{ display: "flex", alignItems: "center", gap: "6px", fontFamily: getFont(theme, "secondary"), fontSize: "10px", color: "#f97316", fontWeight: "700", letterSpacing: "1px", whiteSpace: "nowrap" }}>
                  Procesando SOLICITUDES PENDIENTES
                  {pendientes.length > 0 && (
                    <span style={{ background: "#f97316", color: "#fff", borderRadius: "8px", padding: "1px 7px", fontSize: "10px" }}>{pendientes.length}</span>
                  )}
                </div>
                <div style={{ flex: 1, height: "1px", background: "#1e3a5f" }} />
              </div>

              {pendientes.length === 0 ? (
                <div style={{ textAlign: "center", padding: "24px", border: "1px dashed #1e3a5f", borderRadius: "12px", color: "rgba(255,255,255,0.25)", fontFamily: getFont(theme, "secondary"), fontSize: "11px" }}>
                  Sin solicitudes pendientes
                </div>
              ) : (
                pendientes.map((p) => (
                  <div key={p.id} style={{ background: "rgba(249,115,22,0.07)", border: "1px solid rgba(249,115,22,0.25)", borderLeft: "3px solid #f97316", borderRadius: "12px", padding: "12px 14px", marginBottom: "10px" }}>
                    {/* Info del comunicado */}
                    <div style={{ display: "flex", gap: "10px", marginBottom: "10px" }}>
                      {/* Thumbnail */}
                      <div style={{ flexShrink: 0, width: "64px", height: "64px", borderRadius: "8px", overflow: "hidden", background: "#060e1a", border: "1px solid #1e3a5f", display: "flex", alignItems: "center", justifyContent: "center" }}>
                        {isPdf(p.archivo_url) ? (
                          <div style={{ textAlign: "center" }}>
                            <div style={{ fontSize: "24px" }}>📄</div>
                            <div style={{ fontFamily: getFont(theme, "secondary"), fontSize: "8px", color: "rgba(255,255,255,0.4)" }}>PDF</div>
                          </div>
                        ) : (
                          <img src={p.archivo_url} alt="preview" style={{ width: "100%", height: "100%", objectFit: "cover" }} />
                        )}
                      </div>
                      {/* Datos */}
                      <div style={{ flex: 1, minWidth: 0 }}>
                        <div style={{ fontFamily: getFont(theme, "secondary"), fontWeight: "700", fontSize: "12px", color: "rgba(255,255,255,0.95)", marginBottom: "3px", overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{p.titulo}</div>
                        {p.detalle && <div style={{ fontSize: "11px", color: "rgba(255,255,255,0.5)", marginBottom: "5px", overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{p.detalle}</div>}
                        <div style={{ fontSize: "9px", color: "rgba(255,255,255,0.3)", fontFamily: getFont(theme, "secondary"), lineHeight: "1.6" }}>
                          <div>📅 Inicio: {formatDateTime(p.fecha_inicio)}</div>
                          <div>⏰ Fin: {formatDateTime(p.fecha_fin)}</div>
                        </div>
                      </div>
                    </div>
                    {/* Acciones: 3 botones */}
                    <div style={{ display: "flex", gap: "6px" }}>
                      <button
                        onClick={() => setVisorItem(p)}
                        disabled={procesando === p.id}
                        style={{ flex: 1, padding: "8px 4px", background: "rgba(56,189,248,0.12)", border: "1px solid rgba(56,189,248,0.4)", borderRadius: "8px", color: "#38bdf8", fontFamily: getFont(theme, "secondary"), fontSize: "10px", fontWeight: "700", cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", gap: "4px" }}
                      >
                        👁 VER
                      </button>
                      <button
                        onClick={() => aprobar(p.id)}
                        disabled={procesando !== null}
                        style={{ flex: 1, padding: "8px 4px", background: procesando === p.id ? "rgba(34,197,94,0.3)" : "rgba(34,197,94,0.12)", border: "1px solid rgba(34,197,94,0.5)", borderRadius: "8px", color: "#22c55e", fontFamily: getFont(theme, "secondary"), fontSize: "10px", fontWeight: "700", cursor: procesando !== null ? "not-allowed" : "pointer", display: "flex", alignItems: "center", justifyContent: "center", gap: "4px", opacity: procesando !== null && procesando !== p.id ? 0.5 : 1 }}
                      >
                        {procesando === p.id ? "Procesando" : "✓"} APROBAR
                      </button>
                      <button
                        onClick={() => rechazar(p.id)}
                        disabled={procesando !== null}
                        style={{ flex: 1, padding: "8px 4px", background: "rgba(239,68,68,0.12)", border: "1px solid rgba(239,68,68,0.5)", borderRadius: "8px", color: "#ef4444", fontFamily: getFont(theme, "secondary"), fontSize: "10px", fontWeight: "700", cursor: procesando !== null ? "not-allowed" : "pointer", display: "flex", alignItems: "center", justifyContent: "center", gap: "4px", opacity: procesando !== null && procesando !== p.id ? 0.5 : 1 }}
                      >
                        ✕ RECHAZAR
                      </button>
                    </div>
                  </div>
                ))
              )}
            </div>
          )}
        </>
      )}
    </>
  );
}


function MediaConverterModal({ files = [], onClose, onNotice }) {
  const theme = React.useContext(ThemeContext);
  const [busy, setBusy] = useState("");
  const [error, setError] = useState("");
  const pdfCount = Array.from(files).filter(f => f.type === "application/pdf").length;
  const imgCount = Array.from(files).filter(f => f.type?.startsWith("image/")).length;

  const runPdfToJpeg = async () => {
    setBusy("pdf-jpeg");
    setError("");
    try {
      const result = await pdfFilesToJpegDownloadClient(files);
      onNotice?.(result.zipped ? `Se descargó un ZIP con ${result.count} imágenes JPEG.` : "Se descargó la imagen JPEG.", "#22c55e");
      onClose?.();
    } catch (e) {
      setError(e?.message || "No se pudo convertir PDF a JPEG.");
    } finally {
      setBusy("");
    }
  };

  const runImagesToPdf = async () => {
    setBusy("img-pdf");
    setError("");
    try {
      const result = await imageFilesToPdfDownloadClient(files);
      onNotice?.(`Se generó PDF con ${result.count} imagen${result.count === 1 ? "" : "es"}.`, "#22c55e");
      onClose?.();
    } catch (e) {
      setError(e?.message || "No se pudo convertir imagen a PDF.");
    } finally {
      setBusy("");
    }
  };

  return createPortal(
    <div onClick={onClose} style={{ position:"fixed", inset:0, zIndex:10000, background:"rgba(2,6,23,.88)", display:"flex", alignItems:"center", justifyContent:"center", padding:"14px" }}>
      <div onClick={e=>e.stopPropagation()} style={{ width:"min(720px, 100%)", background:"#0b1b33", border:"1px solid rgba(56,189,248,.35)", borderRadius:"16px", boxShadow:"0 20px 80px rgba(0,0,0,.45)", overflow:"hidden" }}>
        <div style={{ padding:"14px 16px", borderBottom:"1px solid rgba(255,255,255,.10)", display:"flex", justifyContent:"space-between", alignItems:"center", gap:"10px" }}>
          <div>
            <div style={{ fontFamily:getFont(theme,"secondary"), color:"#fff", fontWeight:900, fontSize:"15px" }}>Conversor PDF / imagen</div>
            <div style={{ fontFamily:getFont(theme,"secondary"), color:"rgba(255,255,255,.55)", fontSize:"11px", marginTop:"3px" }}>Funciona directo en el navegador desde GitHub/Vercel; no requiere backend local.</div>
          </div>
          <button onClick={onClose} style={{ width:"34px", height:"34px", borderRadius:"999px", border:"1px solid rgba(255,255,255,.16)", background:"rgba(255,255,255,.08)", color:"#fff", cursor:"pointer" }}>✕</button>
        </div>

        <div style={{ padding:"16px", display:"grid", gap:"8px" }}>
          <div style={{ padding:"12px", borderRadius:"12px", background:"rgba(255,255,255,.06)", border:"1px solid rgba(255,255,255,.12)", color:"rgba(255,255,255,.76)", fontFamily:getFont(theme,"secondary"), fontSize:"12px", lineHeight:1.6 }}>
            Archivos detectados: <b>{pdfCount}</b> PDF · <b>{imgCount}</b> imagen{imgCount === 1 ? "" : "es"}. Si un PDF tiene varias hojas, se genera un JPEG por hoja y se descarga en ZIP.
          </div>

          {error && <div style={{ padding:"10px 12px", borderRadius:"10px", color:"#f87171", border:"1px solid rgba(239,68,68,.45)", background:"rgba(239,68,68,.10)", fontFamily:getFont(theme,"secondary"), fontSize:"12px" }}>{error}</div>}

          <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fit, minmax(220px, 1fr))", gap:"10px" }}>
            <button onClick={runPdfToJpeg} disabled={!!busy || !pdfCount} style={{ padding:"14px", borderRadius:"12px", border:"1px solid rgba(251,191,36,.55)", background:pdfCount ? "rgba(251,191,36,.14)" : "rgba(100,116,139,.12)", color:pdfCount ? "#fbbf24" : "#64748b", fontFamily:getFont(theme,"secondary"), fontSize:"12px", fontWeight:900, cursor:busy ? "wait" : (pdfCount ? "pointer" : "not-allowed") }}>
              {busy === "pdf-jpeg" ? "Convirtiendo…" : "PDF → JPEG"}
            </button>
            <button onClick={runImagesToPdf} disabled={!!busy || !imgCount} style={{ padding:"14px", borderRadius:"12px", border:"1px solid rgba(56,189,248,.55)", background:imgCount ? "rgba(56,189,248,.14)" : "rgba(100,116,139,.12)", color:imgCount ? "#38bdf8" : "#64748b", fontFamily:getFont(theme,"secondary"), fontSize:"12px", fontWeight:900, cursor:busy ? "wait" : (imgCount ? "pointer" : "not-allowed") }}>
              {busy === "img-pdf" ? "Convirtiendo…" : "Imagen → PDF"}
            </button>
          </div>

          <div style={{ color:"rgba(255,255,255,.42)", fontFamily:getFont(theme,"secondary"), fontSize:"10px", lineHeight:1.5 }}>
            Nota: archivos muy pesados o PDFs con muchas hojas pueden tardar más porque la conversión se hace en el dispositivo del usuario.
          </div>
        </div>
      </div>
    </div>,
    document.body
  );
}

function OcrZonePickerModal({ files = [], onClose, onApply }) {
  const theme = React.useContext(ThemeContext);
  const [pages, setPages] = useState([]);
  const [activeKey, setActiveKey] = useState("");
  const [loading, setLoading] = useState(true);
  const [running, setRunning] = useState(false);
  const [error, setError] = useState("");
  const dragRef = useRef(null);
  // Congela los archivos al abrir el modal. Evita que un arreglo nuevo en cada render
  // dispare otra vez la carga y restablezca el cuadro en bucle.
  const sourceFilesRef = useRef(Array.isArray(files) ? files : []);

  useEffect(() => {
    const oldOverflow = document.body.style.overflow;
    const oldOverscroll = document.body.style.overscrollBehavior;
    document.body.style.overflow = "hidden";
    document.body.style.overscrollBehavior = "none";
    return () => {
      document.body.style.overflow = oldOverflow;
      document.body.style.overscrollBehavior = oldOverscroll;
    };
  }, []);

  useEffect(() => {
    let cancelled = false;
    (async () => {
      setLoading(true);
      setError("");
      try {
        const built = [];
        const sourceFiles = sourceFilesRef.current || [];
        for (let i = 0; i < sourceFiles.length; i++) {
          const file = sourceFiles[i];
          if (file.type?.startsWith("image/")) {
            const img = await fileToImageCanvas(file);
            built.push({
              key: `${i}-img-1`, fileIndex: i, fileName: file.name, type: "image", pageNo: 1,
              canvas: img.canvas, previewUrl: img.previewUrl, width: img.width, height: img.height,
              zone: { x: 0.08, y: 0.12, w: 0.84, h: 0.34 }
            });
          } else if (file.type === "application/pdf") {
            const pdfPages = await renderPdfFileToCanvases(file, 12);
            pdfPages.forEach(pg => built.push({
              key: `${i}-pdf-${pg.pageNo}`, fileIndex: i, fileName: file.name, type: "pdf", pageNo: pg.pageNo,
              canvas: pg.canvas, previewUrl: pg.previewUrl, width: pg.width, height: pg.height,
              zone: { x: 0.08, y: 0.12, w: 0.84, h: 0.28 }
            }));
          }
        }
        if (!cancelled) {
          setPages(built);
          setActiveKey(built[0]?.key || "");
        }
      } catch (e) {
        if (!cancelled) setError(e?.message || "No se pudo abrir el archivo para seleccionar zonas.");
      } finally {
        if (!cancelled) setLoading(false);
      }
    })();
    return () => { cancelled = true; };
  }, []);

  useEffect(() => {
    const move = (ev) => {
      const d = dragRef.current;
      if (!d) return;
      ev.preventDefault?.();
      const clientX = ev.touches?.[0]?.clientX ?? ev.clientX;
      const clientY = ev.touches?.[0]?.clientY ?? ev.clientY;
      const dx = (clientX - d.startX) / Math.max(1, d.rect.width);
      const dy = (clientY - d.startY) / Math.max(1, d.rect.height);
      setPages(prev => prev.map(p => {
        if (p.key !== d.key) return p;
        let { x, y, w, h } = d.zone;
        if (d.mode === "move") {
          x = Math.min(0.98 - w, Math.max(0, x + dx));
          y = Math.min(0.98 - h, Math.max(0, y + dy));
        } else {
          w = Math.min(1 - x, Math.max(0.08, w + dx));
          h = Math.min(1 - y, Math.max(0.06, h + dy));
        }
        return { ...p, zone: { x, y, w, h } };
      }));
    };
    const up = () => { dragRef.current = null; };
    window.addEventListener("mousemove", move);
    window.addEventListener("mouseup", up);
    window.addEventListener("touchmove", move, { passive: false });
    window.addEventListener("touchend", up);
    return () => {
      window.removeEventListener("mousemove", move);
      window.removeEventListener("mouseup", up);
      window.removeEventListener("touchmove", move);
      window.removeEventListener("touchend", up);
    };
  }, []);

  const active = pages.find(p => p.key === activeKey) || pages[0];
  const activeIndex = active ? pages.findIndex(p => p.key === active.key) : -1;
  const activeRatio = active?.width && active?.height ? `${active.width} / ${active.height}` : "1 / 1";

  const startDrag = (ev, page, mode) => {
    const box = ev.currentTarget.closest("[data-zone-stage]")?.getBoundingClientRect();
    if (!box) return;
    const clientX = ev.touches?.[0]?.clientX ?? ev.clientX;
    const clientY = ev.touches?.[0]?.clientY ?? ev.clientY;
    dragRef.current = { key: page.key, mode, startX: clientX, startY: clientY, rect: box, zone: { ...page.zone } };
    ev.preventDefault?.();
    ev.stopPropagation?.();
  };

  const resetZone = () => {
    if (!active) return;
    setPages(prev => prev.map(p => p.key === active.key ? { ...p, zone: { x: 0.08, y: 0.12, w: 0.84, h: 0.34 } } : p));
  };

  const fullPageZone = () => {
    if (!active) return;
    setPages(prev => prev.map(p => p.key === active.key ? { ...p, zone: { x: 0, y: 0, w: 1, h: 1 } } : p));
  };

  const apply = async () => {
    setRunning(true);
    setError("");
    try {
      let text = "";
      const results = [];
      for (const page of pages) {
        const cropped = cropCanvasByZone(page.canvas, page.zone);
        const pageText = await ocrCanvasClient(cropped);
        results.push({ key: page.key, fileName: page.fileName, pageNo: page.pageNo, text: pageText });
        if (pageText) {
          text += `${text ? "\n\n" : ""}${pageText}`;
        }
      }
      const cleanedText = stripFileNamesFromOcrText(text, sourceFilesRef.current || []);
      await onApply?.({ text: cleanedText, results, zones: pages.map(({ canvas, previewUrl, ...p }) => p) });
      onClose?.();
    } catch (e) {
      setError(e?.message || "No se pudo extraer texto de las zonas seleccionadas.");
    } finally {
      setRunning(false);
    }
  };

  return createPortal(
    <div style={{ position:"fixed", inset:0, zIndex:10000, background:"rgba(2,6,23,.88)", display:"flex", alignItems:"center", justifyContent:"center", padding:"14px", overflow:"hidden", overscrollBehavior:"none", touchAction:"none" }} onClick={onClose}>
      <div onClick={e=>e.stopPropagation()} style={{ width:"min(1180px, 100%)", maxHeight:"94vh", overflow:"hidden", background:"#0b1b33", border:"1px solid rgba(56,189,248,.35)", borderRadius:"16px", boxShadow:"0 20px 80px rgba(0,0,0,.45)", display:"flex", flexDirection:"column", overscrollBehavior:"contain", touchAction:"auto", overflowAnchor:"none" }}>
        <div style={{ padding:"13px 15px", borderBottom:"1px solid rgba(255,255,255,.10)", display:"flex", justifyContent:"space-between", alignItems:"center", gap:"10px" }}>
          <div>
            <div style={{ fontFamily:getFont(theme,"secondary"), fontWeight:900, color:"#fff", fontSize:"14px" }}>Elegir zonas de extracción</div>
            <div style={{ fontFamily:getFont(theme,"secondary"), color:"rgba(255,255,255,.55)", fontSize:"11px", marginTop:"2px" }}>Arrastra el cuadro para moverlo. Usa la esquina inferior derecha para agrandarlo o hacerlo pequeño.</div>
          </div>
          <button onClick={onClose} style={{ width:"34px", height:"34px", borderRadius:"999px", border:"1px solid rgba(255,255,255,.16)", background:"rgba(255,255,255,.08)", color:"#fff", cursor:"pointer" }}>✕</button>
        </div>

        {loading ? (
          <div style={{ padding:"44px", textAlign:"center", color:"#93c5fd", fontFamily:getFont(theme,"secondary"), fontWeight:800 }}>Abriendo archivo…</div>
        ) : error ? (
          <div style={{ margin:"16px", padding:"14px", borderRadius:"12px", color:"#f87171", border:"1px solid rgba(239,68,68,.45)", background:"rgba(239,68,68,.10)", fontFamily:getFont(theme,"secondary") }}>{error}</div>
        ) : !active ? (
          <div style={{ padding:"44px", textAlign:"center", color:"#94a3b8", fontFamily:getFont(theme,"secondary") }}>Selecciona una imagen o PDF primero.</div>
        ) : (
          <div style={{ display:"grid", gridTemplateColumns:"190px 1fr", minHeight:0, overflow:"hidden" }}>
            <div style={{ borderRight:"1px solid rgba(255,255,255,.10)", padding:"10px", overflowY:"auto", maxHeight:"calc(94vh - 124px)", overscrollBehavior:"contain", WebkitOverflowScrolling:"touch", touchAction:"pan-y", overflowAnchor:"none" }}>
              {pages.map((p, idx) => (
                <button key={p.key} onClick={()=>setActiveKey(p.key)} style={{ width:"100%", textAlign:"left", marginBottom:"8px", padding:"8px", borderRadius:"10px", border:`1px solid ${p.key===active.key ? "rgba(56,189,248,.75)" : "rgba(255,255,255,.12)"}`, background:p.key===active.key ? "rgba(56,189,248,.16)" : "rgba(255,255,255,.05)", color:"#fff", cursor:"pointer", fontFamily:getFont(theme,"secondary"), fontSize:"10px" }}>
                  <img src={p.previewUrl} alt="preview" style={{ width:"100%", height:"78px", objectFit:"cover", borderRadius:"7px", display:"block", marginBottom:"6px" }} />
                  {p.type === "pdf" ? `Hoja ${p.pageNo}` : "Imagen"} · {idx + 1}/{pages.length}
                </button>
              ))}
            </div>
            <div style={{ padding:"12px", overflow:"auto", maxHeight:"calc(94vh - 124px)", overscrollBehavior:"contain", WebkitOverflowScrolling:"touch", touchAction:"pan-y", overflowAnchor:"none" }} onWheel={(e)=>e.stopPropagation()}>
              <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", gap:"8px", flexWrap:"wrap", marginBottom:"10px" }}>
                <div style={{ color:"#cbd5e1", fontFamily:getFont(theme,"secondary"), fontSize:"11px", fontWeight:800 }}>{active.fileName}{active.type === "pdf" ? ` · Hoja ${active.pageNo}` : ""}</div>
                <div style={{ display:"flex", gap:"8px", flexWrap:"wrap" }}>
                  <button onClick={() => activeIndex > 0 && setActiveKey(pages[activeIndex - 1].key)} disabled={activeIndex <= 0} style={{ padding:"8px 10px", borderRadius:"9px", border:"1px solid rgba(255,255,255,.12)", background:"rgba(255,255,255,.06)", color:"#cbd5e1", cursor:activeIndex <= 0 ? "not-allowed" : "pointer" }}>←</button>
                  <button onClick={() => activeIndex < pages.length - 1 && setActiveKey(pages[activeIndex + 1].key)} disabled={activeIndex >= pages.length - 1} style={{ padding:"8px 10px", borderRadius:"9px", border:"1px solid rgba(255,255,255,.12)", background:"rgba(255,255,255,.06)", color:"#cbd5e1", cursor:activeIndex >= pages.length - 1 ? "not-allowed" : "pointer" }}>→</button>
                  <button onClick={resetZone} style={{ padding:"8px 10px", borderRadius:"9px", border:"1px solid rgba(251,191,36,.35)", background:"rgba(251,191,36,.10)", color:"#fbbf24", cursor:"pointer" }}>Restablecer cuadro</button>
                  <button onClick={fullPageZone} style={{ padding:"8px 10px", borderRadius:"9px", border:"1px solid rgba(148,163,184,.30)", background:"rgba(148,163,184,.10)", color:"#cbd5e1", cursor:"pointer" }}>Toda la hoja</button>
                </div>
              </div>
              <div data-zone-stage style={{ position:"relative", width:"min(100%, 820px)", aspectRatio: activeRatio, margin:"0 auto", borderRadius:"12px", overflow:"hidden", border:"1px solid rgba(255,255,255,.14)", background:"#fff", lineHeight:0, userSelect:"none", touchAction:"none", overflowAnchor:"none", contain:"layout paint" }}>
                <img src={active.previewUrl} alt="zona" draggable={false} loading="eager" decoding="sync" style={{ position:"absolute", inset:0, width:"100%", height:"100%", display:"block" }} />
                <div onMouseDown={(e)=>startDrag(e, active, "move")} onTouchStart={(e)=>startDrag(e, active, "move")} style={{ position:"absolute", left:`${active.zone.x*100}%`, top:`${active.zone.y*100}%`, width:`${active.zone.w*100}%`, height:`${active.zone.h*100}%`, border:"2px solid #22c55e", background:"rgba(34,197,94,.14)", boxShadow:"0 0 0 9999px rgba(0,0,0,.36)", cursor:"move", boxSizing:"border-box", touchAction:"none" }}>
                  <div style={{ position:"absolute", left:"8px", top:"8px", background:"rgba(2,6,23,.82)", color:"#fff", borderRadius:"999px", padding:"4px 8px", fontSize:"10px", fontFamily:getFont(theme,"secondary"), lineHeight:1 }}>Zona OCR</div>
                  <div onMouseDown={(e)=>startDrag(e, active, "resize")} onTouchStart={(e)=>startDrag(e, active, "resize")} style={{ position:"absolute", right:"-8px", bottom:"-8px", width:"18px", height:"18px", borderRadius:"5px", background:"#22c55e", border:"2px solid #fff", cursor:"nwse-resize", touchAction:"none" }} />
                </div>
              </div>
            </div>
          </div>
        )}

        <div style={{ padding:"12px 15px", borderTop:"1px solid rgba(255,255,255,.10)", display:"flex", justifyContent:"space-between", gap:"10px", flexWrap:"wrap" }}>
          <div style={{ color:"rgba(255,255,255,.48)", fontFamily:getFont(theme,"secondary"), fontSize:"10px" }}>{pages.length ? `Se extraerá texto de ${pages.length} zona${pages.length === 1 ? "" : "s"}. En PDF se usa un cuadro por hoja.` : ""}</div>
          <div style={{ display:"flex", gap:"8px" }}>
            <button onClick={onClose} disabled={running} style={{ padding:"10px 13px", borderRadius:"10px", border:"1px solid rgba(148,163,184,.35)", background:"rgba(148,163,184,.12)", color:"#cbd5e1", cursor:running?"wait":"pointer", fontFamily:getFont(theme,"secondary"), fontWeight:800 }}>Cancelar</button>
            <button onClick={apply} disabled={running || loading || !pages.length} style={{ padding:"10px 13px", borderRadius:"10px", border:"1px solid #22c55e", background:"rgba(34,197,94,.18)", color:"#22c55e", cursor:running?"wait":"pointer", fontFamily:getFont(theme,"secondary"), fontWeight:900 }}>{running ? "Extrayendo…" : "Extraer texto de zonas"}</button>
          </div>
        </div>
      </div>
    </div>, document.body
  );
}

// ─── TAB: NOTICIAS ────────────────────────────────────────────────────────────
function NoticiasAdminPublisher({ onPublished, isAdmin = false }) {
  const theme = React.useContext(ThemeContext);
  const [titulo, setTitulo] = useState("");
  const [categoria, setCategoria] = useState("comunicado");
  const [fecha, setFecha] = useState(() => new Date().toISOString().slice(0, 10));
  const [texto, setTexto] = useState("");
  const [files, setFiles] = useState([]);
  const [mediaUrls, setMediaUrls] = useState([]);
  const [pdfUrls, setPdfUrls] = useState([]);
  const [busy, setBusy] = useState(false);
  const [msg, setMsg] = useState(null);
  const [zonePickerOpen, setZonePickerOpen] = useState(false);
  const [converterOpen, setConverterOpen] = useState(false);
  const inputRef = useRef(null);

  const allowed = ["image/jpeg", "image/png", "image/webp", "application/pdf"];
  const setNotice = (text, color = "#2563eb") => { setMsg({ text, color }); setTimeout(() => setMsg(null), 3500); };

  const onFiles = (e) => {
    const selected = Array.from(e.target.files || []);
    const bad = selected.find(f => !allowed.includes(f.type));
    if (bad) return setNotice("Solo se permiten JPG, PNG, WEBP y PDF.", "#ef4444");
    const tooLarge = selected.find(f => f.size > 15 * 1024 * 1024);
    if (tooLarge) return setNotice("Cada archivo debe pesar máximo 15 MB.", "#ef4444");
    setFiles(selected);
    setMediaUrls(selected.filter(f => f.type.startsWith("image/")).map(f => URL.createObjectURL(f)));
    setPdfUrls(selected.filter(f => f.type === "application/pdf").map(f => f.name));
  };

  const uploadFiles = async () => {
    const uploadedImages = [];
    const uploadedPdfs = [];
    for (const file of files) {
      const ext = sanitizeStorageName(file.name.split(".").pop() || (file.type === "application/pdf" ? "pdf" : "jpg"));
      const path = `noticias/${Date.now()}_${Math.random().toString(36).slice(2)}_${sanitizeStorageName(file.name)}`;
      const { error } = await sb.storage.from("noticias").upload(path, file, { contentType: file.type, upsert: false });
      if (error) throw error;
      const { data: { publicUrl } } = sb.storage.from("noticias").getPublicUrl(path);
      if (file.type === "application/pdf") uploadedPdfs.push({ url: publicUrl, type: file.type, path });
      else uploadedImages.push(publicUrl);
    }
    return { uploadedImages, uploadedPdfs };
  };

  const procesar = async () => {
    if (!files.length) return setNotice("Selecciona una imagen o PDF para procesar.", "#f97316");
    setBusy(true);
    const localUrlsToRevoke = [];
    try {
      let extracted = "";
      let allImages = [];
      let uploadedImages = [];
      let uploadedPdfs = [];

      // OCR primero en el navegador con archivos locales. Así la extracción funciona aunque
      // el bucket 'noticias' o una Edge Function de OCR todavía no estén configurados.
      for (const file of files) {
        const localUrl = URL.createObjectURL(file);
        localUrlsToRevoke.push(localUrl);
        if (file.type.startsWith("image/")) {
          allImages.push(localUrl);
          const r = await callMediaProcessor({ action: "image_ocr", sourceUrl: localUrl, fileType: file.type, title: titulo, bucketPath: "noticias/ocr" });
          if (r?.text) extracted += (extracted ? "\n\n" : "") + r.text;
        } else if (file.type === "application/pdf") {
          const r = await callMediaProcessor({ action: "pdf_to_images_ocr", sourceUrl: localUrl, fileType: file.type, title: titulo, bucketPath: "noticias/pdf" });
          allImages = [...allImages, ...parseJsonArray(r?.image_urls)];
          if (r?.text) extracted += (extracted ? "\n\n" : "") + r.text;
        }
      }

      // Subida opcional: si el bucket falla, no bloquea la extracción de texto.
      try {
        const uploaded = await uploadFiles();
        uploadedImages = uploaded.uploadedImages || [];
        uploadedPdfs = uploaded.uploadedPdfs || [];
        if (uploadedImages.length) allImages = [...uploadedImages, ...allImages.filter(u => !String(u).startsWith("blob:"))];
        setPdfUrls(uploadedPdfs.map(p => p.url));
      } catch (uploadError) {
        console.warn("No se pudieron subir archivos al bucket noticias; OCR local completado.", uploadError?.message || uploadError);
        setPdfUrls(files.filter(f => f.type === "application/pdf").map(f => f.name));
      }

      const cleanExtracted = stripFileNamesFromOcrText(extracted, files);
      setMediaUrls(allImages);
      if (cleanExtracted) setTexto(prev => [prev, cleanExtracted].filter(Boolean).join("\n\n"));
      setNotice(
        cleanExtracted
          ? "Texto extraído en el navegador. Revísalo antes de publicar."
          : "No se detectó texto legible. Puedes escribir o corregir la descripción manualmente.",
        cleanExtracted ? "#22c55e" : "#f97316"
      );
    } catch (e) {
      console.error(e);
      setNotice("No se pudo extraer texto en el navegador. Revisa la imagen/PDF o escribe el texto manualmente.", "#ef4444");
    } finally {
      // Mantener files para permitir publicar/subir aunque el OCR haya usado URLs temporales.
      setBusy(false);
      // No revocar inmediatamente las URLs usadas como preview; solo revocamos URLs que no quedaron en mediaUrls.
    }
  };

  const aplicarTextoDeZonas = async ({ text }) => {
    const cleanText = stripFileNamesFromOcrText(text, files);
    if (cleanText) {
      setTexto(prev => [prev, cleanText].filter(Boolean).join("\n\n"));
      setNotice("Texto extraído desde las zonas seleccionadas. Revísalo antes de publicar.", "#22c55e");
    } else {
      setNotice("No se detectó texto legible dentro de las zonas seleccionadas.", "#f97316");
    }
  };

  const publicar = async () => {
    if (!titulo.trim()) return setNotice("Escribe un título.", "#ef4444");
    setBusy(true);
    try {
      // Si el admin no presionó procesar, subimos los archivos al publicar.
      let images = mediaUrls.filter(u => typeof u === "string" && !u.startsWith("blob:"));
      let pdfs = pdfUrls.filter(u => typeof u === "string" && u.startsWith("http"));
      if (files.length) {
        const up = await uploadFiles();
        images = [...images, ...up.uploadedImages];
        pdfs = [...pdfs, ...up.uploadedPdfs.map(p => p.url)];
      }
      const payload = {
        tipo: categoria,
        titulo: titulo.trim(),
        detalle: texto.trim() || null,
        icono: categoria === "comunicado" ? "document" : "dispatch-news",
        color: categoria === "comunicado" ? "#2563eb" : "#0ea5e9",
        origen: categoria === "comunicado" ? "comunicados" : "admin_noticias",
        fecha_publicacion: fecha || new Date().toISOString().slice(0, 10),
        texto_extraido: texto.trim() || null,
        media_urls: images,
        pdf_urls: pdfs,
        archivo_url: images[0] || pdfs[0] || null,
        archivo_tipo: images[0] ? "image/jpeg" : (pdfs[0] ? "application/pdf" : null),
        ocultar_en_feed: false,
      };
      const { data, error } = await sb.from("noticias").insert(payload).select("*").single();
      if (error) throw error;
      setTitulo(""); setTexto(""); setFiles([]); setMediaUrls([]); setPdfUrls([]);
      if (inputRef.current) inputRef.current.value = "";
      setNotice("Noticia publicada.", "#22c55e");
      onPublished && onPublished(data);
    } catch (e) {
      console.error(e);
      setNotice("No se pudo publicar. Aplica la migración SQL de noticias extendidas.", "#ef4444");
    } finally {
      setBusy(false);
    }
  };

  return (
    <div style={{ background:"rgba(255,255,255,0.07)", border:"1px solid rgba(148,163,184,0.22)", borderRadius:"14px", padding:"14px", marginBottom:"16px" }}>
      <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", gap:"8px", marginBottom:"12px", flexWrap:"wrap" }}>
        <div>
          <div style={{ fontFamily:getFont(theme,"secondary"), fontSize:"12px", color:"rgba(255,255,255,0.92)", fontWeight:800 }}>{isAdmin ? "Panel admin de Noticias" : "Herramientas para preparar comunicado"}</div>
          <div style={{ fontFamily:getFont(theme,"secondary"), fontSize:"10px", color:"rgba(255,255,255,0.48)", marginTop:"2px" }}>{isAdmin ? "Sube imágenes o PDF, procesa OCR y edita el texto antes de publicar." : "Convierte archivos, elige zonas y extrae texto. Después pega el texto en tu propuesta para revisión."}</div>
        </div>
        <Badge color={isAdmin ? "#2563eb" : "#fbbf24"} small>{isAdmin ? "Solo administrador" : "Usuarios normales"}</Badge>
      </div>
      {msg && <div style={{ padding:"9px 10px", borderRadius:"9px", background:msg.color+"18", border:`1px solid ${msg.color}55`, color:msg.color, fontFamily:getFont(theme,"secondary"), fontSize:"11px", marginBottom:"10px" }}>{msg.text}</div>}
      {!isAdmin && <div style={{ padding:"9px 10px", borderRadius:"9px", background:"rgba(251,191,36,0.08)", border:"1px solid rgba(251,191,36,0.28)", color:"#fbbf24", fontFamily:getFont(theme,"secondary"), fontSize:"11px", marginBottom:"10px", lineHeight:1.45 }}>Estas herramientas son para preparar tu propuesta. La publicación directa en Noticias queda reservada para administradores; los comunicados de usuarios normales pasan por aprobación.</div>}
      {isAdmin && <>
      <div style={{ display:"grid", gridTemplateColumns:"1fr 150px", gap:"8px", marginBottom:"8px" }}>
        <input value={titulo} onChange={e=>setTitulo(e.target.value)} placeholder="Título de la noticia o comunicado" style={{ background:"rgba(2,6,23,0.68)", border:"1px solid rgba(148,163,184,0.28)", borderRadius:"10px", padding:"11px 12px", color:"#fff", fontFamily:getFont(theme,"secondary"), fontSize:"12px" }} />
        <select value={categoria} onChange={e=>setCategoria(e.target.value)} style={{ background:"rgba(2,6,23,0.68)", border:"1px solid rgba(148,163,184,0.28)", borderRadius:"10px", padding:"11px 12px", color:"#fff", fontFamily:getFont(theme,"secondary"), fontSize:"12px" }}>
          <option value="comunicado">Comunicado</option>
          <option value="acceso">Accesos</option>
          <option value="terminal">Terminales</option>
          <option value="incidente">Incidente</option>
          <option value="accidente">Accidente</option>
          <option value="patio">Patios</option>
          <option value="carril">Carriles</option>
        </select>
      </div>
      <input type="date" value={fecha} onChange={e=>setFecha(e.target.value)} style={{ width:"100%", boxSizing:"border-box", background:"rgba(2,6,23,0.68)", border:"1px solid rgba(148,163,184,0.28)", borderRadius:"10px", padding:"10px 12px", color:"#fff", fontFamily:getFont(theme,"secondary"), fontSize:"12px", marginBottom:"8px" }} />
      </>}
      <input ref={inputRef} type="file" accept="image/jpeg,image/png,image/webp,application/pdf" multiple onChange={onFiles} style={{ width:"100%", color:"rgba(255,255,255,0.7)", marginBottom:"8px", fontFamily:getFont(theme,"secondary"), fontSize:"11px" }} />
      {(mediaUrls.length > 0 || pdfUrls.length > 0) && <div style={{ display:"flex", gap:"8px", flexWrap:"wrap", marginBottom:"8px" }}>
        {mediaUrls.map((u,i)=><img key={u+i} src={u} alt="preview" style={{ width:"82px", height:"62px", objectFit:"cover", borderRadius:"8px", border:"1px solid rgba(255,255,255,.14)" }} />)}
        {pdfUrls.map((u,i)=><div key={u+i} style={{ width:"82px", height:"62px", borderRadius:"8px", border:"1px solid rgba(255,255,255,.14)", display:"flex", alignItems:"center", justifyContent:"center", color:"#cbd5e1", fontSize:"10px", fontFamily:getFont(theme,"secondary") }}>PDF</div>)}
      </div>}
      <textarea value={texto} onChange={e=>setTexto(e.target.value)} placeholder={isAdmin ? "Texto extraído o descripción editable antes de publicar…" : "Texto extraído. Puedes copiarlo y pegarlo en tu propuesta de comunicado…"} rows={5} style={{ width:"100%", boxSizing:"border-box", background:"rgba(2,6,23,0.68)", border:"1px solid rgba(148,163,184,0.28)", borderRadius:"10px", padding:"11px 12px", color:"#fff", fontFamily:getFont(theme,"secondary"), fontSize:"12px", resize:"vertical", marginBottom:"10px" }} />
      <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fit, minmax(190px, 1fr))", gap:"8px" }}>
        <button onClick={procesar} disabled={busy || !files.length} style={{ padding:"11px", borderRadius:"10px", border:"1px solid rgba(37,99,235,.5)", background:"rgba(37,99,235,.14)", color:"#93c5fd", fontFamily:getFont(theme,"secondary"), fontSize:"12px", fontWeight:800, cursor:busy?"wait":"pointer" }}>{busy ? "Procesando…" : "Convertir / extraer texto"}</button>
        <button onClick={()=>setZonePickerOpen(true)} disabled={busy || !files.length} style={{ padding:"11px", borderRadius:"10px", border:"1px solid rgba(251,191,36,.55)", background:"rgba(251,191,36,.12)", color:"#fbbf24", fontFamily:getFont(theme,"secondary"), fontSize:"12px", fontWeight:900, cursor:(busy || !files.length)?"not-allowed":"pointer" }}>Elegir zonas de extracción</button>
        <button onClick={()=>setConverterOpen(true)} disabled={busy || !files.length} style={{ padding:"11px", borderRadius:"10px", border:"1px solid rgba(56,189,248,.55)", background:"rgba(56,189,248,.12)", color:"#38bdf8", fontFamily:getFont(theme,"secondary"), fontSize:"12px", fontWeight:900, cursor:(busy || !files.length)?"not-allowed":"pointer" }}>Conversor PDF / imagen</button>
        {!isAdmin && <button onClick={async()=>{ try { await navigator.clipboard.writeText(texto || ""); setNotice(texto ? "Texto copiado. Pégalo en tu propuesta de comunicado." : "No hay texto para copiar todavía.", texto ? "#22c55e" : "#f97316"); } catch { setNotice("No se pudo copiar automáticamente. Selecciona el texto y cópialo manualmente.", "#f97316"); } }} disabled={busy || !texto.trim()} style={{ padding:"11px", borderRadius:"10px", border:"1px solid rgba(34,197,94,.55)", background:"rgba(34,197,94,.12)", color:"#22c55e", fontFamily:getFont(theme,"secondary"), fontSize:"12px", fontWeight:900, cursor:(busy || !texto.trim())?"not-allowed":"pointer" }}>Copiar texto extraído</button>}
        {isAdmin && <button onClick={publicar} disabled={busy} style={{ padding:"11px", borderRadius:"10px", border:"1px solid #2563eb", background:"#2563eb", color:"#fff", fontFamily:getFont(theme,"secondary"), fontSize:"12px", fontWeight:900, cursor:busy?"wait":"pointer" }}>Publicar en Noticias</button>}
      </div>
      {zonePickerOpen && <OcrZonePickerModal files={files} onClose={()=>setZonePickerOpen(false)} onApply={aplicarTextoDeZonas} />}
      {converterOpen && <MediaConverterModal files={files} onClose={()=>setConverterOpen(false)} onNotice={setNotice} />}
    </div>
  );
}


// ─── REPORTE AUTOMÁTICO EN NOTICIAS: JPEG visible y descargable ───────────────
