            filter: hasUnreadAdminMessages ? "drop-shadow(0 0 14px rgba(251,191,36,.42))" : showQRPanel === "gemini" ? "drop-shadow(0 0 14px rgba(239,68,68,.36))" : "drop-shadow(0 0 16px rgba(34,211,238,.45))"
